def determine_priority_level(analysis):
    """Maps every detected attacktype to a math-based priority tier."""
    if not analysis: return 'low'
    
    # Priority 1: High-Stakes Reactionary (Counters and Supers)
    if analysis.get('is_super') or analysis.get('is_counter') or analysis.get('attacktype') == "counter":
        return 'reversal'
    
    # Priority 2: Standard Categories
    if analysis.get('is_antiair'): return 'high'
    if analysis.get('is_okizeme'): return 'meaty'
    
    atype = analysis.get('attacktype', 'unknown')

    # Mapping the specific "Enhanced Detection" strings to tiers
    tier_map = {
        # High Priority: Moves that break guards or are defensive staples
        "reversal": "reversal",
        "defensive_helper": "reversal",
        "command_throw": "throw",
        "custom_state_throw": "throw",
        "target_state_grab": "throw",
        "grab_helper": "throw",
        
        # Medium-High: Projectiles and Strikers
        "projectile": "high",
        "striker_helper": "high",
        
        # Utility & Mobility: Usually lower priority so they don't spam
        "teleport": "low",
        "heal": "low",
        "major_recovery": "low",
        "stat_modifier_buff": "low",
        "power_charge": "low",
        "assist_helper": "medium",
        "puppet_spawn": "medium",
        "tag_assist": "medium",
        "taunt": "low",
        "utility_tech": "low"
    }

    if atype in tier_map:
        return tier_map[atype]

    # Priority 3: Normal Attacks (Based on Speed)
    if atype in ["hitdef", "unknown"]:
        startup = analysis.get('reach', [99])[0]
        if startup is None: startup = 99
        return 'poke' if startup < 10 else 'medium'
    
    return 'low'

