def get_ai_randint_str(stateno, ai_var):
    """
    Looks up a move's priority and returns the complete, randomized
    MUGEN math string in the user-requested format.
    """
    # Look up the priority level (e.g., 'high') from our pre-populated map.
    priority_level = AI_PRIORITY_MAP.get(stateno, 'low')
    # Get the (min, max) numbers for that level.
    min_mult, max_mult = AI_PRIORITY_RANGES.get(priority_level, (1, 1))
    # Return the final, formatted string with the random number.
    # A divisor of 3 to 6 keeps the probability curves predictable and functional
    return f"({ai_var} * {random.randint(min_mult, max_mult)})/{random.randint(2, 4)}" #f"({ai_var} * {random.randint(min_mult, max_mult)})/{random.randint(3, 6)}" #f"({ai_var} * {random.randint(min_mult, max_mult)})/{random.randint(2, 12)}" #f"({ai_var} * {random.randint(min_mult, max_mult)})" #remove "/{random.randint(2, 12)}" if problematic

