def memoize(func):
    """
    (V10 - STABLE HASH) 
    Improved stability to prevent the RecursionError seen in V9.
    Ensures nested MUGEN logic structures generate consistent cache keys.
    """
    cache = {}

    def make_hashable(arg):
        """Recursively convert any argument into a hashable type."""
        if isinstance(arg, (str, int, float, bool, type(None))):
            return arg
        if isinstance(arg, dict):
            # Sort keys to ensure {'a':1, 'b':2} is the same as {'b':2, 'a':1}
            return tuple(sorted((k, make_hashable(v)) for k, v in arg.items()))
        if isinstance(arg, (list, tuple, set)):
            return tuple(make_hashable(elem) for elem in arg)
        
        return repr(arg)

    def wrapper(*args, **kwargs):
        # Create a stable, hashable key from all arguments
        key_args = tuple(make_hashable(arg) for arg in args)
        key_kwargs = tuple(sorted((k, make_hashable(v)) for k, v in kwargs.items()))
        key = (key_args, key_kwargs)

        if key in cache:
            return cache[key]

        result = func(*args, **kwargs)
        cache[key] = result
        return result

    return wrapper

