enable_remapper = False

def find_used_vars_and_fvars(all_char_files):
    """(V13) Scans all character files to find every var and fvar index in use."""
    global USED_VARS, USED_FVARS
    print("\n--- Universal Remapper: Scanning for used variables... ---")
    p_var = re.compile(r'var\s*\(\s*(\d+)\s*\)', re.I)
    p_fvar = re.compile(r'fvar\s*\(\s*(\d+)\s*\)', re.I)
    p_v_set = re.compile(r'^\s*v\s*=\s*(\d+)', re.I)
    p_fv_set = re.compile(r'^\s*fv\s*=\s*(\d+)', re.I)

    for file_path in all_char_files:
        if not os.path.isfile(file_path): continue
        try:
            content_str = "".join(read_unknown_encoding(file_path))
            for match in p_var.findall(content_str): USED_VARS.add(int(match))
            for match in p_v_set.findall(content_str): USED_VARS.add(int(match))
            for match in p_fvar.findall(content_str): USED_FVARS.add(int(match))
            for match in p_fv_set.findall(content_str): USED_FVARS.add(int(match))
        except Exception as e:
            print(f"  -> Warning: Could not scan {os.path.basename(file_path)}: {e}")
    print(f"  -> Found {len(USED_VARS)} unique vars and {len(USED_FVARS)} unique fvars in use.")

def create_ai_var_remapping():
    """(V13) Creates the mapping from the script's vars to safe, unused vars."""
    global AI_VAR_MAP, AI_FVAR_MAP
    print("--- Universal Remapper: Generating safe variable map... ---")
    free_var_idx = 0
    for needed_var in sorted(AI_SCRIPT_VARS_NEEDED):
        while free_var_idx in USED_VARS:
            free_var_idx += 1
        if free_var_idx > 59:
            print("  -> CRITICAL WARNING: Not enough free vars available! AI may malfunction.")
            break
        if needed_var != free_var_idx: AI_VAR_MAP[needed_var] = free_var_idx
        USED_VARS.add(free_var_idx)
    free_fvar_idx = 0
    for needed_fvar in sorted(AI_SCRIPT_FVARS_NEEDED):
        while free_fvar_idx in USED_FVARS:
            free_fvar_idx += 1
        if free_fvar_idx > 39:
            print("  -> CRITICAL WARNING: Not enough free fvars available! AI may malfunction.")
            break
        if needed_fvar != free_fvar_idx: AI_FVAR_MAP[needed_fvar] = free_fvar_idx
        USED_FVARS.add(free_fvar_idx)
    if not AI_VAR_MAP and not AI_FVAR_MAP:
        print("  -> No variable conflicts detected. No remapping is necessary.")

def remap_ai_code_block(code_block):
    """(V13) Post-processes a block of AI code, replacing variables with their safe counterparts."""
    if not enable_remapper or (not AI_VAR_MAP and not AI_FVAR_MAP):
        return code_block
    remapped_lines = []
    for line in code_block:
        modified_line = line
        for original, new in AI_VAR_MAP.items():
            # Standard var() replacement
            modified_line = re.sub(r'\bvar\(\s*' + str(original) + r'\s*\)', f'var({new})', modified_line, flags=re.I)
            # Safe assignment replacement using \g<1> to prevent ambiguity errors
            modified_line = re.sub(r'(\bv\s*=\s*)' + str(original) + r'(\b|;|\n)', fr'\g<1>{new}\g<2>', modified_line, flags=re.I)
            
        for original, new in AI_FVAR_MAP.items():
            # Standard fvar() replacement
            modified_line = re.sub(r'\bfvar\(\s*' + str(original) + r'\s*\)', f'fvar({new})', modified_line, flags=re.I)
            # Safe assignment replacement using \g<1> to prevent ambiguity errors
            modified_line = re.sub(r'(\bfv\s*=\s*)' + str(original) + r'(\b|;|\n)', fr'\g<1>{new}\g<2>', modified_line, flags=re.I)
            
        remapped_lines.append(modified_line)
    return remapped_lines

def remap_all_generated_code(list_of_code_lists):
    """(V13 - Central Hub) Iterates through all lists of generated code and applies remapping."""
    if not enable_remapper:
        return
    print("\n--- Universal Remapper: Applying safe variable map to all generated AI code... ---")
    for code_list in list_of_code_lists:
        for i in range(len(code_list)):
            if code_list[i]: # Ensure the block is not None
                code_list[i] = remap_ai_code_block(code_list[i])

def get_root():
    """Utility to create a forced-focus hidden Tkinter root."""
    root = tk.Tk()
    root.withdraw()
    root.attributes('-topmost', True) # Forces dialog to the front
    return root

def select_def_files():
    """Opens a file dialog to select one or more .def files."""
    root = get_root()
    filepaths = filedialog.askopenfilenames(
        parent=root,
        title="Select MUGEN Character .def file(s)",
        filetypes=(("DEF files", "*.def"), ("All files", "*.*"))
    )
    root.destroy() # Completely clear the instance from memory
    return list(filepaths)

def select_folders_and_find_defs():
    """Opens a folder dialog and finds all .def files recursively."""
    root = get_root()
    folder = filedialog.askdirectory(parent=root, title="Select Folder Containing Characters")
    root.destroy()
    
    if not folder:
        return []
    
    print(f" -> Scanning folder: {folder}...")
    def_files = []
    for dirpath, _, filenames in os.walk(folder):
        for filename in filenames:
            if filename.lower().endswith(".def"):
                # Avoid processing backup or temp files if they exist
                if not any(x in filename.lower() for x in ['backup', 'temp', 'old']):
                    full_path = os.path.abspath(os.path.join(dirpath, filename))
                    def_files.append(full_path)
    
    print(f" -> Found {len(def_files)} potential character(s).")
    return def_files

