def main_file_selection():
    def_files_to_process = []
    while not def_files_to_process:
        print("\n" + "="*55)
        print("     MUGEN AI GENERATOR - OMNI-ADAPTIVE LOADER".center(55))
        print("="*55)
        print(" 1: Select individual .def file(s) (Manual Selection)")
        print(" 2: Select a folder (Batch search characters)")
        print(" 3: Use Current Directory (Quick Start)")
        print(" 4: Exit")
        print("-" * 55)
        choice = input(" Please select an option (1-4): ").strip()

        if choice == '1':
            def_files_to_process = select_def_files()
        elif choice == '2':
            def_files_to_process = select_folders_and_find_defs()
        elif choice == '3':
            # Get current working directory
            cwd = os.getcwd()
            deffilelist = [f for f in os.listdir(cwd) if f.lower().endswith(".def")]
            if deffilelist:
                def_files_to_process = [os.path.abspath(os.path.join(cwd, f)) for f in deffilelist]
            else:
                print("\n [!] Error: No .def files found in the current directory.")
        elif choice == '4':
            print(" Exiting...")
            sys.exit()
        else:
            print("\n [!] Invalid choice. Please enter 1, 2, 3, or 4.")

        if not def_files_to_process and choice in ['1', '2', '3']:
            print(" [!] No files were selected. Returning to menu...")
            
    return def_files_to_process

