# --- OMNISCIENT ENCODING SYSTEM (V50) ---
# Prevents text corruption by detecting the specific language of a file,
# remembering it, and ensuring it is written back exactly as found.
# =====================================================================

# Global dictionary to remember the encoding of every file we touch
FILE_ENCODING_CACHE = {}

def detect_encoding(rawdata):
    """
    Analyzes binary data to guess the text encoding (Shift-JIS, UTF-8, etc).
    """
    # 1. Check for Byte Order Marks (Absolute Certainty)
    if rawdata.startswith(codecs.BOM_UTF8): return 'utf-8-sig'
    if rawdata.startswith(codecs.BOM_UTF16_LE): return 'utf-16-le'
    if rawdata.startswith(codecs.BOM_UTF16_BE): return 'utf-16-be'

    # 2. Try Standard UTF-8 (Most common modern format)
    try:
        rawdata.decode('utf-8')
        return 'utf-8'
    except UnicodeDecodeError:
        pass

    # 3. Use Statistical Detection (The "Brain")
    # Tries to distinguish between Japanese (Shift-JIS), Korean (EUC-KR), etc.
    if HAS_NORMALIZER:
        try:
            matches = from_bytes(rawdata)
            best_match = matches.best()
            if best_match: return best_match.encoding
        except: pass
    elif HAS_CHARDET:
        try:
            result = chardet.detect(rawdata)
            if result['encoding']: return result['encoding']
        except: pass

    # 4. Fallback for MUGEN Legacy (Common formats)
    # If detection failed, try Shift-JIS (common in MUGEN)
    try:
        rawdata.decode('shift_jis')
        return 'shift_jis'
    except UnicodeDecodeError:
        pass

    # 5. The "Nuclear Option" (Latin-1)
    # Maps bytes 1:1. Never crashes. Preserves data structure but might display garbage.
    return 'latin-1'

