def read_unknown_encoding(filepath):
    """
    AMALGAMATED V102: The "Structural Integrity" Reader.
    Removes latin-1 to prevent symbol corruption. 
    Uses surrogateescape to keep data 1:1 for unknown bytes.
    """
    if not os.path.isfile(filepath):
        if os.path.isfile(os.path.join(os.getcwd(), filepath)):
            filepath = os.path.join(os.getcwd(), filepath)
        else:
            print(f"  -> ERROR: File not found: {filepath}")
            return []

    try:
        with open(filepath, 'rb') as f:
            rawdata = f.read()
    except Exception as e:
        print(f"  -> FATAL: Could not read bytes from {filepath}. {e}")
        return []

    if not rawdata:
        return []

    # --- PHASE 1: HIERARCHICAL DETECTION ---
    detected_enc = None
    
    # 1. BOM Check (Absolute Certainty)
    if rawdata.startswith(codecs.BOM_UTF8): 
        detected_enc = 'utf-8-sig'
    elif rawdata.startswith(codecs.BOM_UTF16_LE): 
        detected_enc = 'utf-16-le'
    elif rawdata.startswith(codecs.BOM_UTF16_BE): 
        detected_enc = 'utf-16-be'
    
    # 2. Try UTF-8 (Modern Standard)
    if not detected_enc:
        try:
            rawdata.decode('utf-8')
            detected_enc = 'utf-8'
        except UnicodeDecodeError:
            pass

    # 3. Try Shift-JIS (Common for MUGEN/Japanese content)
    if not detected_enc:
        try:
            rawdata.decode('shift_jis')
            detected_enc = 'shift_jis'
        except UnicodeDecodeError:
            pass

    # 4. Try GBK (Common for Chinese content)
    if not detected_enc:
        try:
            rawdata.decode('gbk')
            detected_enc = 'gbk'
        except UnicodeDecodeError:
            pass

    # 5. Final Fallback: UTF-8 with surrogateescape
    # If we can't find a matching "language", we treat it as UTF-8
    # and "escape" any byte that doesn't fit. This prevents the latin-1 "garbage" issue.
    if not detected_enc:
        detected_enc = 'utf-8'

    # Store in cache
    FILE_ENCODING_CACHE[filepath] = detected_enc
    FILE_ENCODING_CACHE[os.path.basename(filepath)] = detected_enc

    # --- PHASE 2: DECODE & NORMALIZE ---
    # We use surrogateescape here to ensure that if a Shift-JIS file was forced into 
    # the UTF-8 fallback, the bytes are preserved for the round-trip.
    try:
        text = rawdata.decode(detected_enc, errors='surrogateescape')
    except:
        # Emergency last-resort if even surrogateescape fails (rare)
        text = rawdata.decode('ascii', errors='surrogateescape')

    # Fix spacing issues (\r\n vs \n)
    clean_lines_list = text.splitlines()
    final_lines = [line.rstrip() + '\n' for line in clean_lines_list]

    return final_lines

def save_safe_encoding(filepath, lines):
    """
    Writes back using the cached encoding and surrogateescape.
    """
    # Default to utf-8 if not in cache
    enc = FILE_ENCODING_CACHE.get(filepath, FILE_ENCODING_CACHE.get(os.path.basename(filepath), 'utf-8'))
    
    with open(filepath, 'w', encoding=enc, errors='surrogateescape') as f:
        f.writelines(lines)
         
def cut(line):
    """Removes comments from a line."""
    p = re.compile(r';.*')
    subs = p.sub('', line)
    if subs.lstrip():
        subs = subs.lstrip()
    return subs

def findstateno2(state):
    """Legacy check for stateno values specifically using ifelse logic."""
    s=0
    stateno=-1
    p1=re.compile(r'value\s*=\s*ifelse\(.*,\s*(\d+)\s*,\s*(\d+)\s*\)',re.I)
    for line in state:
        m1=p1.search(line)
        if m1:
            stateno=m1.group(1)
            break
    return stateno

def findtrigger(state):
    """Legacy check for specific trigger presence in a state block."""
    triggerall=0
    trigger1=0
    p1=re.compile(r'triggerall',re.I)
    p2=re.compile(r'trigger1',re.I)
    for line in state:
        m1=p1.search(line)
        m2=p2.search(line)
        if m1:triggerall=1
        if m2:trigger1=1
    return triggerall, trigger1

def parse_complex_value(line):
    """
    (NEW) Parses complex MUGEN value assignments, including Cond, ifelse,
    and basic variable checks. It extracts all possible numerical outcomes.
    Returns a list of integers found.
    """
    # Pattern to find all numbers within a cond or ifelse statement
    p_complex = re.compile(r'(?:cond|ifelse)\s*\((.*?)\)', re.I)
    # Pattern to find a simple numerical value
    p_simple = re.compile(r'value\s*=\s*(-?\d+)', re.I)

    complex_match = p_complex.search(line)
    if complex_match:
        # Extract the content inside the parentheses
        content = complex_match.group(1)
        # Find all numbers inside, which represent the possible statenos
        numbers = re.findall(r'-?\d+', content)
        return [int(n) for n in numbers]

    simple_match = p_simple.search(line)
    if simple_match:
        return [int(simple_match.group(1))]

    return []

