def _findstateno_universal_parser(line):
    """
    (UNIVERSAL PARSER) A helper function that intelligently parses a single line
    containing a 'value =' assignment to find the resulting stateno(s).
    It correctly handles simple numbers, complex Cond(), and ifelse() statements
    by isolating the result arguments from the condition arguments.
    """
    # Universal pattern to capture everything after "value ="
    p_universal_value = re.compile(r'value\s*=\s*(.*)', re.I)
    match = p_universal_value.search(line)
    
    if not match:
        return None

    expression = match.group(1).strip()

    # Check for complex statements first
    is_complex = re.search(r'^(cond|ifelse)\s*\(', expression, re.I)
    if is_complex:
        # Extract the content inside the parentheses
        content_match = re.search(r'\((.*)\)', expression)
        if not content_match:
            return None
        
        content = content_match.group(1)
        
        # *** THE DEFINITIVE FIX ***
        # We split the string only on the *first* comma. This correctly separates
        # the entire condition (e.g., "pos y >= 0") from the results (e.g., "60,65").
        parts = content.split(',', 1)
        
        # We only care about the results, which are in the second part.
        if len(parts) > 1:
            result_part = parts[1]
            # Now, we find all numbers within the results part. This avoids
            # capturing numbers from the condition.
            numbers_found = re.findall(r'-?\d+', result_part)
            if numbers_found:
                return int(numbers_found[0]) # Return the first valid outcome
        
        # Fallback if split logic fails for some reason
        return None

    # If it's not complex, it must be a simple number.
    # We can use findall to be safe.
    numbers_found = re.findall(r'-?\d+', expression)
    if numbers_found:
        return int(numbers_found[0])

    return None

def findstateno(state):
    """
    (IMPROVED & UNIVERSAL FUSION) Finds the stateno from a state change controller.
    Fuses the explicit legacy regexes (for exact ifelse matching) with the new 
    universal parser to handle modern MUGEN 1.0+ cond() statements.
    """
    s = 0
    stateno = -1
    
    # --- Legacy V2 Patterns ---
    p = re.compile(r'value\s*=\s*(\d+)', re.I)
    p1 = re.compile(r'value\s*=\s*ifelse\(.*,\s*(\d+)\s*,\s*(\d+)\s*\)', re.I)
    
    for line in state:
        # 1. Try the explicit V2 Legacy Regex checks first
        m = p.search(line)
        m1 = p1.search(line)
        
        if m:            
            stateno = int(m.group(1))
            break
        if m1 and stateno == -1:
            stateno = int(m1.group(1))
            break
            
        # 2. If legacy failed, deploy the Universal Parser (V1)
        if stateno == -1:
            univ_stateno = _findstateno_universal_parser(line)
            if univ_stateno is not None and univ_stateno != -1:
                stateno = univ_stateno
                break
                
    return stateno

