global_fallback_cache = {}

def preload_all_cns_files(cns_file_list, verbose=True):
    """
    (V18 - OMNI-ROBUST & DEFINITIVE FUSION) The ultimate, hybrid Statedef parser that
    fuses multiple layers of analysis into a single, exhaustive pass at startup.

    1.  **Header Indexing:** First, it maps the line number of every `[Statedef ...]`
        header for accelerated, targeted lookups. Uses V2's (\s*|\D+.*) pattern for 
        flawless comment/name bypassing.

    2.  **High-Speed State Machine Parser:** A primary, high-performance method that
        correctly handles well-formatted files, capturing the vast majority of
        Statedefs almost instantly.

    3.  **Integrated Brute-Force Recovery Engine:** For any state missed by the high-speed parser, 
        this engine activates a targeted, line-by-line scan. It uses the header index to start 
        scanning at the *exact* right line and stops at the next Statedef.
    """
    if verbose:
        print("\n---[V18 OMNI-ROBUST FUSION] Pre-loading all CNS files with Definitive Parser... ---")

    all_statedefs = {}
    header_index = {}  # Stores stateno -> (filename, line_number)

    # --- Regex Optimization (Fused with V2 logic) ---
    # More robust regex to catch headers like[Statedef 123;comment] or [Statedef 123, StateName]
    p_statedef_header = re.compile(r'\[Statedef\s+(-?\d+)(\s*|\D+.*)\]', re.I)
    p_any_header = re.compile(r'\[Statedef', re.I)

    for cns_file in cns_file_list:
        if not os.path.isfile(cns_file):
            if verbose: print(f"  -> Skipping non-existent file: {cns_file}")
            continue

        if verbose: print(f"  -> Reading: {os.path.basename(cns_file)}")
        try:
            # --- Single-Pass File Read ---
            if 'read_unknown_encoding' in globals():
                content_lines = read_unknown_encoding(cns_file)
            else:
                with open(cns_file, 'r', encoding='utf-8', errors='ignore') as ST:
                    content_lines = ST.readlines()

            # --- Phase 1: Header Indexing for Accelerated Fallback ---
            # This step is critical for the brute-force engine's speed.
            for i, line in enumerate(content_lines):
                match = p_statedef_header.search(cut(line))
                if match:
                    stateno = int(match.group(1))
                    if stateno not in header_index:
                        header_index[stateno] = (cns_file, i)

            # --- Phase 2: High-Speed State Machine Parser ---
            # This is the primary engine for well-formatted files.
            current_stateno = None
            current_statedef_lines =[]
            for line in content_lines:
                match = p_statedef_header.search(cut(line))
                if match:
                    if current_stateno is not None:
                        all_statedefs[current_stateno] = current_statedef_lines
                    current_stateno = int(match.group(1))
                    current_statedef_lines = [line]
                elif current_stateno is not None:
                    current_statedef_lines.append(line)
            # Add the very last state block in the file
            if current_stateno is not None and current_statedef_lines:
                all_statedefs[current_stateno] = current_statedef_lines

            # --- Phase 3: Integrated Brute-Force Recovery Engine ---
            # This is the merged logic from the old `findstatedef` functions. It activates
            # only for states missed by the high-speed parser.
            for stateno, (filename, start_idx) in header_index.items():
                if filename == cns_file and stateno not in all_statedefs:
                    if verbose: print(f"     -> State machine missed Statedef {stateno}. Activating targeted Brute-Force Recovery...")
                    
                    # This is the core of the `findstatedef` logic, now made hyper-efficient.
                    block =[]
                    # Start scanning from the exact line where the header was found.
                    for i in range(start_idx, len(content_lines)):
                        line = content_lines[i]
                        # The stop condition: if we find a *new* Statedef header after our starting line.
                        if i > start_idx and p_any_header.search(cut(line)):
                            break
                        block.append(line)
                    
                    if block:
                        all_statedefs[stateno] = block
                        if verbose: print(f"        -> Successfully recovered Statedef {stateno}.")

        except Exception as e:
            if verbose: print(f"  -> CRITICAL ERROR reading {os.path.basename(cns_file)}: {e}")

    if verbose:
        print(f"--- Omni-Robust Pre-load complete. Found and cached {len(all_statedefs)} unique statedefs. ---")

    # The function returns the complete dictionary of all found states.
    return all_statedefs, header_index

# --- NEW: A dedicated cache for the fallback mechanism ---

global_fallback_cache = {}

def findstatedef(stateno, cached_defs=None, newstfiles=None):
    """
    (V20 - HYBRID ACCELERATED GETTER) Finds and returns the full definition of a statedef.
    
    This fuses the blazing-fast pure dictionary lookup (V1) with the bulletproof 
    hard-drive reading loop (V2). If the state is not in the cache, it will scan 
    the actual files on disk, extract the state, and dynamically inject it into 
    the cache so it never lags again.
    """
    # 1. Blazing Fast Cache Check (O(1) time)
    if cached_defs is not None:
        cached_result = cached_defs.get(stateno)
        if cached_result:
            return cached_result
            
    # 2. V2 Omni-Robust Disk Fallback (Runs ONLY if the cache missed)
    # Fused with V2's legacy regex pattern to catch malformed headers.
    p = re.compile(r'\[Statedef\s*' + str(stateno) + r'(\s*|\D+.*)\]', re.I)
    p1 = re.compile(r'\[Statedef', re.I)
    s = 0
    statedef = []
    
    # Global fallback if newstfiles isn't explicitly passed
    files_to_check = newstfiles if newstfiles is not None else globals().get('newstfiles',[])
    
    if files_to_check:
        for cnsfile in files_to_check:
            if os.path.isfile(cnsfile):
                try:
                    if 'read_unknown_encoding' in globals():
                        temp = read_unknown_encoding(cnsfile)
                    else:
                        with open(cnsfile, 'r', encoding='utf-8', errors='ignore') as ST:
                            temp = ST.readlines()
                            
                    if not statedef:
                        for line in temp:
                            line = cut(line) if 'cut' in globals() else line.split(';')[0].strip()
                            m = p.search(line)
                            m1 = p1.search(line)
                            
                            if s == 1:
                                if m1 is None:
                                    statedef.append(line)
                                if m1:
                                    break
                            if m and s == 0:
                                s = 1
                                statedef.append(line)
                except Exception:
                    pass
                    
                if statedef:
                    # Dynamic Cache Injection: Save it so we never read the disk again!
                    if cached_defs is not None:
                        cached_defs[stateno] = statedef
                    break
                    
    return statedef
   
@memoize
# =========================================================================
# THE DEFINITIVE OMNI-ROBUST ANIMATION PARSER (FINDaction AMALGAMATED)
# =========================================================================

def findaction(animno, actionlist=None):
    """
    (ULTIMATE AMALGAMATION)
    Finds the definition of a specific action (animation) in the AIR file data.
    Detects offensive capability (Clsn1) and captures all valid animation elements.
    """
    # --- 1. Scope & Validation Gate ---
    if animno is None:
        return [], 0
        
    # [OMNI-FIX]: Support both passed actionlist and global actionlist for recursion safety
    if actionlist is None:
        actionlist = globals().get('actionlist')
        
    if actionlist is None:
        return [], 0

    # --- 2. Regex Definitions ---
    # Matches the specific header: [Begin Action 1234]
    p = re.compile(r'\[Begin action\s*' + str(animno) + r'\s*\]', re.I)
    # Matches the start of ANY action header (used to find the end of the block)
    p1 = re.compile(r'\[Begin action', re.I)

    s = 0        # Search status flag (0: looking for header, 1: capturing lines)
    clsn1 = 0    # Offensive box detection flag
    action = []  # List to store the animation lines

    # --- 3. Parsing Loop ---
    for line in actionlist:
        # Check for our specific animation header
        m = p.search(line)
        
        if s == 1:
            # We are currently inside the target animation block.
            # Check if we've hit the start of a DIFFERENT animation.
            m1 = p1.search(line)
            
            if m1 is None:
                # Still inside our block. Use 'cut' to strip comments/whitespace.
                # Only append if there is actual content left.
                if cut(line):
                    # DETECT OFFENSIVE PAYLOAD:
                    # If 'clsn1' (red box) is found in the line, mark this action as an attack.
                    if line is not None and line != '' and 'clsn1' in line.lower():
                        clsn1 = 1
                    action.append(line)
            else:
                # We hit a new [Begin Action] header, meaning our target block is over.
                break
                
        if m and s == 0:
            # HEADER FOUND: Start capturing lines starting from the next iteration.
            action.append(line)
            s = 1

    # Returns the list of animation lines and the attack-ready flag (0 or 1).
    return action, clsn1

def analyze_vertical_properties(reach_data, statetype, char_constants=None):
    """
    (V18 OMNI-ADAPTIVE) 
    Context-aware vertical analysis engine. Uses character constants to normalize
    detection thresholds, ensuring accuracy across all character scales.
    """
    if not reach_data or len(reach_data) < 8:
        return {}

    # Extract Reach Data
    c1x2 = reach_data[3] # Hitbox Max X
    c1y1 = reach_data[4] # Hitbox Top
    c1y2 = reach_data[5] # Hitbox Bottom
    c2y1 = reach_data[6] # Hurtbox Top
    c2y2 = reach_data[7] # Hurtbox Bottom

    # Default Character Constants (Fallback if CNS data missing)
    # head_pos.y is typically around -90 for standard MUGEN chars
    head_y = char_constants.get('head_pos_y', -90) if char_constants else -90
    mid_y = head_y * 0.6  # Calculated waistline (~ -54)

    properties = {
        'is_low_profile': False,
        'is_anti_air': False,
        'is_mid_level': False,
        'is_ground_sweep': False,
        'is_jump_in': False,
        'is_divekick': False,
        'is_overhead': False,
        'effective_top': c1y1,
        'effective_bottom': c1y2,
    }

    if c1y1 is None or c1y2 is None:
        return properties

    # --- CONTENT-AWARE CLASSIFICATION ---
    
    if statetype in ['S', 'C']:
        # Overhead: Hits the opponent's head but doesn't reach the ground
        if c1y2 < (mid_y) and c1y1 <= (head_y + 10):
            properties['is_overhead'] = True
        
        # Anti-air: High vertical reach, clear gap at the feet
        elif c1y1 < (head_y - 20) and c1y2 < (mid_y):
            properties['is_anti_air'] = True
            
        # Ground Sweep: Focuses on the base of the sprite
        elif c1y2 >= -5 and c1y1 > (mid_y):
            properties['is_ground_sweep'] = True
            
        else:
            properties['is_mid_level'] = True

    elif statetype == 'A':
        # Divekick: Strong forward momentum + downward hitbox
        if c1x2 is not None and c1x2 > 60 and c1y2 > mid_y:
            properties['is_divekick'] = True
        # Jump-in: Deep hitbox extending below the character's axis
        elif c1y2 > 5:
            properties['is_jump_in'] = True
        else:
            properties['is_mid_level'] = True

    # --- CONTEXT-AWARE STATUS ---
    
    # Low Profile: The character's own hurtbox is at or below 50% of their usual height
    if c2y1 is not None:
        if c2y1 > (head_y * 0.5): # e.g., if -40 > -45
            properties['is_low_profile'] = True

    return properties
    
