def findreach(action, pausetime=0, statetype='A', velocity_x=0):
    """
    (ULTIMATE AMALGAMATION - OMNI-FUSED V26.9 + LEGACY FULL)
    Ensures:
    - Adaptive Gap Handling & Multi-Syntax Parsing (.AIR Modern/Legacy/Ancient).
    - Velocity-Awareness: Factors in horizontal movement for "true" dynamic reach.
    - Legacy State Flags: Strictly preserves s, s0, s1, s2, s3, s4 logic for timing locks exactly as originally coded.
    - Buffered Frame Processing: No data is lost on the last animation element.
    """
    import re
    
    # --- 1. AMALGAMATED REGEX PATTERNS ---
    # Element Regex: Captures all 5 parameters. The 5th is the duration time.
    t = re.compile(r'^\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)(?:\s*,\s*([^\s,]+))?', re.I)
    
    # Clsn Block Regex
    p_clsn_block = re.compile(r'Clsn(\d)(?:Default)?:\s*\d*', re.I)
    
    # Legacy/Ancient Variations
    c = re.compile(r'clsn(\d+)\s*:\s*\d+\s*', re.I)
    c0 = re.compile(r'clsn\[\d+\]\s*=\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)', re.I)
    c1 = re.compile(r'clsn1\[\d+\]\s*=\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)', re.I)
    c2 = re.compile(r'clsn2\[\d+\]\s*=\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)', re.I)

    # --- 2. INTEGRATED STATE TRACKING ---
    time = 0
    totaltime = 0
    atkendtime = 0
    pattern = 0
    clsn = 0
    
    # Legacy Flags
    s, s0, s1, s2, s3, s4 = 0, 0, 0, 0, 0, 0
    
    # Hitbox/Hurtbox Boundaries
    c1x1, c1x2, c1y1, c1y2 = None, None, None, None
    c2y1, c2y2 = None, None

    # V3/V4 Spatial Buffers
    found_first_hit = False
    frame_clsn1 = []
    frame_clsn2 = []
    current_clsn_type = None  
    ancient_mode = 0          
    last_duration = 0

    def process_frame_amalgamated(f_clsn1, f_clsn2, dur, vel_x, current_totaltime):
        """Processes buffered frame data using both Spatial and Legacy Timing logic."""
        nonlocal found_first_hit, atkendtime, c1x1, c1x2, c1y1, c1y2, c2y1, c2y2
        nonlocal s, s0, s1, s2, s3, s4
        
        # --- HITBOX PROCESSING (CLSN1) ---
        if f_clsn1:
            if not found_first_hit:
                found_first_hit = True
            
            # Legacy s0 locking logic: Only calculate boundaries on the FIRST active frame series
            if s0 == 0:
                for (bx1, by1, bx2, by2) in f_clsn1:
                    # Spatial Logic: Normalize box (no displacement for static ranges)
                    cx1 = min(bx1, bx2)
                    cx2 = max(bx1, bx2)
                    cy1 = min(by1, by2)
                    cy2 = max(by1, by2)

                    # Min/Max assignment exactly preserving the legacy algorithm's logic
                    if c1x1 is not None: c1x1 = min(c1x1, cx1)
                    else: c1x1 = cx1
                    
                    if c1x2 is not None: c1x2 = max(c1x2, cx2)
                    else: c1x2 = cx2

                    if c1y1 is not None: c1y1 = min(c1y1, cy1)
                    else: c1y1 = cy1
                    
                    if c1y2 is not None: c1y2 = max(c1y2, cy2)
                    else: c1y2 = cy2

            # Flag Updates Preserved 1:1
            s = 1       
            s1 = 1      
            s0 = 1      
            if s2 == 0: s3 = 1 

        if s == 1:
            atkendtime += dur
            s = 0 

        # --- HURTBOX PROCESSING (CLSN2) ---
        if f_clsn2 and s4 == 0:
            if statetype == 'A' and s1 == 1:
                for (bx1, by1, bx2, by2) in f_clsn2:
                    cy1 = min(by1, by2)
                    cy2 = max(by1, by2)
                    
                    if c2y1 is not None: c2y1 = min(c2y1, cy1)
                    else: c2y1 = cy1
                    
                    if c2y2 is not None: c2y2 = max(c2y2, cy2)
                    else: c2y2 = cy2
                s2 = 1 
            if s2 == 1: s4 = 1

    # --- 3. THE PARSING LOOP ---
    for line in action:
        line_clean = line.split(';')[0].strip()
        if not line_clean: continue

        # SIGNAL: Animation Element found
        m = t.search(line_clean)
        if m:
            # 1. FLUSH: Process the clsn data gathered BEFORE this element line
            if totaltime > 0 or frame_clsn1 or frame_clsn2:
                process_frame_amalgamated(frame_clsn1, frame_clsn2, last_duration, velocity_x, totaltime)

            # 2. Parse Current Element's Duration
            t1 = abs(int(m.group(5)))
            last_duration = 1 if t1 == -1 else t1
            
            # 3. TIMING CALCULATION (Legacy Math Preserved)
            time = time + last_duration * (1 - s1) * (1 - s3)
            totaltime = totaltime + last_duration
            
            if s1 == 1: s0 = 1
            if s2 == 1: s4 = 1
            
            # 4. RESET buffers for the next element
            frame_clsn1 = []
            frame_clsn2 = []
            current_clsn_type = None
            ancient_mode = 0
            s1 = 0 
            continue

        # --- COLLISION BOX PARSING ---
        mc = c.search(line_clean)
        m_block = p_clsn_block.search(line_clean)
        m0 = c0.search(line_clean)
        m1 = c1.search(line_clean)
        m2 = c2.search(line_clean)

        if m_block:
            current_clsn_type = m_block.group(1)
            continue
            
        if mc:
            pattern = 1
            clsn = int(mc.group(1))
            ancient_mode = clsn
            if clsn == 1: s = 1 
            continue

        target_type = None
        box_data = None
        
        if m1:
            target_type = '1'
            box_data = m1.groups()
            s = 1 # Preserved specific legacy assignment
        elif m2:
            target_type = '2'
            box_data = m2.groups()
        elif m0:
            if current_clsn_type:
                target_type = current_clsn_type
            elif ancient_mode:
                target_type = str(ancient_mode)
            box_data = m0.groups()
            if target_type == '1': s = 1 # Preserved specific legacy assignment

        if box_data and target_type:
            try:
                # Convert matched groups to floats first to handle anomalies, then safely to ints
                coords = tuple(int(float(x)) for x in box_data)
                if target_type == '1': frame_clsn1.append(coords)
                elif target_type == '2': frame_clsn2.append(coords)
            except (ValueError, TypeError): 
                pass

    # --- 4. THE FINAL FLUSH ---
    # Process the very last frame of the animation
    if frame_clsn1 or frame_clsn2 or last_duration > 0:
        process_frame_amalgamated(frame_clsn1, frame_clsn2, last_duration, velocity_x, totaltime)

    # --- 5. FINAL ADJUSTMENTS (Amalgamated Validation) ---
    if c1x1 is None:
        time = None
        
    if time is not None and time != 0:
        time = time + 1
        
    if pausetime is not None and time is not None and time >= pausetime:
        time = time - pausetime

    # Legacy commented print
    #if stateno == 2045:print(time,pausetime)

    return time, totaltime, c1x1, c1x2, c1y1, c1y2, c2y1, c2y2, atkendtime


# =========================================================================
# THE DEFINITIVE OMNI-ROBUST DYNAMIC PHYSICS ENGINE (V18)
# =========================================================================

def calculate_dynamic_reach(analysis):
    """
    (V18 OMNI-ROBUST PHYSICS ENGINE)
    Simplified to return zero displacement for static ranges.
    """
    return {'x': 0.0, 'y': 0.0}


def calculate_full_dynamic_range(analysis, dynamic_displacement):
    """
    (V18 HYBRID RANGE)
    Simplified to return static baseline without dynamic displacement.
    """
    # Defaults
    res = {'x1': 0, 'x2': 60, 'y1': -80, 'y2': 0}
    if not analysis or analysis['reach'][2] is None:
        return res

    reach = analysis['reach']
    stateattr = analysis['stateattr']
    is_air = (stateattr[1] == 'A')
    scale_x = analysis.get('xscale', 1.0) or 1.0
    
    # 1. Determine Static Baseline (Amalgamated from previous step)
    front = airfront if is_air else groundfront
    back = airback if is_air else groundback
    
    raw_x1 = reach[2] * scale_x
    raw_x2 = reach[3] * scale_x
    
    # Leading edge logic
    base_x2 = raw_x2 - front
    
    # Trailing edge / Cross-up logic
    if raw_x1 < 0 and abs(raw_x1) > back:
        base_x1 = raw_x1 + back
    elif raw_x1 >= (back + 10):
        base_x1 = raw_x1 - back
    else:
        base_x1 = 0

    # 2. No Dynamic Momentum Integration (Static ranges)
    final_x1 = base_x1
    final_x2 = base_x2
    
    # 3. Y-Axis Calculation
    r4, r5 = reach[4], reach[5]
    r6, r7 = (reach[6] or 0), (reach[7] or 0)
    
    if not is_air:
        base_y1, base_y2 = r4, r5
    else:
        # Relative height reach
        base_y1, base_y2 = (r4 - r7), (r5 - r6)

    final_y1 = base_y1
    final_y2 = base_y2

    # 4. Final Normalization (Ensures x1 < x2 and y1 < y2)
    res['x1'] = int(min(final_x1, final_x2))
    res['x2'] = int(max(final_x1, final_x2))
    res['y1'] = int(min(final_y1, final_y2))
    res['y2'] = int(max(final_y1, final_y2))

    return res

# =========================================================================
# THE DEFINITIVE OMNI-ROBUST ANIMATION TIMING ENGINE (AMALGAMATED)
# =========================================================================

def read_animelem(animno, actionlist, elemno, oper=''):
    """
    (ULTIMATE AMALGAMATION) 
    Calculates the exact game-tick time until a specific animation element (frame) 
    is reached, including support for MUGEN's AnimElemTime operator syntax.
    """
    # --- 1. Regex & Environment Setup ---
    # Matches the 5th value in an .AIR element line (the duration)
    t = re.compile(r'\s*-?\d+\s*,\s*-?\d+\s*,\s*-?\d+\s*,\s*-?\d+\s*,\s*(-?\d+)\s*')
    
    # Retrieve the animation action block
    try:
        action_data = findaction(animno, actionlist)
        action = action_data[0] if action_data else []
    except (NameError, TypeError, IndexError):
        return 0

    i = 1             # Element counter (1-based)
    time = 0          # Cumulative tick counter
    s = 0             # Search lock flag
    opertime = 0      # Offset from the operator string
    totaltime = None

    # --- 2. Operator Parsing ---
    # Fused Logic: Extract digits from operator string (e.g., ">5" -> 5)
    if oper is not None and oper != '':
        digit_match = re.findall(r'\d+', str(oper))
        if digit_match:
            opertime = int(digit_match[0])
        else:
            opertime = 0 # Fallback to prevent IndexError on invalid operator strings

    # --- 3. The Timing Simulation Loop ---
    for line in action:
        # Stop counting once we've reached the target element
        if s != 0: 
            break
            
        m = t.search(line)
        if m:
            # Get element duration; treat infinite (-1) as 1 for calculation purposes
            dur_raw = int(m.group(1))
            t1 = abs(dur_raw) if dur_raw != -1 else 1
            
            # Accumulate time
            time = time + t1
            
            # Check if we have hit the target element number
            i = i + 1
            if i >= elemno:
                s = 1

    # --- 4. Final Timing Normalization ---
    # This block interprets MUGEN's logic for ">", "<", and "=" operators
    if oper is not None and oper != '':
        if '<' in oper:
            # If the check is "less than", we are interested in the baseline element start
            opertime = 0
            totaltime = time
        else:
            # If the operator is strictly ">", MUGEN evaluates at Offset + 1
            if '=' not in oper:
                totaltime = time + opertime + 1
            else:
                # If the operator is ">=" or "=", it's exactly at opertime
                totaltime = time + opertime
    else:
        # No operator provided; return the start of the element
        totaltime = time

    # --- 5. Boundary Correction ---
    # Legacy Quirk: If we are looking for anything beyond the first frame,
    # add 1 tick to account for the frame 0 -> frame 1 tick transition.
    if elemno > 1:
        totaltime = totaltime + 1
        
    return totaltime

