def clearcmd(state, ai_var_re):
    """
    (OMNI-FUSED FINAL - V34 ROBUST + V17 STRICT)
    Amalgamates intelligent line splitting, global sniffing, and strict syntax cleanup.
    
    MODES:
    1-5: Legacy Promotion & Filtering
    6: Smart Fusion (OR Logic) -> Handles 512-char limit via var(59) bridge.
    7: Hyper-Strict Fusion (AND Logic) -> Forces all groups true.
    8: Trigger1 -> Triggerall Promotion
    9: Global Trigger -> Triggerall Promotion
    """
    import re

    # --- REGEX DEFINITIONS (Merged) ---
    p_numbered_trigger = re.compile(r'^\s*trigger(\d+)\s*=\s*(.*)', re.I)
    p_trigger_all = re.compile(r'^\s*triggerall\s*=', re.I)
    p_trigger_one = re.compile(r'^\s*trigger1\s*=', re.I)
    
    # AI & Command Cleaning
    # Updated p0 to catch AILevel, {ai_var}, and "!=" variations
    ## Updated p0 to catch ANY comparison involving the AI Variable or AILevel
    # This handles: !=1, =2, >0, <=0, etc.
    p0 = re.compile(fr'(?:(?:{ai_var_re})|AILevel|(?:{ai_var})|var\({legacy_var_fallback}\))\s*(?:!?=\s*\d+|[<>]=?\s*\d+)|'fr'!\s*(?:(?:{ai_var_re})|AILevel|(?:{ai_var})|var\({legacy_var_fallback}\))', re.I)
    #p0 = re.compile(fr'(?:{ai_var_re}|AILevel|{ai_var})\s*(?:!?=\s*\d+|[<>]=?\s*\d+)|!\s*(?:{ai_var_re}|AILevel|{ai_var})', re.I) #p0 = re.compile(fr'(?:{ai_var_re}|AILevel|{ai_var})\s*(?:!?=\s*0|<=\s*0|<\s*1)|!\s*(?:{ai_var_re}|AILevel|{ai_var})', re.I) #p0 = re.compile(fr'{ai_var_re}\s*<?=\s*0|{ai_var_re}\s*<\s*1$|!\s*{ai_var_re}', re.I) #p0 = re.compile(fr'{ai_var_re}\s*<?=\s*0|{ai_var_re}\s*<\s*1$|!\s*{ai_var_re}', re.I)
    p1 = re.compile(r'command\s*!?=\s*".*?"', re.I) # Clean command checks (V17)
    
    # Selective Promotion Patterns
    p_state_only = re.compile(r'statetype\s*!?=\s*\w+', re.I)
    # Update/Add this to catch S or C specifically
    p_sc_detect = re.compile(r'statetype\s*=\s*[SC]', re.I)
    p_move_only = re.compile(r'movetype\s*!?=\s*\w+', re.I)
    p_statetype_fallback = re.compile(r'(\s*)statetype\s*=\s*[SC]', re.I) # (V17 specific)

    # Cleanup Patterns (V17 Strictness)
    p_cleanup_and = re.compile(r'(&&|\(|=|(?:\|\|))\s*&&')
    p_cleanup_trailing = re.compile(r'(&&|\|\|)\s*$')
    p_cleanup_or = re.compile(r'(&&|\(|=|(?:\|\|))\s*\|\|')
    p_cleanup_empty = re.compile(r'trigger\w+\s*=\s*$', re.I)
    
    # Matches 'ctrl' or 'ctrl = 1' only. 
    # It will NOT match if followed by =, !=, <, or > (protecting ctrl=0, etc.)
    # It will NOT capture surrounding parentheses.
    p_ctrl_fix = re.compile(r'(?<!,)(?<!,\s)(?<!,\s\s)(?<!\w)ctrl(?:\s*=\s*1)?(?!\s*[!><=])(?!\w)', re.I) #p_ctrl_fix = re.compile(r'(?<!\w)ctrl(?:\s*=\s*1)?(?!\s*[!><=])(?!\w)', re.I)

    # Ctrl Fix Pattern (Handles ((ctrl)), (ctrl), ctrl=1)
    #p_ctrl_fix = re.compile(r'\(+\s*ctrl\s*(=\s*1)?\s*\)+|(?<!\w)ctrl\s*(=\s*1)?(?!\w)', re.I)

    # --- GLOBAL SNIFFER LIST (V34) ---
    global_triggers = [
        "Alive", "Anim", "AnimElem", "AnimElemNo", "AnimElemTime", "AnimExist", "AnimTime",
        "Ctrl", "StateNo", "StateType", "MoveType", "Time", "TimeMod", "Vel", "Pos", 
        "ScreenPos", "Facing", "BackEdgeBodyDist", "BackEdgeDist", "FrontEdgeBodyDist", 
        "FrontEdgeDist", "RootDist", "ParentDist", "P2BodyDist", "P2Dist", "P2Life", 
        "P2MoveType", "P2Name", "P2StateType", "EnemyNear", "Enemy", "NumEnemy", 
        "NumTarget", "Target", "Var", "FVar", "SysVar", "SysFVar", "Life", "LifeMax", 
        "Power", "PowerMax", "PalNo", "ID", "PlayerIDExist", "SelfAnimExist", 
        "HitDefAttr", "MoveContact", "MoveGuarded", "MoveHit", "MoveReversed", 
        "HitCount", "UniqHitCount", "ComboCount", "HitFall", "HitOver", "HitPauseTime", 
        "HitShakeOver", "HitVel", "CanRecover", "InGuardDist", "NumExplod", "NumHelper", 
        "NumPartner", "NumProj", "NumProjID", "ProjCancelTime", "ProjContact", 
        "ProjContactTime", "ProjGuarded", "ProjGuardedTime", "ProjHit", "ProjHitTime", 
        "IsHelper", "GameHeight", "GameTime", "GameWidth", "IsHomeTeam", "MatchNo", 
        "MatchOver", "RoundNo", "RoundsExisted", "RoundState", "TeamMode", "TeamSide", 
        "TicksPerSecond", "Win", "StateNo", "Stateno"
    ]
    p_globals = re.compile(r'\b(' + '|'.join(re.escape(t) for t in global_triggers) + r')\b', re.I)

    # --- CONTEXT DETECTION ---
    # Sniff the state for "Burst" markers (Stateno 5000+, MoveType H, or GetHitVar)
    is_burst = any(re.search(r'stateno\s*=\s*\[?5000|movetype\s*=\s*H|gethitvar', l, re.I) for l in state)
    
    # NOTE: Assuming CTRL_STRIP_MODE and convert_mode are available in scope. 
    # If not, add them as arguments to the function definition.
    try:
        strip_mode = CTRL_STRIP_MODE
        mode = convert_mode
    except NameError:
        strip_mode = 1 # Default fallback
        mode = 6       # Default fallback

    # Logic: Mode 2 forces strip, Mode 1 strips only if in burst state
    should_strip_ctrl = (strip_mode == 2) or (strip_mode == 1 and is_burst)

    temp = []
    trigger_groups = {} 
    mandatory_triggeralls = [] 
    preserved_lines = [] 
    existing_triggeralls = []

    for line in state:
        line = line.strip()
        
        # 1. Basic AI & Value Cleaning
        if p0.search(line): line = p0.sub('1', line)
        
        # (V17) Command cleanup: Don't let AI hang on command names, but keep values
        if p1.search(line) and 'value' not in line.lower(): 
            line = p1.sub('1', line)

        # 2. Strict Syntax Cleanup (V17)
        # Runs multiple times to catch nested garbage like "&& &&"
        for _ in range(2):
            line = p_cleanup_and.sub(r'\1', line)
            line = p_cleanup_or.sub(r'\1', line)
            line = p_cleanup_trailing.sub('', line)

        if not line or p_cleanup_empty.search(line): continue

        # 3. Context-Aware Ctrl Stripping (Merged)
        if should_strip_ctrl:
            line = p_ctrl_fix.sub('1', line)

        # 4. Separation & Categorization
        match_num = p_numbered_trigger.match(line)
        match_all = p_trigger_all.match(line)

        if match_num:
            t_num = int(match_num.group(1))
            # Capture content, stripping comments
            raw_content = match_num.group(2).split(';')[0].strip()
            if raw_content in ["1", ""]: continue
            
            # --- NEW: S/C TO != A CONVERSION ---
            try:
                if OPTIMIZE_SC_GROUND and p_sc_detect.search(raw_content):
                    # Replace "statetype = S" or "statetype = C" with "statetype != A"
                    raw_content = p_sc_detect.sub('statetype != A', raw_content)
            except NameError:
                pass # Fallback if variable isn't in scope

            # --- MODE ROUTING ---
            
            # Legacy Modes (1-4)
            if mode == 1:
                if p_state_only.search(raw_content): existing_triggeralls.append(f"triggerall = {raw_content}\n")
                elif p_statetype_fallback.search(raw_content): # V17 Fallback
                    temp.append(f"trigger{t_num} = statetype != A\n")
                else: temp.append(f"trigger{t_num} = {raw_content}\n")
            
            elif mode == 2:
                if p_move_only.search(raw_content): existing_triggeralls.append(f"triggerall = {raw_content}\n")
                else: temp.append(f"trigger{t_num} = {raw_content}\n")

            elif mode == 3:
                if p_state_only.search(raw_content) or p_move_only.search(raw_content):
                    existing_triggeralls.append(f"triggerall = {raw_content}\n")
                else: temp.append(f"trigger{t_num} = {raw_content}\n")

            elif mode == 4:
                existing_triggeralls.append(f"triggerall = {raw_content}\n")
            
            # Fusion Modes (6 & 7)
            elif mode in [6, 7]:
                # Smart Fusion: Move pure globals to triggerall immediately to save bridge space
                # MODIFICATION: Only promote if promote_globals is TRUE
                if promote_globals and p_globals.search(raw_content) and "Anim" not in raw_content and "StateNo" not in raw_content:
                    mandatory_triggeralls.append(raw_content)
                else:
                    if t_num not in trigger_groups: trigger_groups[t_num] = []
                    trigger_groups[t_num].append(raw_content)

            # Promotion Modes (8 & 9 - V34)
            elif mode == 8: # Trigger1 -> Triggerall
                if t_num == 1: existing_triggeralls.append(f"triggerall = {raw_content}\n")
                else: temp.append(f"trigger{t_num} = {raw_content}\n")
            
            elif mode == 9: # Global -> Triggerall
                # MODIFICATION: Only promote if promote_globals is TRUE
                if promote_globals and p_globals.search(raw_content): existing_triggeralls.append(f"triggerall = {raw_content}\n")
                else: temp.append(f"trigger{t_num} = {raw_content}\n")
            
            else: # Mode 5 or Unknown (Legacy Default)
                temp.append(f"trigger{t_num} = {raw_content}\n")

        elif match_all:
            existing_triggeralls.append(line + "\n")
        else:
            preserved_lines.append(line + "\n")

    # --- ASSEMBLY PHASE ---

   # FUSION LOGIC (Modes 6 & 7) - WARUSAKI3 / M-ISM BITWISE OMNI-BRIDGE
   # if mode in [6, 7]:
        # Step 1: Initialize assembly with state headers and existing triggeralls
   #     final = preserved_lines + existing_triggeralls

   # --- ASSEMBLY PHASE ---
    
    # BUGFIX: Ensure 'type', 'value', etc. are preserved for non-changestate blocks
    essential_params = []
    # These are keywords that define what the block DOES (The SCTRL itself)
    # We use ^\s* to ensure we only catch them when they are the line's primary command
    p_sctrl_key = re.compile(r'^\s*(type|value|stateno|id|v)\s*=', re.I)

    for l in state:
        # 1. Check if the line is a primary SCTRL parameter (not a trigger)
        if p_sctrl_key.match(l):
            # 2. Safety: Ensure it's not already in preserved_lines (which usually holds [State])
            # and double-check it's not a trigger line
            if 'trigger' not in l.lower():
                clean_l = l.strip() + "\n"
                if clean_l not in preserved_lines:
                    essential_params.append(clean_l)

    if mode in [6, 7]:
        # Step 1: Header + SCTRL Type + Existing Triggeralls
        final = preserved_lines + essential_params + existing_triggeralls
        
        for m_ta in mandatory_triggeralls:
            final.append(f"triggerall = {m_ta}\n")
            
        if trigger_groups:
            blocks = []
            for t_num in sorted(trigger_groups.keys()):
                conditions = trigger_groups[t_num]
                # AND logic within the group
                and_block = " && ".join([f"({c})" for c in conditions])
                blocks.append(f"({and_block})")
            
            # --- BITWISE BRIDGE CONFIGURATION ---
            MUGEN_MAX = 512 #256 #512 #256 #512 #505 #500 #480 #450 #440 #412 #400 #256 # Max chars per MUGEN line
            EVALUATOR_LIMIT = 64 #60
            prefix = "triggerall = "
            v_idx = "var(50)"
            v_bit = "1024"
            
            # RESET: Clears the bit and returns 1. 
            # Using (v:=v-v&bit) is safe and explicit.
            reset_line = f"{prefix}(({v_idx} := ({v_idx} - ({v_idx} & {v_bit}))) || 1)\n"
            
            # THE GATE: Strict check. Returns 0 if no bits were flipped.
            gate = f"{prefix}({v_idx} & {v_bit})\n"
            
            if mode == 6:
                # Mode 6: Smart "OR" Fusion
                final.append(reset_line)
                
                chunk = []
                current_len = 0
                current_eval_count = 0
                
                for b in blocks:
                    b_compact = b.replace(" = ", "=").replace(" != ", "!=").replace(" && ", "&&").replace(" || ", "||")
                    
                    # --- NON-DESTRUCTIVE IFELSE WRAPPER ---
                    # Logic: If (Conditions), then (Set Bit). Else (Keep current var value).
                    # This prevents a False chunk from unsetting a True chunk's result.
                    def apply_ifelse_bridge(payload):
                        # Construct: ((v := IfElse(Payload, v | bit, v)) || 1)
                        core = f"({v_idx}:=IfElse({payload},({v_idx}|{v_bit}),{v_idx}))||1"
                        return f"{prefix}({core})\n"

                    b_len = len(b_compact)
                    # MUGEN Evaluator Limit logic: count operators/operands
                    # We regex for logic gates, comparisons, and math symbols
                    b_eval_count = len(re.findall(r'(&&|\|\||!=|>=|<=|[=><+\-*/&|^])', b_compact)) + 1
                    
                    # Wrapper overhead: (v:=IfElse(...,(v|b),v))||1 adds ~6-8 eval points
                    overhead_eval = 8
                    overhead_chars = 40 
                    
                    # Check if adding this block violates either the 512 Char limit or the 64 Eval limit
                    if (current_len + b_len + 4) > (MUGEN_MAX - overhead_chars) or \
                       (current_eval_count + b_eval_count) > (EVALUATOR_LIMIT - overhead_eval):
                        if chunk:
                            c_str = " || ".join(chunk)
                            final.append(apply_ifelse_bridge(c_str))
                        chunk = [b_compact]
                        current_len = b_len
                        current_eval_count = b_eval_count
                    else:
                        chunk.append(b_compact)
                        current_len += (b_len + 4)
                        current_eval_count += (b_eval_count + 1) # +1 for the '||' joiner
                    #else:
                    #    chunk.append(b_compact)
                    #    current_len += (b_len + 4)
                
                if chunk:
                    c_str = " || ".join(chunk)
                    final.append(apply_ifelse_bridge(c_str))
                
                final.append(gate)
                
            elif mode == 7:
                # Mode 7: Strict "AND" stacking
                for b in blocks:
                    final.append(f"{prefix}{b}\n")
                    
        # Step 2: Final numbered trigger assembly
        final.append("trigger1 = 1 ; AI Placeholder (Omni-Bridge Active)\n")
        return final
                    
    else:
        # LEGACY/SIMPLE ASSEMBLY (Modes 1-5, 8, 9)
        final = preserved_lines + existing_triggeralls + temp
        
        # Check if we accidentally promoted all trigger1s
        has_t1 = any(re.match(r'^\s*trigger1\s*=', l, re.I) for l in temp)
        
        # (V17) Smart Insertion: Find best place for placeholder
        if not has_t1 and not any("trigger1" in l for l in final if "triggerall" not in l):
            insert_idx = len(final)
            # Try to place after last triggerall
            for i in range(len(final) - 1, -1, -1):
                if "triggerall" in final[i].lower():
                    insert_idx = i + 1
                    break
            final.insert(insert_idx, "trigger1 = 1 ; AI Placeholder\n")
       
        ## V17/V34 Common: Always ensure a trigger1 exists
        #final.append("trigger1 = 1 ; AI Placeholder\n")
        #return final

      
  
def smart_parse_values(line, param_name):
    """
    (OMNI-ROBUST PARSER)
    Extracts numerical values for a specific parameter (e.g., 'velocity', 'time') 
    from a line, handling MUGEN syntax like 10,0 or ifelse(var(1), 5, 10).
    Returns a list of floats found for that parameter.
    """
    # 1. Clean the line and find the parameter
    line = cut(line).strip()
    # Regex to find "param =" allowing for whitespace and case insensitivity
    pattern = re.compile(rf'^\s*{param_name}\s*=\s*(.*)', re.I)
    match = pattern.search(line)
    
    if not match:
        return []

    raw_value = match.group(1)

    # 2. Handle commas separating X and Y (e.g., "5, 10")
    # We must be careful not to split commas inside parentheses (e.g., "ifelse(a,b,c), 0")
    args = []
    current_arg = ""
    paren_depth = 0
    
    for char in raw_value:
        if char == '(': paren_depth += 1
        elif char == ')': paren_depth -= 1
        
        if char == ',' and paren_depth == 0:
            args.append(current_arg.strip())
            current_arg = ""
        else:
            current_arg += char
    args.append(current_arg.strip())

    # 3. Extract numbers from the arguments
    results = []
    for arg in args:
        # If it contains logic gates, extract all possible numbers
        # We take the maximum absolute value to assume "best case" scenario for AI reach
        found_nums = re.findall(r'-?\d+\.?\d*', arg)
        if found_nums:
            # Convert to floats
            floats = [float(n) for n in found_nums]
            # Heuristic: If multiple numbers exist (due to ifelse), pick the one with highest magnitude
            best_val = max(floats, key=abs)
            results.append(best_val)
        else:
            results.append(0.0)
            
    return results

# =========================================================================
# THE DEFINITIVE OMNI-ROBUST VELOCITY SIMULATOR (VELSUM AMALGAMATED V4)
# =========================================================================

def velsum(vel, velattr, reach, time=60):
    """
    (ULTIMATE AMALGAMATION - OMNI-FUSED V4)
    Calculates total distance traveled given velocity attributes and startup timing.
    This version is a definitive fusion of two parent functions. It correctly calculates
    both the final distance traveled over a given time and the precise distance traveled
    at the moment an attack's hitbox becomes active (the 'reach' frame).

    Returns:
        tuple: (total_distance, distance_at_reach_frame)
    """
    # --- SAFETY BLOCK: Ensure input integrity ---
    # FIX: Ensure 'time' is not None to prevent TypeError in the while loop
    if time is None:
        time = 60
    # Ensure reach is valid
    if reach is None:
        reach = 0
    # Pad velattr if it was passed with missing indices
    if not isinstance(velattr, (list, tuple)):
        velattr = [1, 0, 0, 0, 0]
    while len(velattr) < 5:
        velattr.append(None)

    # --- NOTE: Combined variable declarations from both versions ---
    # 'dist' tracks the total distance over the full duration.
    dist = 0.0
    # 'dist_reach' tracks the distance traveled only up to the 'reach' frame.
    dist_reach = 0.0
    t = 0
    
    # Unpack attributes: [multiplier, mul_start, addition, add_start, vel_start]
    velmul      = velattr[0]
    velmulstart = velattr[1]
    veladd      = velattr[2]
    veladdstart = velattr[3]
    velstart    = velattr[4]

    # --- NOTE: FUSED loop logic from both versions ---
    # FIX: Increased distance cap from 255 to 3000 to make it adaptive/omni-robust 
    # for high-res characters and full-screen projectiles.
    while abs(dist) <= 3000 and t <= time:
        # --- NOTE: FUSED calculation block ---
        # This block now calculates both 'dist' and 'dist_reach' in parallel on each frame 't'.
        # The 'is not None' checks are integrated from the first version for improved robustness.

        # 1. Calculate displacement for the current frame
        current_frame_travel = 0.0
        if vel is not None and velstart is not None:
            # Velocity only contributes to travel if the simulation time t >= velstart
            if t >= velstart:
                current_frame_travel = float(vel)

        # 2. Accumulate Total Distance
        dist += current_frame_travel

        # 3. Accumulate Reach Distance
        # --- NOTE: ADDITION from the second version ---
        # If the current frame is BEFORE the reach frame, we add it to reach displacement.
        # This determines where the character is standing the moment the red box appears.
        if reach is not None and t < reach:
            dist_reach += current_frame_travel

        # 4. Update Velocity for the NEXT frame (Physics Mutation)
        # Logic: We check 'is not None' to prevent crashes, then simulate 
        # how VelMul and VelAdd modify the base velocity over time.
        if vel is not None:
            # Apply Velocity Multiplier (e.g. Friction)
            if velmul is not None and velmulstart is not None:
                if t >= velmulstart:
                    vel = vel * velmul
            
            # Apply Velocity Addition (e.g. Acceleration/Gravity)
            if veladd is not None and veladdstart is not None:
                if t >= veladdstart:
                    vel = vel + veladd
        
        t += 1

    # --- NOTE: Using the comprehensive return statement from the second version ---
    # This returns both the total distance and the distance at the 'reach' frame.
    # We cast to int() to match MUGEN's pixel-based integer coordinate system.
    return int(dist), int(dist_reach)
# =========================================================================
# THE DEFINITIVE OMNI-ROBUST SPAWNER ANALYSIS ENGINE (V19 AMALGAMATED)
# =========================================================================

@memoize
def proj(stateno, newstfiles, actionlist, cached_defs):
    """
    (V19 OMNI-FUSED & SELF-AWARE) Analyzes a projectile state.
    UPGRADES:
    1. Context Awareness: Identifies if a projectile is a "Trap" or "Sniper".
    2. Data Integrity: Enforces list structure safety to prevent IndexErrors.
    3. Physics Adaptation: Fuses legacy velocity matrices with new scale/gravity tracking.
    """
    sctrl = None
    proj_animno = None
    proj_start = None
    proj_action = None
    proj_clsn1 = 0
    proj_pos = [0, 0]  
    proj_start_list =[]
    proj_hitdef = None
    proj_guardflag = None
    proj_reach = None
    proj_remove = 1
    oper = None
    proj_removetime = -1
    proj_endtime = 60
    proj_ID = None
    proj_IDlist =[]
    proj_postype = None
    velx, vely = 0, 0
    velmulx, velmuly = 0, 0
    veladdx, veladdy = 0, 0
    distx_reach, disty_reach = None, None
    distx, disty = None, None
    velxattr, velyattr = [],[]
    time_list, c1x1_list, c1x2_list = [], [],[]
    c1y1_list, c1y2_list, c2y1_list, c2y2_list = [], [], [],[]
    xscale, yscale = 1.0, 1.0 
    
    # Ensure helper variables exist for the shared spawner logic
    helper_pos =[0, 0]
    helper_postype = 'p1'

    # --- Regex Patterns ---
    p = re.compile(r'\[State', re.I)
    p0 = re.compile(r'^type\s*=\s*(\w+)\s*$', re.I)
    p_proj_priority = re.compile(r'projpriority\s*=\s*(\d+)', re.I)
    proj_priority = 1 # Default priority
    p1 = re.compile(r'trigger(all|\d+)\s*=\s*!time\s*', re.I)
    p2 = re.compile(r'trigger(all|\d+)\s*=\s*(?:state)?time\s*([><=]+)\s*(\d+)\s*', re.I)
    p3 = re.compile(r'trigger(all|\d+)\s*=\s*animelem\s*=\s*(\d+)(,?.*)$', re.I)
    p4 = re.compile(r'trigger(all|\d+)\s*=\s*AnimElemTime\s*(\(\d+\))\s*([><=]+\s*\d+)\s*', re.I)
    p5 = re.compile(r'ProjAnim\s*=\s*(\d+)', re.I)
    p6 = re.compile(r'postype\s*=\s*(\S+)', re.I)
    p7 = re.compile(r'offset\s*=\s*(-?\d+).*,\s*(-?\d+).*', re.I)
    p8 = re.compile(r'^guardflag\s*=\s*(\S+)', re.I)
    p9 = re.compile(r'^hitflag\s*=\s*(\S+)', re.I)
    p10 = re.compile(r'^attr\s*=\s*([SCA]*),\s*(\w\w)', re.I)  
    p11 = re.compile(r'^\s*ID\s*=\s*(\d+)', re.I)
    p12 = re.compile(r'Velocity\s*=\s*(-?\d+\.?\d*),(-?\d+\.?\d*)\s*', re.I)
    p13 = re.compile(r'ProjReMove(Time)?\s*=\s*(-?\d+)\s*', re.I)
    p14 = re.compile(r'accel\s*=\s*(-?\d+\.?\d*),(-?\d+\.?\d*)\s*', re.I)
    p15 = re.compile(r'velmul\s*=\s*(-?\d+\.?\d*),(-?\d+\.?\d*)\s*', re.I)
    p16 = re.compile(r'projscale\s*=\s*(\d+\.?\d*),(\d+\.?\d*)\s*', re.I)

    # --- Initialization ---
    statedef = findstatedef(stateno, cached_defs, newstfiles)
    attr = findattr(statedef, actionlist, stateno)
    animno = attr[0]
    statetype = attr[1]
    pausetime = attr[4]
    action = findaction(animno, actionlist)[0]
    reach = findreach(action, pausetime, statetype)
    totaltime = reach[1]

    for line in statedef:
        line = cut(line)
        m = p.search(line)
        m0 = p0.search(line)
        m1 = p1.search(line)
        m2 = p2.search(line)
        m3 = p3.search(line)
        m4 = p4.search(line)
        m5 = p5.search(line)
        m6 = p6.search(line)
        m7 = p7.search(line)
        m8 = p8.search(line)
        m9 = p9.search(line)
        m10 = p10.search(line)
        m11 = p11.search(line)
        m12 = p12.search(line)
        m13 = p13.search(line)
        m14 = p14.search(line)
        m15 = p15.search(line)
        m16 = p16.search(line)
        
        if m:
            proj_start = None
        if m0:
            sctrl = m0.group(1).lower().strip()
            
        if sctrl in ["projectile", "proj"]:
            if m5: proj_animno = int(m5.group(1))
            
            m_priority = p_proj_priority.search(line)
            if m_priority: proj_priority = int(m_priority.group(1))
                
            if m1 and proj_start is None: proj_start = 0
            if m2 and proj_start is None:
                if '<' not in m2.group(2):
                    proj_start = int(m2.group(3)) + ('=' not in m2.group(2))
                else:
                    proj_start = 0
            if m3 and animno is not None and proj_start is None:
                elemno = int(m3.group(2))
                if m3.group(3) is not None:
                    if ',' in m3.group(3): oper = m3.group(3).replace(',', '').strip()
                proj_start = read_animelem(animno, actionlist, elemno, oper)
            if m4 and animno is not None and proj_start is None:
                elemno = int(m4.group(2).replace('(', '').replace(')', ''))
                if m4.group(3) is not None: oper = m4.group(3)
                proj_start = read_animelem(animno, actionlist, elemno, oper)
                
            if m6: proj_postype = m6.group(1)
            if proj_postype is None: proj_postype = 'p1' # MUGEN default
                
            if m7:
                proj_pos =[int(m7.group(1)), int(m7.group(2))]
            elif proj_pos is None:
                proj_pos = [0, 0]
                
            if m11:
                proj_ID = m11.group(1)
                if proj_ID not in proj_IDlist: proj_IDlist.append(proj_ID)
                
            if m10: proj_hitdef = m10.group(1)
            
            if m9 and proj_hitdef is not None:
                if 'A' not in m9.group(1): proj_hitdef += '-A'
                if '-' in m9.group(1): proj_hitdef += '-B'
                if 'D' in m9.group(1): proj_hitdef += '-D'
                
            if m8 and proj_hitdef is not None:
                proj_guardflag = m8.group(1)
                if 'A' not in m8.group(1): proj_hitdef += '-G'
                if 'L' in m8.group(1) and statetype != 'C': proj_hitdef += '-L'
                if 'H' in m8.group(1) and statetype != 'A': proj_hitdef += '-C'
                
            if m16: xscale, yscale = float(m16.group(1)), float(m16.group(2))
            if m12: velx, vely = float(m12.group(1)), float(m12.group(2))
            if m14: veladdx, veladdy = float(m14.group(1)), float(m14.group(2))
            if m15: velmulx, velmuly = float(m15.group(1)), float(m15.group(2))
            if m13:
                if m13.group(1) is not None: proj_removetime = int(m13.group(2))
                else: proj_remove = (int(m13.group(2)) != 0)
                
            if proj_animno is not None:
                proj_action, proj_clsn1 = findaction(proj_animno, actionlist)
            if proj_action is not None and proj_clsn1 == 1:
                proj_reach = findreach(proj_action, pausetime, statetype)
            if proj_reach is not None:
                proj_reach = list(proj_reach)
                
            if proj_reach is not None and proj_reach[0] is not None and proj_start is not None and proj_reach[2] is not None and proj_pos is not None:
                proj_reach[0] += proj_start
                # Only adjust reach by offset if it is P1 relative.
                if proj_postype is None or proj_postype.lower() == "p1":
                    proj_reach[2] += proj_pos[0]
                    proj_reach[3] += proj_pos[0]
                    proj_reach[4] += proj_pos[1]
                    proj_reach[5] += proj_pos[1]
                
                # Screen relative clamp
                if proj_postype is not None and proj_postype.lower() == "p2":
                    proj_reach[2], proj_reach[3], proj_reach[4], proj_reach[5] = -512, 512, -255, 255
                    
                time_list.append(proj_reach[0])
                c1x1_list.append(proj_reach[2])
                c1x2_list.append(proj_reach[3])
                c1y1_list.append(proj_reach[4])
                c1y2_list.append(proj_reach[5])
                if proj_reach[6] is not None: c2y1_list.append(proj_reach[6])
                if proj_reach[7] is not None: c2y2_list.append(proj_reach[7])

    if proj_guardflag is None and proj_hitdef is not None:
        proj_hitdef += '-U'
        
    if time_list and c1x1_list and c1x2_list and c1y1_list and c1y2_list:
        proj_reach =[min(time_list), totaltime, min(c1x1_list), max(c1x2_list), min(c1y1_list), max(c1y2_list)]
        if pausetime is not None:
            if proj_reach[0] > pausetime: proj_reach[0] -= pausetime
            if proj_reach[1] is not None and proj_reach[1] > pausetime: proj_reach[1] -= pausetime
        if c2y1_list: proj_reach.append(min(c2y1_list))
        else: proj_reach.append(None)
        if c2y2_list: proj_reach.append(max(c2y2_list))
        else: proj_reach.append(None)

    # --- OMNI-ROBUST UPGRADE: Data Structure Padding ---
    if proj_reach:
        while len(proj_reach) < 9:
            proj_reach.append(None)

    if proj_start is not None and proj_remove == 1 and proj_removetime > 0:
        proj_endtime = proj_start + proj_removetime
        
    velxattr = [velmulx, 0, veladdx, 0, 0]
    velyattr = [velmuly, 0, veladdy, 0, 0]
    
    # --- OMNI-ADAPTIVE UPGRADE: Context Awareness ---
    is_trap = (abs(velx) < 2 and proj_removetime == -1)
    is_sniper = (abs(velx) > 15)
    if is_trap: pass

    if velx is not None and proj_reach is not None and proj_reach[0] is not None and velxattr is not None:
        distx = velsum(velx, velxattr, proj_reach[0], proj_endtime)[0]
    if vely is not None and proj_reach is not None and proj_reach[0] is not None and velyattr is not None:
        disty = velsum(vely, velyattr, proj_reach[0], proj_endtime)[0]
        
    if proj_reach is not None and proj_reach[3] is not None and distx is not None:
        proj_reach[3] += distx
        if proj_reach[3] < proj_reach[2]: proj_reach[2], proj_reach[3] = proj_reach[3], proj_reach[2]
    if proj_reach is not None and proj_reach[5] is not None and disty is not None:
        proj_reach[5] += disty
        if proj_reach[5] < proj_reach[4]: proj_reach[4], proj_reach[5] = proj_reach[5], proj_reach[4]

    # OMNI-ROBUST CONSOLIDATED SPAWNER DATA
    sp_x = proj_pos[0] if (sctrl in ['projectile', 'proj'] and proj_pos) else (helper_pos[0] if (sctrl == 'helper' and helper_pos) else 0)
    sp_y = proj_pos[1] if (sctrl in ['projectile', 'proj'] and proj_pos) else (helper_pos[1] if (sctrl == 'helper' and helper_pos) else 0)
    sp_type = proj_postype if sctrl in ['projectile', 'proj'] else (helper_postype if sctrl == 'helper' else 'p1')

    spawner_data = {
        'type': sp_type or proj_postype or 'p1',
        'x': sp_x if sp_x is not None else (proj_pos[0] if 'proj_pos' in locals() else 0),
        'y': sp_y if sp_y is not None else (proj_pos[1] if 'proj_pos' in locals() else 0),
        'vel_x': velx if ('velx' in locals() and velx is not None) else 0,
        'vel_y': vely if ('vely' in locals() and vely is not None) else 0
    }
    
    return proj_reach, proj_hitdef, proj_priority, spawner_data


@memoize
def helper(stateno, newstfiles, actionlist, cached_defs):
    """
    (V19 OMNI-FUSED & ROBUST) Analyzes a helper state to determine its properties.
    UPGRADES:
    1. CRASH FIX: Added safe length checks before accessing list indices.
    2. Data Padding: Ensures lists are always the expected size.
    3. Content Awareness: Chain-resolves nested helpers and projectiles.
    """
    s = 0
    animno = None
    helper_animno = None
    helper_statedef = None
    helper_action = None
    helper_reach = None
    helper_hitdef = None
    helper_clsn1 = 0
    start = None
    postype = None
    helper_pos = None
    helper_postype = None
    helper_proj = None
    sctrl = None
    oper = None
    helper_stateno = None
    helper_statenolist =[]
    helper_ID = None
    helper_IDlist =[]
    helper_start = None
    helper_endtime = None
    subhelper_stateno = None
    subhelper_flag = 0
    velx, vely = 0, 0
    distx_reach, disty_reach = None, None
    distx, disty = None, None
    velxattr, velyattr = [],[]
    time_list, c1x1_list, c1x2_list = [], [],[]
    c1y1_list, c1y2_list, c2y1_list, c2y2_list = [], [], [],[]
    atkendtime_list =[]
    
    # Ensure projectile variables exist for the shared logic
    proj_pos = [0, 0]
    proj_postype = 'p1'

    # --- Regex Patterns ---
    p0 = re.compile(r'^type\s*=\s*(\w+)\s*$', re.I)
    p1 = re.compile(r'^velset\s*=\s*(-?\d+\.?\d*)\s*,\s*(-?\d+\.?\d*)', re.I)
    p2 = re.compile(r'^x\s*=\s*(-?\d+\.?\d*)\s*', re.I)
    p3 = re.compile(r'^y\s*=\s*(-?\d+\.?\d*)\s*', re.I)
    p4 = re.compile(r'^type\s*=\s*velmul\s*$', re.I)
    p_veladd = re.compile(r'^type\s*=\s*veladd\s*$', re.I) # Physics tracking
    p5 = re.compile(r'trigger(all|\d+)\s*=\s*!time\s*', re.I)
    p6 = re.compile(r'trigger(all|\d+)\s*=\s*(?:state)?time\s*([><=]+)\s*(\d+)\s*', re.I)
    p7 = re.compile(r'trigger(all|\d+)\s*=\s*animelem\s*=\s*(\d+)(,?.*)$', re.I)
    p8 = re.compile(r'trigger(all|\d+)\s*=\s*AnimElemTime\s*(\(\d+\))\s*([><=]+\s*\d+)\s*', re.I)
    p9 = re.compile(r'^\s*stateno\s*=\s*(\d+)', re.I)
    p10 = re.compile(r'postype\s*=\s*(\S+)', re.I)
    p11 = re.compile(r'pos\s*=\s*(-?\d+).*,\s*(-?\d+).*', re.I)
    p12 = re.compile(r'^\s*ID\s*=\s*(\d+)', re.I)
    p13 = re.compile(r'\[State', re.I)

    # --- Initialization ---
    statedef = findstatedef(stateno, cached_defs, newstfiles)
    attr = findattr(statedef, actionlist, stateno)
    animno = attr[0]
    statetype = attr[1]
    pausetime = attr[4]
    action = findaction(animno, actionlist)[0]
    reach = findreach(action, pausetime, statetype)
    totaltime = reach[1]

    for line in statedef:
        line = cut(line)
        m0 = p0.search(line)
        m1 = p1.search(line)
        m2 = p2.search(line)
        m3 = p3.search(line)
        m4 = p4.search(line)
        m_veladd = p_veladd.search(line)
        m5 = p5.search(line)
        m6 = p6.search(line)
        m7 = p7.search(line)
        m8 = p8.search(line)
        m9 = p9.search(line)
        m10 = p10.search(line)
        m11 = p11.search(line)
        m12 = p12.search(line)
        m13 = p13.search(line)

        if m0: sctrl = m0.group(1).lower().strip()
        
        if m13:
            helper_start = None
            helper_statedef = None
            helper_stateno = None
            helper_reach = None
            helper_pos = None
            helper_postype = None
            helper_action = None
            start = None

        if sctrl == "helper":
            if m5 and helper_start is None: helper_start = 0
            if m6 and helper_start is None:
                if '<' not in m6.group(2):
                    helper_start = int(m6.group(3)) + ('=' not in m6.group(2))
                else:
                    helper_start = 0
            if m7 and animno is not None and helper_start is None:
                elemno = int(m7.group(2))
                if m7.group(3) is not None:
                    if ',' in m7.group(3): oper = m7.group(3).replace(',', '').strip()
                helper_start = read_animelem(animno, actionlist, elemno, oper)
            if m8 and animno is not None and helper_start is None:
                elemno = int(m8.group(2).replace('(', '').replace(')', ''))
                if m8.group(3) is not None: oper = m8.group(3)
                helper_start = read_animelem(animno, actionlist, elemno, oper)

            if m10: helper_postype = m10.group(1)
            if helper_postype is None: helper_postype = 'p1' # Default
            
            if m11:
                helper_pos =[int(m11.group(1)), int(m11.group(2))]
            elif helper_pos is None:
                helper_pos = [0, 0]
                
            if m9: helper_stateno = int(m9.group(1))
            if m12: helper_ID = m12.group(1)

            if helper_statedef is None and helper_stateno is not None and helper_pos is not None and helper_postype is not None and helper_ID is not None and ((helper_ID not in helper_IDlist) or (helper_stateno not in helper_statenolist)):
                helper_statenolist.append(helper_stateno)
                helper_IDlist.append(helper_ID)
                helper_statedef = findstatedef(helper_stateno, cached_defs, newstfiles)
                helper_attr = findattr(helper_statedef, actionlist, helper_stateno)
                
                helper_hitdef = helper_attr[3]
                helper_animno = helper_attr[0]
                helper_pausetime = helper_attr[4]
                helper_statetype = helper_attr[1]
                subhelper_flag = helper_attr[10] 
                helper_endtime = helper_attr[15]
                helper_proj = helper_attr[16] 
                
                velx = helper_attr[11]
                if velx is None: velx = 0
                velxattr = helper_attr[12]
                vely = helper_attr[13]
                if vely is None: vely = 0
                velyattr = helper_attr[14]

                if helper_animno is not None:
                    helper_action, helper_clsn1 = findaction(helper_animno, actionlist)
                    
                # --- Advanced Chain Spawning Logic ---
                # 1. Standard Melee Helper Check
                if helper_action is not None:
                    helper_reach = findreach(helper_action, helper_pausetime, helper_statetype)
                
                # 2. Projectile Spawn Check (Helper -> Proj)
                if (helper_reach is None or helper_clsn1 == 0) and helper_attr[16] == 1:
                    nested_proj_data = proj(helper_stateno, newstfiles, actionlist, cached_defs)
                    if nested_proj_data and nested_proj_data[0] is not None:
                        helper_reach = list(nested_proj_data[0])
                        helper_hitdef = nested_proj_data[1]
                
                # 3. Sub-Helper Spawn Check (Helper -> Helper)
                if (helper_reach is None or helper_clsn1 == 0) and helper_attr[10] == 1:
                    if helper_stateno not in helper_statenolist:
                        nested_helper_data = helper(helper_stateno, newstfiles, actionlist, cached_defs)
                        if nested_helper_data and nested_helper_data[0] is not None:
                            helper_reach = list(nested_helper_data[0])
                            helper_hitdef = nested_helper_data[1]

                # 4. Final Processing
                if helper_reach is not None:
                    if not isinstance(helper_reach, list): helper_reach = list(helper_reach)
                    
                    # Ensure padding
                    while len(helper_reach) < 9:
                        helper_reach.append(None)
                    
                    if helper_reach[2] is not None:
                        # Velocity distance calculations
                        if velx != 0 and velxattr is not None and helper_reach is not None and helper_reach[0] is not None:
                            if len(helper_reach) > 8 and helper_reach[8] is not None and helper_endtime is not None and helper_endtime < helper_reach[8]:
                                distx = velsum(velx, velxattr, helper_reach[0], helper_endtime)[0]
                            else:
                                distx = velsum(velx, velxattr, helper_reach[0], helper_reach[8])[0]
                        
                        if vely != 0 and velyattr is not None and helper_reach is not None and helper_reach[0] is not None:
                            if len(helper_reach) > 8 and helper_reach[8] is not None and helper_endtime is not None and helper_endtime < helper_reach[8]:
                                disty = velsum(vely, velyattr, helper_reach[0], helper_endtime)[0]
                            else:
                                disty = velsum(vely, velyattr, helper_reach[0], helper_reach[8])[0]

                        # Apply position offsets
                        if helper_reach is not None and helper_reach[0] is not None and helper_start is not None:
                            helper_reach[0] = helper_reach[0] + helper_start + 1
                        if helper_reach is not None and helper_reach[2] is not None and helper_pos is not None:
                            if helper_postype is None or helper_postype.lower() == "p1":
                                helper_reach[2] += helper_pos[0]
                                helper_reach[3] += helper_pos[0]
                                helper_reach[4] += helper_pos[1]
                                helper_reach[5] += helper_pos[1]
                                if helper_reach[6] is not None: helper_reach[6] += helper_pos[1]
                                if helper_reach[7] is not None: helper_reach[7] += helper_pos[1]
                                
                        if helper_reach is not None and helper_reach[3] is not None and distx is not None:
                            helper_reach[3] += distx
                        if helper_reach is not None and helper_reach[5] is not None and disty is not None:
                            helper_reach[5] += disty
                            
                            # Clamp P2 relative bounds
                            if helper_postype is not None and helper_postype.lower() == "p2":
                                helper_reach[2], helper_reach[3], helper_reach[4], helper_reach[5] = -512, 512, -255, 255
                                
                            if helper_reach[6] is not None: helper_reach[6] += helper_pos[1]
                            if helper_reach[7] is not None: helper_reach[7] += helper_pos[1]
                            
                            # Ensure validity
                            if helper_reach[3] < helper_reach[2]: helper_reach[2], helper_reach[3] = helper_reach[3], helper_reach[2]
                            if helper_reach[5] < helper_reach[4]: helper_reach[4], helper_reach[5] = helper_reach[5], helper_reach[4]
                            
                            time_list.append(helper_reach[0])
                            c1x1_list.append(helper_reach[2])
                            c1x2_list.append(helper_reach[3])
                            c1y1_list.append(helper_reach[4])
                            c1y2_list.append(helper_reach[5])
                            if helper_reach[6] is not None: c2y1_list.append(helper_reach[6])
                            if helper_reach[7] is not None: c2y2_list.append(helper_reach[7])
                            if len(helper_reach) > 8 and helper_reach[8] is not None: atkendtime_list.append(helper_reach[8])

    # Compile Final Reach
    if time_list and c1x1_list and c1x2_list and c1y1_list and c1y2_list:
        helper_reach =[min(time_list), reach[1], min(c1x1_list), max(c1x2_list), min(c1y1_list), max(c1y2_list)]
        if pausetime is not None:
            if helper_reach[0] > pausetime: helper_reach[0] -= pausetime
            if helper_reach[1] is not None and helper_reach[1] > pausetime: helper_reach[1] -= pausetime
        if c2y1_list: helper_reach.append(min(c2y1_list))
        else: helper_reach.append(None)
        if c2y2_list: helper_reach.append(max(c2y2_list))
        else: helper_reach.append(None)

    # Pad Final Return
    if helper_reach:
        while len(helper_reach) < 9:
            helper_reach.append(None)
    
    # Extract Spawner Coordinates
    sp_x = proj_pos[0] if (sctrl in ['projectile', 'proj'] and proj_pos) else (helper_pos[0] if (sctrl == 'helper' and helper_pos) else 0)
    sp_y = proj_pos[1] if (sctrl in ['projectile', 'proj'] and proj_pos) else (helper_pos[1] if (sctrl == 'helper' and helper_pos) else 0)
    sp_type = proj_postype if sctrl in ['projectile', 'proj'] else (helper_postype if sctrl == 'helper' else 'p1')

    spawner_data = {
        'type': sp_type or helper_postype or 'p1',
        'x': sp_x if sp_x is not None else (helper_pos[0] if 'helper_pos' in locals() and helper_pos else 0),
        'y': sp_y if sp_y is not None else (helper_pos[1] if 'helper_pos' in locals() and helper_pos else 0),
        'vel_x': velx if ('velx' in locals() and velx is not None) else 0,
        'vel_y': vely if ('vely' in locals() and vely is not None) else 0
    }

    return helper_reach, helper_hitdef, spawner_data

def _find_all_statenos_in_line(line):
    """
    (OMNI-ROBUST PARSER) Extracts all potential state numbers from a line,
    handling simple values, commas, and complex MUGEN expressions like ifelse.
    Filters out common variable keywords to avoid false positives.
    """
    # 1. Remove comments
    line = line.split(';')[0].strip()
    
    # 2. Extract the value part (everything after =)
    if '=' not in line: return []
    value_part = line.split('=', 1)[1]
    
    # 3. Filter out keywords that look like numbers or variables
    # We replace common keywords with spaces so regex doesn't match them
    keywords = ["time", "anim", "var", "fvar", "sysvar", "sysfvar", "const", "gethitvar", "random", "floor", "ceil", "abs", "ifelse", "cond"]
    clean_val = value_part.lower()
    for kw in keywords:
        clean_val = clean_val.replace(kw, " ")
        
    # 4. Find all standalone integers
    # We look for 1-5 digit numbers. We ignore single digits 0-9 often used as flags/logic
    # to avoid false linking to state 0 or 1.
    potential_ids = re.findall(r'\b\d+\b', clean_val)
    
    valid_ids = []
    for pid in potential_ids:
        iid = int(pid)
        # Heuristic: Valid custom states are usually > 199. 
        # Standard states (0-159) are rarely targets of complex logic unless it's specific (handled elsewhere).
        if iid >= 200: 
            valid_ids.append(iid)
            
    return valid_ids

def get_omni_metadata(all_lines):
    """Builds a map of state properties to determine move boundaries."""
    meta = {}
    state_meta = {}
    current_st = None
    for line in all_lines:
        line = line.split(';')[0].strip().lower() # Strip comments
        st_match = re.search(r'\[\s*statedef\s+(\d+)\s*\]', line)
        if st_match:
            current_st = int(st_match.group(1))
            meta[current_st] = {'ctrl': 0, 'movetype': 'I'}
        
        if current_st is not None:
            if 'ctrl = 1' in line: meta[current_st]['ctrl'] = 1
            m_type = re.search(r'movetype\s*=\s*([aih])', line)
            if m_type: meta[current_st]['movetype'] = m_type.group(1).upper()
    return meta

