@memoize
def state_read(stateno, newstfiles, actionlist, cached_defs):
    """
    (V34 OMNI-SENTIENT AGGREGATE) Top-level exhaustive analysis function.
    Fuses all legacy parameters with modern deep-scanning.
    Reads EVERY line of the statedef, ensuring no SCTRL or argument is ignored.

    It incorporates:
    - The advanced Data Fusion Gatekeeper for performance and consistency.
    - The comprehensive, multi-layered attack type classification system.
    - The deep recursive analysis for moves that spawn helpers and projectiles.
    - The simple but effective self-chaining infinite loop prevention from the secondary version.
    """
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    # --- 1. DATA FUSION GATEKEEPER ---
    # --- NOTE: ADDITION from first version: Data Fusion Gatekeeper ---
    # This block checks the global cache FIRST. If a complete, advanced
    # analysis already exists, it uses that superior data and returns
    # immediately, bypassing the older analysis logic below.
    if stateno in GLOBAL_ANALYSIS_CACHE and (GLOBAL_ANALYSIS_CACHE[stateno].get('_advanced_analyzed') or GLOBAL_ANALYSIS_CACHE[stateno].get('_legacy_analyzed')):
        advanced_data = GLOBAL_ANALYSIS_CACHE[stateno]
        
        # SPEED FIX: If it's currently 'processing' in a deep loop, return a generic safe tuple immediately to prevent recursion lag.
        if advanced_data.get('_status') == 'processing':
            return "unknown", tuple([None]*38), [0,0,None,None,None,None,None,None,0], None, None

        # Directly use the richer data from the advanced analysis.
        stateattr = advanced_data.get('stateattr', [])
        reach = advanced_data.get('reach', [None] * 9)
        attacktype = advanced_data.get('attacktype', 'unknown')
        attr = advanced_data.get('attr_string', None)
