def generate_integrated_guard_cancel_ai(ai_var, aihelperID, power_cost=1000):
    """
    (CONVERTED AS PER DIRECT INSTRUCTION) Generates and injects AI [State -3] blocks
    for Guard Cancel moves into a provided state block. This version strictly adheres to
    the requested tempstate = state[:] and tempstate.insert() pattern.
    """
    # --- NOTE: ADHERING TO THE MANDATED PATTERN ---
    # The function now starts by making a copy of the input state block and
    # setting the insertion index to the provided trigger point.
    tempstate = state[:]
    idx = trigger

    # Retrieve the state numbers for forward and backward guard cancels.
    gc_fwd_stateno_list = movement_states.get('guard_cancel_roll_fwd', [])
    gc_back_stateno_list = movement_states.get('guard_cancel_roll_back', [])

    # --- Generate and Inject the Forward Guard Cancel Block ---
    if gc_fwd_stateno_list:
        gc_fwd_stateno = gc_fwd_stateno_list[0]
        
        # --- NOTE: Each line of the new state block is now individually inserted ---
        # --- into the copy of the original state block at the specified index. ---
        tempstate.insert(idx, f"\n; AI: Guard Cancel Fwd (Reactive)\n"); idx += 1
        tempstate.insert(idx, f"triggerall = {ai_var} > 0 && Roundstate = 2\n"); idx += 1
        tempstate.insert(idx, f"triggerall = power >= {power_cost}\n"); idx += 1
        tempstate.insert(idx, f"triggerall = stateno = 151 ; While in guard stun\n"); idx += 1
        tempstate.insert(idx, f"trigger1 = P2Dist X < 0 ; Use fwd roll to cross-up a cornered opponent\n"); idx += 1
        tempstate.insert(idx, f"triggerall = random <= 600 * {get_ai_scale_string(stateno, ai_var)}\n"); idx += 1

    # --- Generate and Inject the Backward Guard Cancel Block ---
    if gc_back_stateno_list:
        gc_back_stateno = gc_back_stateno_list[0]

        # --- NOTE: The insertion continues from where the last one left off. ---
        tempstate.insert(idx, f"\n; AI: Guard Cancel Back (Reactive)\n"); idx += 1
        tempstate.insert(idx, f"triggerall = {ai_var} > 0 && Roundstate = 2\n"); idx += 1
        tempstate.insert(idx, f"triggerall = power >= {power_cost}\n"); idx += 1
        tempstate.insert(idx, f"triggerall = stateno = 151 ; While in guard stun\n"); idx += 1
        tempstate.insert(idx, f"trigger1 = P2Dist X >= 0 ; Use back roll to create space\n"); idx += 1
        tempstate.insert(idx, f"triggerall = random <= 800 * {get_ai_scale_string(stateno, ai_var)}\n"); idx += 1

    return tempstate
def parse_hitdef_sctrl(statedef_lines):
    """Parses a HitDef block to extract key parameters for advanced analysis."""
    hitdef_params = {
        'id': 0,
        'chainid': -1,
        'projid': None,
        'projpriority': 1,
        'projhits': 1,
        'affectteam': 'E'
    }
    in_hitdef_block = False
    p_hitdef_type = re.compile(r'^\s*type\s*=\s*HitDef\s*$', re.I)
    p_proj_type = re.compile(r'^\s*type\s*=\s*Projectile\s*$', re.I)
    
    # Simplified regex for key parameters
    param_patterns = {
        'id': re.compile(r'^\s*id\s*=\s*(\d+)', re.I),
        'chainid': re.compile(r'^\s*chainid\s*=\s*(\d+)', re.I),
        'projid': re.compile(r'^\s*projid\s*=\s*(\d+)', re.I),
        'projpriority': re.compile(r'^\s*projpriority\s*=\s*(\d+)', re.I),
        'projhits': re.compile(r'^\s*projhits\s*=\s*(\d+)', re.I),
        'affectteam': re.compile(r'^\s*affectteam\s*=\s*([B|E|F])', re.I)
    }

    current_sctrl_lines = []
    for line in statedef_lines:
        if re.search(r'\[State', line, re.I):
            # Process the completed sctrl block
            if in_hitdef_block:
                for sctrl_line in current_sctrl_lines:
                    for key, pattern in param_patterns.items():
                        match = pattern.search(sctrl_line)
                        if match:
                            hitdef_params[key] = int(match.group(1)) if match.group(1).isdigit() else match.group(1)
                # Found and parsed one, can exit
                return hitdef_params
            
            # Reset for new sctrl block
            current_sctrl_lines = []
            if p_hitdef_type.search(line) or p_proj_type.search(line):
                in_hitdef_block = True
            else:
                in_hitdef_block = False

        if in_hitdef_block:
            current_sctrl_lines.append(line)

    # Process the last block if the file ends there
    if in_hitdef_block:
        for sctrl_line in current_sctrl_lines:
            for key, pattern in param_patterns.items():
                match = pattern.search(sctrl_line)
                if match:
                    hitdef_params[key] = int(match.group(1)) if match.group(1).isdigit() else match.group(1)

    return hitdef_params


def parse_reversaldef_sctrl(statedef_lines):
    """Parses a ReversalDef to find its specific reversal attributes."""
    reversal_params = {'reversal.attr': None}
    p_reversal_type = re.compile(r'^\s*type\s*=\s*ReversalDef\s*$', re.I)
    p_reversal_attr = re.compile(r'^\s*reversal\.attr\s*=\s*(.*)', re.I)
    
    in_reversal_block = False
    for line in statedef_lines:
        if re.search(r'\[State', line, re.I):
            if in_reversal_block: break # Stop after finding the first one
            in_reversal_block = bool(p_reversal_type.search(line))

        if in_reversal_block:
            match = p_reversal_attr.search(line)
            if match:
                reversal_params['reversal.attr'] = match.group(1).strip()
                return reversal_params # Found what we need
    return reversal_params

def write_transformation_triggers(state, trigger, analysis, ai_var, aihelperID):
    """
    AMALGAMATED V3: Handles Transformations, Installs, and Healing Supers.
    Combines logic for situational awareness and spamblock protection.
    """
    tempstate = state[:]
    stateno = analysis['stateno']
    # Use 1000 as default if power cost wasn't detected
    power_cost = analysis['stateattr'][2] if analysis['stateattr'][2] is not None else 1000
    is_healing = analysis.get('is_healing_move', False)
    
    tempstate.insert(trigger, "; AI: Transformation / Install / Heal Logic\n")
    
    # Optional variable injections (py/pyh)
    if 'py' in globals() and 'pyh' in globals():
        tempstate.insert(trigger, py) #py + pyh) 
    
    # --- 1. CORE SAFETY GATES ---
    tempstate.insert(trigger + 1, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    #tempstate.insert(trigger + 2, f"triggerall = power >= {power_cost}\n")
    
    # --- 2. ANTI-SPAM / STATE LOCK ---
    # Prevents the AI from trying to transform while already in the transformation state
    tempstate.insert(trigger + 3, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")

    # --- 3. SITUATIONAL LOGIC (Branching) ---
    if is_healing:
        tempstate.insert(trigger + 4, "; Intent: Healing / Regeneration\n")
        # Trigger: Use when life is low (below 50%) and safe distance
        tempstate.insert(trigger + 5, "trigger1 = ((Life < LifeMax * 0.5) && (p2dist x > 150)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
        # Trigger: Desperation heal (below 20%) even if closer, as long as P2 isn't attacking
        tempstate.insert(trigger + 6, "trigger2 = ((Life < LifeMax * 0.2) && (p2dist x > 100) && (enemynear,movetype != A)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
        # Trigger: Very early round recovery if chip damage was taken
        tempstate.insert(trigger + 7, "trigger3 = ((Life < LifeMax) * 0.8 && (time < 100) && (p2dist x > 200)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
    else:
        tempstate.insert(trigger + 4, "; Intent: Power-Up / Transformation / Install\n")
        # Trigger 1: At the start of the round from a safe distance.
        tempstate.insert(trigger + 5, "trigger1 = ((roundstate = 2) && (time < 60) && (p2dist x > 150)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
        # Trigger 2: After a knockdown when the opponent is far away.
        tempstate.insert(trigger + 6, "trigger2 = ((enemynear, statetype = L) && (p2dist x > 200)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
        # Trigger 3: Desperation / Comeback mechanic when life is low.
        tempstate.insert(trigger + 7, "trigger3 = ((life < lifemax * 0.4) && (p2dist x > 180)) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
        
    # --- 4. GLOBAL CHANCE & CONTROL ---
    # Randomness gate: Give it a 50% base chance to activate when triggers are met
    tempstate.insert(trigger + 8, f"triggerall = (random <= 500 * {get_ai_scale_string(stateno, ai_var)}) || (P2Dist X > 200) || (Life < LifeMax * 0.5) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
    
    # Final Control Check: Must have control OR be in a valid AI-helper state
    tempstate.insert(trigger + 9, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    
