            tempstate.insert(trigger + 5, f"triggerall = random < (25+50*(enemynear, movetype = H)+100*(enemynear,hitdefattr=sca,at && helper({aihelperID}),var(1)<=1 && abs(p2bodydist x) <= 60))* {get_ai_scale_string(stateno, ai_var)}\n")
            
            # --- Trigger 1: Spacing & Aggression ---
            tempstate.insert(trigger + 6, f"trigger1 = (((p2bodydist x = [{max(60, int(scaling_stats_dict.get('groundfront', 60) * 1.0))},{max(150, int(scaling_stats_dict.get('groundfront', 60) * 2.5))}]) && (enemynear, movetype != A && enemynear, movetype != H)) || (p2bodydist x = [{int(max(150, int(scaling_stats_dict.get('groundfront', 60) * 2.5)) * 0.8)}, {int(max(150, int(scaling_stats_dict.get('groundfront', 60) * 2.5)) * 0.9)}]) || (p2bodydist x = [{int(max(60, int(scaling_stats_dict.get('groundfront', 60) * 1.0)) * 0.9)}, {int(max(60, int(scaling_stats_dict.get('groundfront', 60) * 1.0)) * 1.1)}]) || (enemynear, movetype = A && (enemynear, vel x > 1) && p2bodydist x < {max(150, int(scaling_stats_dict.get('groundfront', 60) * 2.5))} && (enemynear, hitdefattr = SC, AA, AT, AP)))\n") #f"trigger1 = (((p2bodydist x >= 60 && p2bodydist x <= 150) && (enemynear, movetype != A && enemynear, movetype != H)) || (P2Bodydist x = [120,135]) || (P2Bodydist x = [54,68]) || (enemynear, movetype = A && (Enemynear, vel x > 1) && P2bodydist x < 140 && enemynear, hitdefattr = SC,ST,HT))\n")
            
            # --- Trigger 2: [OPTIMIZED] Air Chase & Intercept ---
            # 1. Chase Launcher (Vel Y check added) | 2. Punish Ground Whiff | 3. Definitive Air Intercept
            tempstate.insert(trigger + 7, f"trigger2 = (enemynear, movetype = H && enemynear, statetype = A && (enemynear, vel y < -1) && (p2bodydist x <= 120)) || (enemynear, movetype=A && enemynear, statetype!=A  && (p2bodydist x = [50,190]) && !(Enemynear,Ctrl||StateNo=21)) || (EnemyNear, StateType = A && (P2Dist Y = [-120, -20]) && (EnemyNear, Vel Y > -1))\n")
            
