def write_taunt(state, trigger, ai_var, aihelperID, stateno=0, cmd_statetype_reqs=None, inherited_triggers=None): #add ",analysis," in if needed if you want the safety check.
    """Generates triggers for taunts and other non-offensive moves."""
    
    # --- START: Definitive Safety Check ---
    # This is the most important fix. If a move has a hitbox (even if it's a helper),
    # it is NOT a "generic" move and should be handled by the main fight/combo logic.
    # This check prevents this function from processing standard attacks and causing spacing/duplication errors.
