    tempstate.insert(trigger + 7, f"triggerall = (random <= {attack_rate} * {get_ai_scale_string(stateno, ai_var)}) || (random<power/100) || (random<power/42) || (enemy,ctrl=0 && random<power/42)\n")
    tempstate.insert(trigger + 8, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    tempstate.insert(trigger + 9, f"triggerall = AnimTime = 0\n")
