def write_special_triggers_persistent(state, trigger, attacktype, stateattr, ai_var, aihelperID, stateno=0, cmd_statetype_reqs=None, inherited_triggers=None):
    """Generates triggers for moves identified by non-HitDef controllers."""
    # --- [GUARANTEED FIX] Only process known special move types ---
    known_special_types = {"command_throw", "target_state", "heal", "buff", "teleport", "counter"}
    # Enable or Disable These as you please, delete if problematic, but be aware that without these checks, the function may attempt to process moves it shouldn't, leading to errors or unintended behavior.
    if attacktype not in known_special_types:
        # This is not a special move this function can handle (e.g., a taunt).
        return None
    # --- [END GUARANTEED FIX] ---
    # --- [FIX] Safety Check for "unknown" attack types ---
    if not stateattr or attacktype == "unknown":
         return None
    # --- [END FIX] ---
