def write_wakeup_pressure_persistent(state, trigger, py, reachtime, hitdef, ai_var, aihelperID, power=0, stateno=0):
    """Generates triggers for applying pressure to a downed opponent (okizeme)."""
    tempstate = state[:]
    base_rate = 550
    speed_penalty = (reachtime or 0) * 6
    mixup_bonus = 100 if hitdef and 'L' in hitdef.upper() else 0
    rate_before_scaling = base_rate - speed_penalty + mixup_bonus
    scaled_rate = rate_before_scaling * (1 - ((power or 0) / 1500))
    attack_rate = max(int(scaled_rate), 100)
