def write_combo_breaker(state, trigger, analysis, ai_var, aihelperID, cmd_statetype_reqs):
    """
    (V4 - Definitive & Robust) Generates universal AI triggers for combo
    breakers/bursts, now inheriting StateType/MoveType requirements from the CMD.
    """
    global enable_burst_cooldown
    global CTRL_STRIP_MODE
    tempstate = state[:]
    stateno = analysis['stateno']
    power_cost = analysis['stateattr'][2] or 1000
    
    # Matches 'ctrl' or 'ctrl = 1' only. 
    # It will NOT match if followed by =, !=, <, or > (protecting ctrl=0, etc.)
    # It will NOT capture surrounding parentheses.
    p_ctrl_fix = re.compile(r'(?<!,)(?<!,\s)(?<!,\s\s)(?<!\w)ctrl(?:\s*=\s*1)?(?!\s*[!><=])(?!\w)', re.I) #p_ctrl_fix = re.compile(r'(?<!\w)ctrl(?:\s*=\s*1)?(?!\s*[!><=])(?!\w)', re.I)
    
    # Matches only the word 'ctrl' or 'ctrl=1', ignoring brackets entirely
    #p_ctrl_fix = re.compile(r'\bctrl\s*(=\s*1)?\b', re.I)

    # 2. THE STRIPPER: Clean the existing triggers BEFORE adding new ones
    if CTRL_STRIP_MODE > 0:
        cleaned_state = []
        for line in tempstate:
            # If a line contains 'ctrl', we change it to '1' so the gate stays open
            if p_ctrl_fix.search(line):
                line = p_ctrl_fix.sub('1', line)
            cleaned_state.append(line)
        tempstate = cleaned_state

    tempstate.insert(trigger, "; AI: Combo Breaker / Burst Logic (Universal)\n")
    
    # --- START: True Trigger Inheritance from CMD analysis ---
    # This new block inherits ALL relevant triggers from the original CMD state,
    # including var() checks, to ensure the AI respects the character's design.
    insert_index = trigger + 1
    
    #disable, uncomment or delete if problematic start
    # The 'analysis' dictionary already contains a pre-cleaned list of inheritable triggers.
    #inherited_triggers = analysis.get('original_triggers', [])

    #if inherited_triggers:
     #   tempstate.insert(insert_index, "; --- Inherited Triggers from CMD ---\n"); insert_index += 1
     #   for trigger_line in inherited_triggers:
     #       # Convert all inherited triggers to 'triggerall' to make them mandatory conditions.
     #       cleaned_line = re.sub(r'\btrigger\d*\b', 'triggerall', trigger_line.strip(), 1)
     #       tempstate.insert(insert_index, cleaned_line + "\n"); insert_index += 1
    #disable, uncomment or delete if problematic end
    # --- END: True Trigger Inheritance ---

    # --- Core Triggers (ALL must be true) ---
    tempstate.insert(insert_index, f"triggerall = {ai_var} > 0 && roundstate = 2\n"); insert_index += 1
    #tempstate.insert(insert_index, f"triggerall = power >= {power_cost}\n"); insert_index += 1
    tempstate.insert(insert_index, "triggerall = (stateno=[5000,5210]) || (stateno = [5020,5071]) || ((stateno = 154 || stateno = 155 || MoveGuarded) && power >= 2000) || (statetype = L) || (movetype = H) ; Universal check for being in hitstun\n"); insert_index += 1
    tempstate.insert(insert_index, "triggerall = stateno != [120,159]\n"); insert_index += 1
    #tempstate.insert(insert_index, f"triggerall = p2bodydist x < 100\n"); insert_index += 1
    tempstate.insert(insert_index, py) #py + pyh); insert_index += 1

    # --- Optional Cooldown ---
    if enable_burst_cooldown:
        tempstate.insert(insert_index, f"triggerall = helper({aihelperID}),var(35) <= 0 ; Check for cooldown\n"); insert_index += 1
        
    # --- Situational Triggers (ANY can be true) ---
    
    #Alternate, a bit more stable but hardly noticeable as it doesn't always work
    tempstate.insert(insert_index, f"; -- Situational Triggers --\n")
    tempstate.insert(insert_index, f"trigger1 = (gethitvar(damage) > 80 || hitcount > 2 || hitcount > 4)\n"); insert_index += 1
    tempstate.insert(insert_index, f"trigger1 = random < 250 ; Increased base chance in this mode\n"); insert_index += 1
    tempstate.insert(insert_index, f"trigger1 = random < power / 42\n"); insert_index += 1
    tempstate.insert(insert_index, f"trigger2 = (life < 350 && hitcount > 2) || (enemynear, movetype = A && enemynear,ctrl = 0)\n"); insert_index += 1
    tempstate.insert(insert_index, f"trigger2 = random < power / 100\n"); insert_index += 1
        
    # --- Situational Triggers (ANY can be true) ---
    #tempstate.insert(insert_index, f"; Trigger 1: Use during a special mode (universal placeholder)\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger1 = helper({aihelperID}),var(36) = 1\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger1 = random < 250 ; Increased base chance in this mode\n"); insert_index += 1
    #tempstate.insert(insert_index, f"; Trigger 2: Standard burst based on combo damage and meter\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger2 = helper({aihelperID}),var(36) != 1\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger2 = (gethitvar(damage) > 80 || hitcount > 2) ;hitcount > 4)\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger2 = random < power / 42 ; Chance increases with more power\n"); insert_index += 1
    #tempstate.insert(insert_index, f"; Trigger 3: Desperation or punish burst\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger3 = helper({aihelperID}),var(36) != 1\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger3 = (life < 350 && hitcount > 2) || (enemynear, movetype = A && enemynear,ctrl = 0)\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger3 = random < power / 100\n"); insert_index += 1
    #tempstate.insert(insert_index, f"; Trigger Extra: Use when in a specific state\n"); insert_index += 1
    #tempstate.insert(insert_index, f";trigger1 = stateno=[5000,5210]\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger1 = var(54) <= 0 && random<25\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger1 = helper(12345678),var(1)\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger3 = !helper(12345678),var(1)\n"); insert_index += 1
    #tempstate.insert(insert_index, f"trigger1 = ctrl\n"); insert_index += 1
    #tempstate.insert(insert_index, f";trigger2 = ctrl\n"); insert_index += 1
    #tempstate.insert(insert_index, f";trigger3 = ctrl\n"); insert_index += 1
    
    # --- FINAL CORRECTION: Filter out incompatible triggers ---
    # A combo breaker MUST work when ctrl=0. Any inherited "triggerall = ctrl"
    # would make it impossible to activate. This filter removes that specific line
    # while preserving all other inherited logic.

    tempstate = [line for line in tempstate if not re.search(r'^\s*triggerall\s*=\s*ctrl\s*$', line.strip(), re.I)]

    return tempstate

def is_reactionary_move(state_content):
    """
    Checks if a state contains controllers that require the opponent 
    to be attacking (ReversalDef) or the player to be hit (HitOverride).
    (V4 OMNI-AWARE) Performs a deep-content analysis to identify reactionary 'DNA'.
    Detects explicit SCTRLs, conditional triggers (P2MoveType), and internal 
    MUGEN logic that defines defensive or reactive behavior.
    """
    # Look for the ReversalDef controller (The standard for MUGEN counters)
    if re.search(r'type\s*=\s*ReversalDef', state_content, re.IGNORECASE):
        return True
    
    # Look for HitOverride (Used for "armored" counters or transformation counters)
    if re.search(r'type\s*=\s*HitOverride', state_content, re.IGNORECASE):
        return True

    sc_low = state_content.lower()

    # 1. EXPLICIT REACTIONARY SCTRLS (Hard-Locked Reaction)
    # ReversalDef (Standard Counter) or HitOverride (Armor/Damage-Reaction)
    if re.search(r'type\s*=\s*(reversaldef|hitoverride)', sc_low):
        return True
        
    # Heuristic: Check if the move is explicitly labeled as a counter in comments
    if re.search(r';.*(counter|reversal|reactionary)', state_content, re.IGNORECASE):
        return True

    # 2. CONTEXTUAL TRIGGER SCAN (Situational Reaction)
    # Does the state only trigger when the player is hit or the enemy is attacking?
    reaction_triggers = [
        r'movetype\s*=\s*h',             # Character is in hitstun (Breakers)
        r'gethitvar',                    # Reacting to damage/hit properties
        r'enemynear\s*,\s*movetype\s*=\s*a', # Opponent is currently attacking
        r'p2movetype\s*=\s*a',           # Opponent is currently attacking (Alt)
        r'inguarddist',                  # Reaction within guarding range
        r'nothitby\s*=\s*sca',           # Full invincibility usually paired with counters
        r'movereversed',                 # Countering a reversal
        r'numproj\s*>\s*0'               # Anti-projectile reaction
    ]
    if any(re.search(pat, sc_low) for pat in reaction_triggers):
        return True

    # 3. HEURISTIC SIGNATURES (Implicit Reaction)
    # Checks for "Stance" counters where MoveType is Idle but requires a trigger to attack.
    is_idle_stance = 'movetype = i' in sc_low and 'physics = s' in sc_low
    has_reactive_transition = 'p2movetype = a' in sc_low or 'p2stateno' in sc_low
    if is_idle_stance and has_reactive_transition:
        return True

    # 4. COMMENT METADATA
    if re.search(r';.*(counter|reversal|reactionary|breaker|alpha|parry)', sc_low):
        return True
      
    return False

def check_inheritance_reaction(parent_state, move_metadata):
    """
    If the parent state was a counter, the child (follow-up) 
    should likely inherit the 'reactionary' requirement.
    """
    if move_metadata.get(parent_state, {}).get('is_counter'):
        return True
    return False

