def writecounter3(state, trigger, py, reachtime, nothitby_attr, nothitby_end, ai_var, aihelperID, power=0):
    """Generates triggers for invincible (nothitby) startup moves (reversals)."""
    tempstate = state[:]
    invincible = 0
    power = power or 0
    reachtime = reachtime or 0
    nothitby_end = nothitby_end or 0
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})

    if nothitby_attr:
        attr = ''.join(nothitby_attr.upper().split(','))
        is_body_inv = 'S' in attr and 'C' in attr and 'A' in attr
        is_attack_inv = all(x in attr for x in ["NA", "SA", "HA", "NP", "SP", "HP", "NT", "ST", "HT"])
        is_common_inv = all(x in attr for x in ["AP", "AA", "AT"])
        if is_body_inv or is_attack_inv or (is_body_inv and is_common_inv):
            invincible = 1
            
    invincible=0
    attr=nothitby_attr.split(',')
    attr=list(map(str.upper,attr))
    if len(attr)== 1 and ('S' in attr[0].strip() and 'C' in attr[0].strip() and 'A' in attr[0].strip()) :
        invincible = 1
    if (attr[0]=="" or ('S' in attr[0].strip() and 'C' in attr[0].strip() and 'A' in attr[0].strip()))  and "AP" in attr and "AA" in attr and "AT" in attr:
        invincible = 1
    if (attr[0]=="" or ('S' in attr[0].strip() and 'C' in attr[0].strip() and 'A' in attr[0].strip())) and "NP" in attr and "NA" in attr and "NT" in attr and "SP" in attr and "SA" in attr and "ST" in attr and "HP" in attr and "HA" in attr and "HT" in attr:
        invincible = 1
        
    base_rate = 85
    invuln_window = nothitby_end - reachtime
    invuln_bonus = max(0, invuln_window * 20)
    rate_before_scaling = base_rate + invuln_bonus
    scaled_rate = rate_before_scaling * (1 - (power / 2200))
    attack_rate = max(int(scaled_rate), 40)
    tempstate.insert(trigger, py) #py + pyh)
    tempstate.insert(trigger, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    tempstate.insert(trigger + 1, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    tempstate.insert(trigger + 2, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    tempstate.insert(trigger + 1, f"trigger1 = helper({aihelperID}),var(17) >= 1 && helper({aihelperID}),var(17) <= {reachtime + 2} && p2dist x < 80\n")
    tempstate.insert(trigger + 2, f"trigger2 = (enemynear,time >= (70-9* {get_ai_scale_string(stateno, ai_var)}) && (random <= {attack_rate} * {get_ai_scale_string(stateno, ai_var)})) || ({ai_var} >= 8 && (!ctrl || enemynear,hitdefattr=sca,at))\n")
        # If this invincible move is a super, add a high-priority trigger to use it as a reversal
    if super_flag == 1 and power > 0:
        tempstate.insert(trigger + 3, f"trigger4 = power >= {power} && enemynear, movetype = A && p2dist x < 60\n")
        tempstate.insert(trigger + 4, f"triggerall = random <= 800* {get_ai_scale_string(stateno, ai_var)}\n")
    tempstate.insert(trigger + 5, f"trigger3 = {ai_var} >= 8 && helper({aihelperID}),var(11) = 3 && p2dist x < 50 && enemynear, movetype != A\n")
    if invincible == 1 and nothitby_end >= reachtime:
        tempstate.insert(trigger + 6, f"triggerall = enemynear, movetype = A && enemynear,animtime < -{reachtime}\n")
    elif nothitby_attr:
        tempstate.insert(trigger + 7, f"triggerall = enemynear, movetype = A && enemynear,hitdefattr = {nothitby_attr} && enemynear,animtime < -{reachtime}\n") 
    if (nothitby_end>=reachtime or nothitby_end == -1) and invincible == 1:
        tempstate.insert(trigger + 8,f"triggerall = p2movetype = A && enemynear,animtime < -{reachtime}\n")
        tempstate.insert(trigger + 9,f"triggerall = enemynear,time >= 70-9*{ai_var} && random <= 75*{ai_var} || {ai_var} >= 8 && (!ctrl || enemynear,hitdefattr=sca,at)\n")   
    if (nothitby_end<reachtime and nothitby_end != -1) or invincible != 1:
        tempstate.insert(trigger + 10,f"triggerall = p2movetype = A && enemynear,hitdefattr={nothitby_attr} && enemynear,animtime < -{reachtime}\n")
        tempstate.insert(trigger + 11,f"triggerall = enemynear,time >= 70-9*{ai_var} && random <= 75*{ai_var} || {ai_var} >= 8 && (!ctrl || enemynear,hitdefattr=sca,at)\n")
    return tempstate

