    #for req in cmd_statetype_reqs['movetype']['!=']:
    #    tempstate.insert(insert_index, f"triggerall = movetype != {req} ; From CMD (Spam Fix)\n"); insert_index += 1
        
        # --- START OF Y-AXIS DETECTOR ADDITION ---
    #
    # --- METHOD 1: Direct Coordinate Detection ---
    # This creates a precise vertical engagement box, just like the x-axis one.
    # The 'py' and 'pyh' variables are already calculated by the script.
    # This makes the AI check for both horizontal AND vertical range simultaneously.
    #if py:
    #    tempstate.insert(trigger + 4, f"{py.strip()}\n") # Add the calculated y-trigger

    # --- METHOD 2: Helper-Based Situational Logic (Parallel) ---
    # This adds a secondary, smarter check using our new vertical analysis.
    # The AI will now have multiple reasons to perform the same attack.
    vertical_props = AI_VERTICAL_MAP.get(stateno, {})
    insert_index = trigger + 5

    if vertical_props.get('is_ground_sweep'):
        tempstate.insert(insert_index, "; AI: Use as a low sweep (Helper Logic)\n")
        # Trigger if the opponent is on the ground.
        tempstate.insert(insert_index + 1, f"trigger2 = helper({aihelperID}),var(45) = 0\n")
    elif vertical_props.get('is_divekick') and statetype == 'A':
        tempstate.insert(insert_index, "; AI: Use as a Divekick (Helper Logic)\n")
        # Trigger if we are in the air and above the opponent, but not too close (spacing)
        tempstate.insert(insert_index + 1, f"trigger2 = p2dist x > 40 && p2dist y > 0\n")
    elif vertical_props.get('is_jump_in'):
        tempstate.insert(insert_index, "; AI: Use as a jump-in attack (Helper Logic)\n")
        # Trigger if we are above the opponent and they are on the ground or in low air.
        tempstate.insert(insert_index + 1, f"trigger2 = p2dist y < -40 && helper({aihelperID}),var(45) <= 1\n")
