    tempstate.insert(insert_index + 2, f"; AI: Whiff Punish (Helper Logic)\n")
    tempstate.insert(insert_index + 3, f"trigger3 = enemynear, movetype = A && movetype != H\n") # Opponent is attacking and we are not being hit
    tempstate.insert(insert_index + 4, f"trigger3 = random < 850 ; High probability to punish\n")

