    tempstate.insert(insert_index + 5, f"; AI: Corner Pressure (Helper Logic)\n")
    tempstate.insert(insert_index + 6, f"trigger4 = helper({aihelperID}),var(49) = 1\n") # We have stage advantage
    tempstate.insert(insert_index + 7, f"trigger4 = helper({aihelperID}),var(47) <= 1\n") # Opponent is in point-blank or footsie range

