    # 1. Base Velocity (X and Y)
    # We default to 0.0 because if no velocity is defined, the character is static.
    velx = float(stateattr[11]) if stateattr[11] is not None else 0.0
    vely = float(stateattr[13]) if stateattr[13] is not None else 0.0

