    if velx > 0: # Check if the move itself moves forward
        tempstate.insert(insert_index + 12, f"; AI: Corner Escape Attempt (Helper Logic)\n")
        tempstate.insert(insert_index + 13, f"trigger6 = helper({aihelperID}),var(49) = 2\n") # We are cornered
        tempstate.insert(insert_index + 14, f"trigger6 = enemynear, movetype != A\n") # Don't do it if they are already attacking
    # --- END OF X-AXIS DETECTOR ADDITION (PARALLEL TRIGGERS) ---
    #Disable or delete if problematic end
            
    if '-B' in hitdef or 'T' in hitdef.upper():
        tempstate.insert(trigger + 4, "triggerall = enemynear, movetype != H\n")
    else:
        tempstate.insert(trigger + 4, "triggerall = enemynear, movetype != H || EnemyNear, Stateno = [120,159]\n")
    tempstate.insert(trigger + 4, f"triggerall = (enemynear, statetype != L && movetype != H && ctrl) || (!inguarddist && !helper({aihelperID}),inguarddist && enemynear, statetype != L && movetype != H && ctrl) || (enemynear, statetype != L) ;!inguarddist && !helper({aihelperID}),inguarddist && enemynear, statetype != L && movetype != H && ctrl ;triggerall = !inguarddist && !helper({aihelperID}),inguarddist && enemynear, statetype != L\n")
    #tempstate.insert(trigger + 5, f"triggerall = enemynear, statetype != L ; REMOVED INGUARDDIST FOR AGGRESSION\n")
    #tempstate.insert(trigger + 6, f"triggerall = helper({aihelperID}),var(26) <= 0 ; Don't attack if opponent is blocking our string\n") #Enable if you wish it affects the AI's Behavior in an unpredictable way otherwise disable it or comment it out with "#"
    #tempstate.insert(trigger + 6, f"triggerall = power <= 1000 && helper({aihelperID}),var(28) <= 0 || power <= 2000 && helper({aihelperID}),var(28) <= 1 || power >= 3000\n")
    #tempstate.insert(trigger + 7, f"triggerall = AnimTime = 0\n")
    
    # =================================================================
    # --- START: HYBRID AI DECISION ENGINE INJECTION ---
    # This is where your new logic is correctly and powerfully integrated.
    # =================================================================
    
    # AGGRESSION FIX: Changed 800 to 3000 and cap to 500 to stop pausing
    attack_rate = max(min(int(3000 / (reachtime + 1 + totaltime + 10 * ('S' in hitdef or 'H' in hitdef)) + 15 * (statetype == 'A' or 'T' in hitdef)), 500), 20)
    #attack_rate = max(min(int(800 / (reachtime + 1 + totaltime + 10 * ('S' in hitdef or 'H' in hitdef)) + 15 * (statetype == 'A' or 'T' in hitdef)), 85), 1)
    #attack_rate = max(min(int(950 / (reachtime + 1 + totaltime + 10 * ('S' in hitdef or 'H' in hitdef)) + 15 * (statetype == 'A' or 'T' in hitdef)), 95), 1) # Increased base rate from 800 to 950
    if 0 < power < 1000:
        attack_rate = max(int(attack_rate * (1 - power / 1000)), 1)

    # --- V13 ENHANCEMENT: Corner and Timer Awareness ---
    # Give a significant boost to the attack rate if the AI has the opponent cornered.
    tempstate.insert(insert_index, f";triggerall = random <= {attack_rate} * ifelse(enemynear,backedgedist < 40, 1.5, 1) * {get_ai_scale_string(stateno, ai_var)}\n"); insert_index += 1
