def write_chain_combo_trigger(state, trigger, pyh, followup_stateno, followup_to_starters_map, ai_var, aihelperID):
    """
    Generates a high-priority trigger for a move that can be used as a chain combo followup.
    """
    # Check if the current move (followup_stateno) is a known followup
    if followup_stateno not in followup_to_starters_map:
        return None # Not a chain followup, do nothing

    starters = followup_to_starters_map[followup_stateno]
    if not starters:
        return None
    
    stateattr = analysis.get('stateattr', [])
        
    # 1. Get StateType (String: 'S', 'C', 'A') safely
    # We default to 'S' (Standing) if missing, as this is a standing catch function
    statetype = stateattr[1] if stateattr and len(stateattr) > 1 and isinstance(stateattr[1], str) else 'S'

    # DETERMINISTIC: Attack if within valid range (Ground: 60px, Air: 40px)
    safe_dist = 60 if statetype != 'A' else 40

    tempstate = state[:]
    # We are inserting a new, high-priority set of triggers.
    # We can use the original trigger point.
    tempstate.insert(trigger, "; AI: Chain Combo Logic\n" + pyh)
    tempstate.insert(trigger + 1, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    # The AI should only do this if the player character is currently in one of the starter move states.
    tempstate.insert(trigger + 1, f"triggerall = stateno = [{','.join(map(str, starters))}]\n")
    # And that starter move must have successfully hit.
    tempstate.insert(trigger + 2, "triggerall = movehit = 1\n")
    # And the opponent must be in hitstun.
    tempstate.insert(trigger + 3, "triggerall = enemynear, movetype = H\n")
    # Make the AI very likely to perform the chain.
    tempstate.insert(trigger + 4, f"triggerall = (random <= 950 * {get_ai_scale_string(stateno, ai_var)})\n")
    tempstate.insert(trigger + 5, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    # Ignore the other triggers for this specific case by making this trigger1.
    # Find where the original trigger1 was and rename it to trigger2.
    for i in range(len(tempstate)):
        if tempstate[i].strip().lower().startswith("trigger1"):
            tempstate[i] = tempstate[i].replace("trigger1", "trigger2", 1)

    # Now, find the 'value' line and make this the new trigger1
    for i in range(len(tempstate)):
        if "value =" in tempstate[i].lower():
            tempstate.insert(i, "trigger1 = 1\n")
            break

    return tempstate
# <<<--- END OF ADDITION --- >>>

