def generate_fvar_injection_triggers(path, ai_var, fvar_index=23):
    """
    Generates the list of trigger strings for a specific fvar-based combo path,
    ready to be injected into a starter move's state block.
    """
    if len(path) < 2: return []

    # Build the nested 'cond' string for the value line
    value_str = ""
    for i in range(1, len(path)):
        stateno = path[i]['stateno']
        if i == 1:
            value_str = f"{ai_cond}(fvar({fvar_index}) < {i}, {stateno}"
        else:
            value_str += f", {ai_cond}(fvar({fvar_index}) < {i}, {stateno}"
    value_str += f", {path[-1]['stateno']})" * (len(path) - 1)

    # Assemble the triggers for a new, high-priority ChangeState controller
    injection_triggers = [
        "\n; --- INJECTED FVAR COMBO LOGIC ---\n",
        "[State -3, AI FVar Chain Combo]\n",
        "type = ChangeState\n",
        "triggerall = movecontact\n",
        f"triggerall = fvar({fvar_index}) < {len(path) - 1}\n",
        f"trigger1 = roundstate = 2 && {ai_var} > 0 && random < ({ai_var} * 100)\n",
        ";triggerall = EnemyNear, StateType != L\n",
        f"value = {value_str}\n",
    ]
    return injection_triggers


def get_hittime_from_hitdef(hitdef_string):
    """
    Parses a HitDef string to find the ground.hittime or air.hittime value.
    This is a simplified parser specifically for the heuristic combo engine.
    """
    if not hitdef_string or not isinstance(hitdef_string, str):
        return 0

    # Prefer ground.hittime, as it's the most common for combo starters.
    ground_match = re.search(r'ground\.hittime\s*=\s*(\d+)', hitdef_string, re.I)
    if ground_match:
        return int(ground_match.group(1))

    # Fallback to air.hittime if ground.hittime is not present.
    air_match = re.search(r'air\.hittime\s*=\s*(\d+)', hitdef_string, re.I)
    if air_match:
        return int(air_match.group(1))

    # Return a default safe value if no hittime is specified
    return 12 # A safe default for light/medium attacks

