def generate_air_catch_logic(all_analyses, ai_var, ai_var_re, aihelperID, scaling_stats):
    """
    (V10.1 - FIXED & ISOLATED) Fixes the 'Ghost Trigger' bug by recalculating 
    spatial triggers locally for each move using the centralized authority function.
    """
    print("\n--- [V10.1 REPAIRED] Running Advanced Air Catch AI Generator ---")

    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    move_analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})

    air_catch_blocks = []
    
    aerial_attack_moves = [
        move for move in all_analyses 
        if move and move.get('stateattr') and len(move['stateattr']) > 1 and move['stateattr'][1] == 'A' and move['reach'][2] is not None
    ]

    if not aerial_attack_moves:
        return []

    print(f"    -> Found {len(aerial_attack_moves)} aerial attack moves to generate logic for.")

    # Shared Tracking Logic (State -2)
    air_catch_blocks.append([
        "\n;==================================================\n",
        ";--- ADVANCED AIR CATCH SYSTEM (Generated) ---\n",
        ";==================================================\n",
        "; --- Multi-Enemy ID Tracking for Air Catches --- \n",
        "[State -2, AirCatch P2 ID Track]\n", "type = VarSet\n", "trigger1 = NumEnemy = 1\n", f"var(52) = Enemy,ID\n", "ignorehitpause=1\n",
        "[State -2, AirCatch P3 ID Track]\n", "type = VarSet\n", "trigger1 = NumEnemy >= 2\n", f"var(53) = Enemy(1),ID\n", "ignorehitpause=1\n",
        "[State -2, AirCatch P4 ID Track]\n", "type = VarSet\n", "trigger1 = NumEnemy >= 3\n", f"var(54) = Enemy(2),ID\n", "ignorehitpause=1\n",
    ])
    
    JUGGLE_STATE_PLACEHOLDER = "[6565600,6565611]"

    for move_analysis in aerial_attack_moves:
        original_state_block = move_analysis.get('original_cmd_block')
        if not original_state_block: continue

        stateno_to_use = move_analysis['stateno']
        
        # 1. Clean the block
        tempstate = clearcmd(original_state_block[:], ai_var_re)
        
        # 2. Rename Header
        tempstate[0] = f"[State -3, AI Air Catch Logic -> {stateno_to_use}]\n"

        # 3. Find Insertion Point
        trigger_idx = next((i for i, line in enumerate(tempstate) if 'trigger1' in line.lower()), len(tempstate) - 1)
        
        # 4. RECALCULATE SPATIAL TRIGGERS LOCALLY (The Fix)
        # Extract specific physics for THIS move
        stateattr = move_analysis['stateattr']
        # 1. Base Velocity (X and Y)
        # We default to 0.0 because if no velocity is defined, the character is static.
        velx = float(stateattr[11]) if stateattr[11] is not None else 0.0
        vely = float(stateattr[13]) if stateattr[13] is not None else 0.0

        # 2. Velocity Application Timing (velstart)
        # Most MUGEN moves apply velocity on tick 0. 
        # We only override this if findattr explicitly found a VelSet trigger at a different time.
        velstart = 0
        if isinstance(stateattr[12], (list, tuple)) and len(stateattr[12]) > 4:
            if stateattr[12][4] is not None:
                velstart = int(stateattr[12][4])
        
        # Call the authority function
        # Note: Unpack the scaling_stats dictionary
        local_py, local_pyh = calculate_py_triggers(
            tempstate, trigger_idx, velx, velstart, vely, 
            move_analysis['attacktype'], move_analysis, move_analysis['reach'], stateattr,
            scaling_stats['localcoord_scale'], scaling_stats['xscale'], scaling_stats['yscale'],
            scaling_stats['groundfront'], scaling_stats['groundback'], 
            scaling_stats['airfront'], scaling_stats['airback'], 
            scaling_stats['midposy'], aihelperID, ai_var
        )
        
        # Reach/Time extraction
        reach = move_analysis.get('reach', [])
        
        # FIX: totaltime must be an integer from reach[1], NOT the stateattr string
        totaltime = reach[1] if reach and len(reach) > 1 and isinstance(reach[1], int) else 20
        reachtime = reach[0] if reach and len(reach) > 0 and isinstance(reach[0], int) else 0
        
        # Calc active frames safely
        active_frames = max(totaltime - reachtime, 1)        
        
        #statetype = move_analysis['stateattr'][1]

        stateattr = move_analysis.get('stateattr', [])
        
        # 1. Get StateType (String: 'S', 'C', 'A') safely
        # We default to 'A' (Air) if missing, as this is an air catch function
        statetype = stateattr[1] if stateattr and len(stateattr) > 1 and isinstance(stateattr[1], str) else 'A'

        # DETERMINISTIC: Attack if within valid range (Ground: 60px, Air: 40px)
        safe_dist = 60 if statetype != 'A' else 40


        # 5. Insert Logic
        idx = trigger_idx
        tempstate.insert(idx, "; --- AI-Specific Triggers (Air Catch) ---\n"); idx += 1
        tempstate.insert(idx, f"triggerall = {ai_var} > 0 && RoundState = 2\n"); idx += 1
        tempstate.insert(idx, f"triggerall = (ctrl) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0) ;Ctrl\n"); idx += 1
        tempstate.insert(idx, "triggerall = MoveType != H\n"); idx += 1
        
        # Use the LOCALLY calculated strings
        tempstate.insert(idx, local_py); idx += 1 #local_pyh + local_py) ; idx += 1
        
        # Insert the Resolved Deterministic Trigger
        # This string uses the Python variables calculated above (calc_dist_x, safe_dist)
        # instead of literal bracket strings, ensuring valid MUGEN code.
        #trigger_line = (
        #    f"triggerall = (random < 850) || (random < 850 * {get_ai_scale_string(stateno, ai_var)})"
        #
        #
        #)

        tempstate.insert(idx, f"triggerall = (random < 850) || (random < 850 * {get_ai_scale_string(stateno, ai_var)}) ;|| (P2BodyDist X <= {totaltime*3 + 20})\n"); idx += 1

        #tempstate.insert(idx, trigger_line); idx += 1
        
        # Target Selection Logic (3-Enemy Support)
        tempstate.insert(idx, "\n; --- Target Selection Logic ---\n"); idx += 1
        tempstate.insert(idx, "; Trigger 1: Catch Enemy 1\n"); idx += 1
        tempstate.insert(idx, "trigger1 = playeridexist(var(52)) && playerid(var(52)), alive\n"); idx += 1
        tempstate.insert(idx, f"trigger1 = (playerid(var(52)), stateno != {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, "trigger1 = (playerid(var(52)), pos y < -10)\n\n"); idx += 1

        tempstate.insert(idx, "; Trigger 2: Catch Enemy 2\n"); idx += 1
        tempstate.insert(idx, "trigger2 = playeridexist(var(53)) && playerid(var(53)), alive\n"); idx += 1
        tempstate.insert(idx, f"trigger2 = (!playeridexist(var(52))) || (!playerid(var(52)), alive) || (playerid(var(52)), stateno = {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, f"trigger2 = (playerid(var(53)), stateno != {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, "trigger2 = (playerid(var(53)), pos y < -10)\n\n"); idx += 1

        tempstate.insert(idx, "; Trigger 3: Catch Enemy 3\n"); idx += 1
        tempstate.insert(idx, "trigger3 = playeridexist(var(54)) && playerid(var(54)), alive\n"); idx += 1
        tempstate.insert(idx, f"trigger3 = (!playeridexist(var(52))) || (!playerid(var(52)), alive) || (playerid(var(52)), stateno = {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, f"trigger3 = (!playeridexist(var(53))) || (!playerid(var(53)), alive) || (playerid(var(53)), stateno = {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, f"trigger3 = (playerid(var(54)), stateno != {JUGGLE_STATE_PLACEHOLDER})\n"); idx += 1
        tempstate.insert(idx, "trigger3 = playerid(var(54)), pos y < -10\n\n"); idx += 1
        tempstate.insert(idx, ";triggerall = EnemyNear, StateType != L\n")
        
        air_catch_blocks.append(tempstate)

    return air_catch_blocks

