    tempstate.insert(trigger + 2, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")

