def write_new_ai_style_triggers(state, analysis, ai_var, aihelperID, py, pyh):
    """
    (ENHANCED & PRESERVING) Generates complex, situational [State -3] triggers
    inspired by Ragna's AI logic. This version ADDS to the existing state block,
    preserving all original triggers and incorporating advanced contextual checks.
    """
    if not analysis or not analysis.get('original_cmd_block'):
        return None

    # --- Start with a clean copy of the original state block, as instructed ---
    # This preserves all original triggers, especially `triggerall` conditions.
    tempstate = state[:]

    # --- Extract core information from the analysis for decision-making ---
    stateno = analysis['stateno']
    original_name = get_cmd_state_name(analysis['original_cmd_block'])
    power_cost = analysis['stateattr'][2] or 0
    is_super = analysis['is_super']
    damage = analysis['stateattr'][20] or 0
    is_throw = analysis['is_throw']
    reach_time = analysis['reach'][0] or 10

    # --- Modify the state header for clarity in the final AI file ---
    # This is the only line that is overwritten, as it's metadata.
    tempstate[0] = f"[State -3, AI Logic (New Style) for {original_name}]\n"

    idx = trigger

    # --- Inject Universal AI Triggers ---
    # These are mandatory conditions for the AI to even consider this move.
    tempstate.insert(idx, f"\n; --- Injected AI Universal Triggers ---\n"); idx += 1
    tempstate.insert(idx, f"triggerall = {ai_var} > 0\n"); idx += 1
    tempstate.insert(idx, "triggerall = RoundState = 2 && Alive\n"); idx += 1
    tempstate.insert(idx, py); idx += 1 #py + pyh); idx += 1
    tempstate.insert(idx, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n"); idx += 1
    tempstate.insert(idx, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n"); idx += 1
    tempstate.insert(idx, f"triggerall = helper({aihelperIDCustom}),var(18)-((ceil(helper({aihelperIDCustom}),var(18)/1000)-ifelse(helper({aihelperIDCustom}),var(18)-(ceil(helper({aihelperIDCustom}),var(18)/1000)*1000)<0,1,0))*1000)<=0 && EnemyNear, Stateno !=[5100,5150]\n"); idx += 1
    tempstate.insert(idx, f"triggerall = (inguarddist=0 && helper({aihelperIDCustom}),inguarddist=0 && (numpartner||enemynear, movetype !=A))||var(54)>=100000\n"); idx += 1
    tempstate.insert(idx, f"triggerall = helper({aihelperIDCustom}),var(15)-((ceil(helper({aihelperIDCustom}),var(15)/100)-ifelse(helper({aihelperIDCustom}),var(15)-(ceil(helper({aihelperIDCustom}),var(15)/100)*100)<0,1,0))*100)<=0\n"); idx += 1
    tempstate.insert(idx, f"triggerall = Enemynear,Statetype != L\n"); idx += 1 # Ensure opponent is reachable/contactable and isn't lying down

    # --- Intent-Based Logic Generation (Fused with Ragna's CMD logic) ---
    # This section now generates multiple, parallel triggers (trigger1, trigger2, etc.)
    # to give the AI more reasons to act, making it more dynamic.

    # Intent 1: Finisher (Astral Heat / Black Onslaught Style)
    if is_super and damage > 250:
        tempstate.insert(idx, "\n; --- Finisher Intent ---\n"); idx += 1
        #tempstate.insert(idx, f"triggerall = power >= {power_cost}\n"); idx += 1
        #tempstate.insert(idx, py); idx += 1 #py + pyh); idx += 1
        # Trigger for punishing a whiffed super or highly vulnerable state
        tempstate.insert(idx, f"trigger1 = enemynear, movetype=A && EnemyNear, Stateno>2000 && p2life <= lifemax*0.4\n"); idx += 1
        # Trigger for finishing a combo
        tempstate.insert(idx, "trigger2 = movecontact && enemynear, movetype=H && p2life <= lifemax/3\n"); idx += 1
        # Trigger based on AI helper's strategic decision
        tempstate.insert(idx, f"trigger3 = helper({aihelperIDCustom}),var(35)=18\n"); idx += 1
        return tempstate

    # Intent 2: Punisher / Combo Ender (Carnage Scissors Style)
    if is_super and power_cost <= 2000:
        tempstate.insert(idx, "\n; --- Punisher / Super Combo Ender Intent ---\n"); idx += 1
        #tempstate.insert(idx, f"triggerall = power >= {power_cost}\n"); idx += 1
        #.insert(idx, pyh) #pyh + py); idx += 1 # Use pyh for combo accuracy
        # Trigger to end a combo with a super
        tempstate.insert(idx, "trigger1 = movecontact && enemynear, movetype=H\n"); idx += 1
        # Trigger to punish a whiffed special move
        tempstate.insert(idx, f"trigger2 = !enemynear,ctrl && enemynear, movetype=A && animtime < -{reach_time + 5}\n"); idx += 1
        # Trigger based on AI helper's strategic decision
        tempstate.insert(idx, f"trigger3 = helper({aihelperIDCustom}),var(35)=[16,17]\n"); idx += 1
        return tempstate

    # Intent 3: General Attack (Footsies, Pokes, Combos)
    if not is_super and not is_throw:
        tempstate.insert(idx, "\n; --- General Attack Intent (Footsies/Pokes) ---\n"); idx += 1
        tempstate.insert(idx, "triggerall = enemynear, movetype != H || EnemyNear, Stateno = [120,159]\n"); idx += 1
        #tempstate.insert(idx, py); idx += 1 #py + pyh); idx += 1
        # Trigger for basic footsies, based on AI helper's decision
        tempstate.insert(idx, f"trigger1 = helper({aihelperIDCustom}),var(35) = [23,25]\n"); idx += 1
        # Trigger for whiff punishing normal attacks
        tempstate.insert(idx, f"trigger2 = !enemynear,ctrl && enemynear, movetype=A && animtime < -{reach_time}\n"); idx += 1
        # Trigger for continuing a combo from a normal hit
        tempstate.insert(idx, "trigger3 = movecontact && enemynear, movetype=H\n"); idx += 1
        return tempstate
        
    # Intent 4: Throw (Incorporate Ragna's CMD logic for grabs)
    if is_throw:
        tempstate.insert(idx, "\n; --- Throw Intent ---\n"); idx += 1
        tempstate.insert(idx, "triggerall = enemynear, movetype != H\n"); idx += 1
        #tempstate.insert(idx, py); idx += 1 #py + pyh); idx += 1
        # Trigger for punishing a blocked attack at close range
        tempstate.insert(idx, "trigger1 =EnemyNear, Stateno >= 150 && EnemyNear, Stateno <= 155 && p2dist x < 40\n"); idx += 1
        # Trigger for a wakeup mixup
        tempstate.insert(idx, "trigger2 = enemynear, statetype = L && p2dist x < 40\n"); idx += 1
        # General close-range throw attempt
        tempstate.insert(idx, "trigger3 = enemynear, movetype = I && p2dist x < 30\n"); idx += 1
        return tempstate

    # If no specific intent is met, do not generate a state for this move.
    return None

# NOTE: The function definition below has been CHANGED to accept cmd_statetype_reqs.
def generate_custom_style_ai_states(state_block_from_cmd, analysis, ai_var, ai_var_re, movement_states, cmd_statetype_reqs):
    """
    (V13 - DEFINITIVE & UNABRIDGED)
    Correctly generates [State -3] blocks by modifying a clean copy of the original
    command state, ensuring all original triggers (like transformation vars) are respected.
    """
    #Delete below line if needed or if problematic
    # --- [GUARANTEED FIX] Definitive check for ANY offensive action ---
    is_offensive = (analysis and 
                    (analysis.get('reach', [None, None, None])[2] is not None or 
                     analysis.get('attacktype') in ["command_throw", "target_state", "counter", "reversal", "proj", "helper"]))
    if not is_offensive:
        # This is a non-offensive move (like a taunt). Do not generate attack logic for it.
        return []
    
    # --- GUARANTEED MOVEMENT & OFFENSE PERMIT (OMNI-ROBUST V3 - PRIORITY MODE) ---
    stateno_check = analysis.get('stateno')
    attacktype_str = str(analysis.get('attacktype', 'unknown')).lower()
    
    # 1. ESTABLISH PERMIT FLAGS (The Whitelist)
    
    # A. Verified Movement (Run, Hop, Walk, etc.)
    # Checks if this stateno was found during the CMD/CONST scan.
    is_known_movement = False
    if 'movement_states' in globals() and movement_states:
        is_known_movement = any(stateno_check in s_list for s_list in movement_states.values())

    # B. Explicit Positioning (Teleports)
    is_teleport = (analysis.get('is_positioning_move') and 'teleport' in attacktype_str) or attacktype_str == 'teleport'

    # C. Offensive Traits (Hitboxes & Special Types)
    has_hitbox = analysis.get('reach', [None, None, None])[2] is not None
    is_special_attack = attacktype_str in ["command_throw", "target_state", "counter", "reversal", "proj", "helper"]

    # --- THE GOLDEN RULE ---
    # If it is Verified Movement OR Offensive OR a Teleport, it is VALID.
    # We SKIP all disqualification checks for these states.
    is_valid_action = (is_known_movement or is_teleport or has_hitbox or is_special_attack)

    if is_valid_action:
        # It is valid. Do NOT filter it out, even if it's labeled 'unknown' or 'movement_tech'.
        pass 
    else:
        # --- DISQUALIFICATION GATES (The Blacklist) ---
        # We only reach here if the move has NO hitbox, NO verified movement, and is NOT a special attack.
        
        # Gate A: Movement Tech / Taunt / Unknown
        # Since 'is_known_movement' failed above, any 'movement_tech' here is unverified junk logic.
        if any(x in attacktype_str for x in ['taunt', 'unknown', 'none']) or stateno_check == 195:
            return []

        # Gate B: Empty Installs
        # Installs without hitboxes are just buffs/modes. We filter them to prevent empty attack blocks.
        if analysis.get('is_transformation') or attacktype_str == 'install':
             return []

        # Gate C: Catch-All
        # If it wasn't valid above, and hasn't been caught yet, it's a generic empty state.
        return []
    
    # --- [END GUARANTEED FIX] ---
    # --- [FIX] Safety Check for Non-Offensive States ---
    # If the analysis confirms this is not an attack, exit immediately to prevent
    # generating inappropriate aggressive triggers for taunts or other utility moves.
    #if not analysis or (analysis.get('attacktype', 'unknown') == "unknown" and analysis.get('reach', [None, None, None])[2] is None):
    #    return []
    # --- [END FIX] ---
    #stateno = analysis['stateno']
    #if stateno is None: return []
    # --------------------------------------------
    # -------------------------------------------- 
    # --- [END GUARANTEED FIX] ---
    # --- [FIX] Safety Check for Non-Offensive States ---
    # If the analysis confirms this is not an attack, exit immediately to prevent
    # generating inappropriate aggressive triggers for taunts or other utility moves.
    #if not analysis or (analysis.get('attacktype', 'unknown') == "unknown" and analysis.get('reach', [None, None, None])[2] is None):
    #    return []
    # --- [END FIX] ---
    #Delete above line if needed or if problematic
    stateno = analysis['stateno']
    if stateno is None: return []

    # --- Determine what kind of state this is ---
    all_movement_statenos = [s for states_list in movement_states.values() for s in states_list if s is not None]
    is_movement = stateno in all_movement_statenos
    is_attack = analysis['attacktype'] != "unknown" or analysis['reach'][2] is not None

    # --- BRANCH 1: MOVEMENT AI (Build from a clean copy) ---
    if is_movement:
        movement_name_map = {
            "run_fwd": "Run", "air_dash_fwd": "Air Dash Forward",
            "hop_back": "Run Atras", "air_dash_back": "Run Atras (Aire)",
            "walk_fwd": "Walk Forward", "walk_back": "Walk Backward",
            "jump_start": "Jump", "air_jump": "Air Jump"
        }
        move_type_found = next((move for move, found_statenos in movement_states.items() if stateno in found_statenos), None)
        if not move_type_found or move_type_found not in movement_name_map:
            return []
        
        # --- DEFINITIVE FIX: Start with a clean copy of the original state ---
        tempstate = clearcmd(state_block_from_cmd[:], ai_var_re)
        trigger = next((i for i, line in enumerate(tempstate) if 'trigger1' in line.lower()), len(tempstate) - 1)
        
        state_name = movement_name_map[move_type_found]
        tempstate[0] = f"[State -3, Custom AI {state_name}]\n" # Rename the state block

        # --- Inject universal AI triggers ---
        idx = trigger
        tempstate.insert(idx, f"triggerall = {ai_var} > 0 && RoundState = 2\n"); idx += 1
        tempstate.insert(idx, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n"); idx += 1
        tempstate.insert(idx, f"triggerall = stateno != {stateno}\n"); idx += 1
        
        # --- Inject situational AI logic for the specific movement type ---
        # --- This is the direct injection logic, similar to writestate2 ---
        if move_type_found == "run_fwd":
            tempstate.insert(trigger, f"; AI: Injected Run Logic (stateno {stateno})\n")
            tempstate.insert(trigger + 1, "trigger1 = ((p2bodydist x > 40) || (p2bodydist x > 100) || (p2bodydist x > 60 && (EnemyNear, Vel X) < 0 && enemynear, movetype = H && EnemyNear, Stateno != [120,159]) || (enemynear, movetype != A && p2bodydist x > 240) || (p2bodydist x <= 140) || (enemynear,p2dist x < 0) || (p2bodydist x > 140))\n")
            tempstate.insert(trigger + 2, "trigger2 = enemynear,backedgedist < 40 && p2dist y < -40 && enemynear, statetype = A\n") # Corner Cross-Under
            tempstate.insert(trigger + 3, "triggerall = ((enemynear, statetype != L) || (p2bodydist x > 140) || (p2dist x >= 0)) && (P2Dist X >= 0) && (P2BodyDist X > 50)\n")
            tempstate.insert(trigger + 4, ";triggerall = !inguarddist\n")
            tempstate.insert(trigger + 5, f"triggerall = ({ai_var} > 0 && roundstate = 2 && random <= 13* {get_ai_scale_string(stateno, ai_var)})\n")
            tempstate.insert(trigger + 6, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
            tempstate.insert(trigger + 7, f"triggerall = stateno != {stateno}\n")
            tempstate.insert(trigger + 8, "trigger1 = p2bodydist x > 180\n")
            tempstate.insert(trigger + 9, f"trigger1 = p2bodydist y = [-120,-41]\n")
        elif move_type_found == "walk_fwd":
            # --- AI Walk Forward Logic ---
            tempstate.insert(trigger, f"; AI: Injected Walk Fwd Logic (stateno {stateno})\n")
            
            # Global Restrictions (triggerall)
            tempstate.insert(trigger + 1, f"triggerall = {ai_var} > 0 && roundstate = 2 && ctrl\n")
            tempstate.insert(trigger + 2, f"triggerall = statetype != A && statetype != L\n")
            tempstate.insert(trigger + 3, f"triggerall = stateno != {stateno}\n")
            tempstate.insert(trigger + 4, f"triggerall = random <= 150 * {get_ai_scale_string(stateno, ai_var)}\n")
            
            # Control / Combo Logic
            tempstate.insert(trigger + 5, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0)\n")
            
            # Specific Activation Conditions
            # Trigger 1: Distance and Opponent State
            tempstate.insert(trigger + 6, "trigger1 = p2bodydist x >= 60 || (enemynear, movetype = H && enemynear, statetype != L) || 1\n")
            tempstate.insert(trigger + 7, "trigger1 = enemynear, movetype != A\n")
            tempstate.insert(trigger + 8, "trigger1 = p2bodydist x > 80 && p2bodydist x < 200\n")
            
            # Trigger 2: Velocity and Minimum Distance (Force termination/prevention if too close)
            tempstate.insert(trigger + 9, "trigger2 = vel x > 0 && p2bodydist x > 20\n")
            
            # Safety: Ensure the walk doesn't trigger if already inside the "push" range
            tempstate.insert(trigger + 10, "triggerall = p2bodydist x > 20 ; General safety distance\n")
        elif move_type_found == "hop_back":
            tempstate.insert(trigger, f"; AI: Injected Hop Back Logic (stateno {stateno})\n")
            tempstate.insert(trigger + 1, "trigger1 = (p2bodydist x = [0,80]) || ((p2bodydist x = [-11,80]) && backedgebodydist > 80)\n")
            tempstate.insert(trigger + 2, "triggerall = enemynear, statetype != L && !inguarddist\n")
            tempstate.insert(trigger + 3, "triggerall = enemynear, movetype != H || EnemyNear, Stateno = [120,159]\n")
            tempstate.insert(trigger + 4, f"triggerall = {ai_var} > 0 && roundstate = 2 && random <= 3* {get_ai_scale_string(stateno, ai_var)}\n")
            tempstate.insert(trigger + 5, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
            tempstate.insert(trigger + 6, f"triggerall = stateno != {stateno}\n")
            tempstate.insert(trigger + 7, "triggerall = p2dist x <= 200+20\n")
            tempstate.insert(trigger + 8, "trigger1 = backedgebodydist < 50 && p2bodydist x < 80 && enemynear, movetype = A\n")
            tempstate.insert(trigger + 9, "trigger2 = numproj > 0 && p2bodydist x > 80 && p2bodydist x < 200 && pos y >= 0\n")
            tempstate.insert(trigger + 10, "trigger3 = (enemynear,animtime = [-10,0]) && (p2bodydist x < 100)\n")
            tempstate.insert(trigger + 11, "trigger1 = enemynear, statetype = A && enemynear, movetype = H && p2bodydist x >= 120\n")
            tempstate.insert(trigger + 12, "trigger1 = enemynear,vel y <= 0 && backedgedist >= 60\n")
            tempstate.insert(trigger + 13, "trigger2 = enemynear, statetype = A && enemynear, movetype = H && p2bodydist x < 120\n")
        elif move_type_found == "walk_back":
            # --- AI Walk Back Logic ---
            tempstate.insert(trigger, f"; AI: Injected Walk Back Logic (stateno {stateno})\n")
            
            # Global Restrictions (triggerall)
