# <<<--- REPLACE the old get_cmd_state_name function with this --- >>>
def get_cmd_state_name(state_block_from_cmd):
    """ 
    (IMPROVED) Helper to extract a descriptive name from a .cmd state block,
    making it more robust by analyzing its content for command names and
    the target stateno.
    """
    
    # --- Patterns to find different pieces of information ---
    # Pattern to find the descriptive name in the [State] declaration itself.
    # e.g., [State -3, My Cool Move] -> "My Cool Move"
    p_state_name = re.compile(r'\[State\s-?\d+,\s*([^\]]+)\]', re.I)

    # Pattern to find all command triggers within the block.
    # e.g., trigger1 = command = "Hadoken" -> "Hadoken"
    p_command_name = re.compile(r'command\s*=\s*"([^"]+)"', re.I)
    
    # Pattern to find the target stateno from the ChangeState controller.
    # e.g., value = 200 -> "200"
    p_stateno_value = re.compile(r'^\s*value\s*=\s*(\d+)', re.I)
    
    # --- Data Storage ---
    block_name = None
    command_names = []
    target_stateno = None
    
    # --- Analysis Loop ---
    # Iterate through every line in the provided state block.
    for line in state_block_from_cmd:
        line_strip = line.strip()
        
        # Try to find the name from the [State ...] line.
        if (match := p_state_name.search(line_strip)):
            block_name = match.group(1).strip()

        # Find any and all command names.
        if (match := p_command_name.search(line_strip)):
            cmd_name = match.group(1)
            if cmd_name not in command_names: # Avoid duplicates
                command_names.append(cmd_name)

        # Find the target stateno.
        if (match := p_stateno_value.search(line_strip)):
            target_stateno = match.group(1)

    # --- Name Generation Logic (Priority-based) ---

    # Priority 1: Use the explicit name from the [State ...] line if it's descriptive.
    # A name is considered "descriptive" if it's not just a number or a generic placeholder.
    if block_name and not block_name.isdigit() and "state" not in block_name.lower():
        return block_name
        
    # Priority 2: If the block name isn't good, build a name from the command(s).
    if command_names:
        if len(command_names) == 1:
            return f"AI for Command '{command_names[0]}'"
        else:
            return f"AI for Commands: {', '.join(command_names)}"

    # Priority 3: If no names are found, use the target stateno as a fallback.
    if target_stateno:
        return f"AI State for Stateno {target_stateno}"

    # Priority 4: Final fallback if no useful information was found.
    return "Unknown Custom State"

def extract_cmd_statetype_reqs(state_block_from_cmd):
    """
    (V2 - Enriched) Parses a .cmd state block to find explicit StateType and MoveType
    requirements within its triggers, respecting both '=' and '!=' operators.
    This now returns a dictionary containing all found conditions.
    """
    # Regex to find: (1) trigger type, (2) operator, (3) value
    p_trigger_req = re.compile(r'(state|move)type\s*(!?=)\s*([SCAIHL])', re.I)

    # Use a dictionary to store conditions in a structured way
    found_conditions = {
        'statetype': {'=': set(), '!=': set()},
        'movetype':  {'=': set(), '!=': set()}
    }

    for line in state_block_from_cmd:
        # Find all occurrences on a single line
        matches = p_trigger_req.findall(line)
        for match in matches:
            trigger_type = match[0].lower() + 'type'  # Constructs the full key: 'statetype' or 'movetype'
            operator = match[1]              # '=' or '!='
            value = match[2].upper()         # 'S', 'A', 'H', etc.

            # Add the found value to the correct set
            found_conditions[trigger_type][operator].add(value)

    # Convert the sets back to sorted lists for the final dictionary
    final_conditions = {
        'statetype': {'=': sorted(list(found_conditions['statetype']['='])), '!=': sorted(list(found_conditions['statetype']['!=']))},
        'movetype':  {'=': sorted(list(found_conditions['movetype']['='])), '!=': sorted(list(found_conditions['movetype']['!=']))}
    }

    return final_conditions

