    reachtime = reachtime or 0
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    p2x1 = advanced_analysis.get('corrected_p2x1', 0) if advanced_analysis else 0
    p2x2 = advanced_analysis.get('corrected_p2x2', 60) if advanced_analysis else 60
    
    # --- END OF FIX ---
    # --- Setup Triggers ---
    tempstate.insert(trigger, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    tempstate.insert(trigger, py) #py + pyh)
    tempstate.insert(trigger + 1, f"triggerall = numhelper({l_edge_id}) && numhelper({r_edge_id})\n")
    tempstate.insert(trigger + 2, f";triggerall = EnemyNear, StateType != L\n")
    # AI Action Gate: Allow action on player control OR on a valid, developer-defined cancel.
    tempstate.insert(trigger + 2, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    # The anti-spam check is still required.
    tempstate.insert(trigger + 3, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    #tempstate.insert(trigger + 3, f"triggerall = ctrl && stateno != {stateno}\n")
    
    # --- StateType Check (V2: Prioritizing CMD requirements) ---
    # --- Dynamic Trigger Generation (V3 - Automated from CMD analysis) ---
