def writecombo_warusaki3(state, trigger, pyh, reachtime, ai_var, aihelperID, cmd_statetype_reqs, statetype, power, nothitbyflag, hitdef, stateno, helper_ids, analysis):
    """(Warusaki3) Generates extremely high-probability combo/cancel triggers."""
    l_edge_id, r_edge_id = helper_ids['l_edge'], helper_ids['r_edge']
    tempstate = state[:]
