    tempstate[0] = f"[State -3, Warusaki3 Combo: {original_name}]\n"
    reachtime = reachtime or 0
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    
    # --- END OF FIX ---
    # --- Setup Triggers (No 'ctrl' lock for cancels) ---
    tempstate.insert(trigger, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    tempstate.insert(trigger, pyh) #pyh + py)
    tempstate.insert(trigger + 1, f"triggerall = numhelper({l_edge_id}) && numhelper({r_edge_id})\n")
    tempstate.insert(trigger + 2, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    tempstate.insert(trigger + 3, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")

    # --- THE CRITICAL FIX: MOVE CONTACT CHECK ---
    # This line prevents the "Air Whiffing" bug.
    # If we don't have control (!Ctrl), we MUST have made contact (MoveContact) to proceed.
    # If we have control (Ctrl), we can proceed (raw startup).
    #tempstate.insert(trigger + 3, "triggerall = Ctrl || MoveContact\n")

    # --- StateType Check (V2: Prioritizing CMD requirements) ---
    # --- Dynamic Trigger Generation (V3 - Automated from CMD analysis) ---
    # We will insert triggers starting at this index
    insert_index = trigger + 3

    # Add StateType requirements found in the CMD
    #if cmd_statetype_reqs['statetype']['=']:
        #type_conditions = [f"statetype = {req}" for req in cmd_statetype_reqs['statetype']['=']]
       # trigger_line = " || ".join(type_conditions)
      #  tempstate.insert(insert_index, f"triggerall = ({trigger_line}) ; From CMD\n"); insert_index += 1
    
    # Add negative StateType requirements
    #for req in cmd_statetype_reqs['statetype']['!=']:
      #  tempstate.insert(insert_index, f"triggerall = statetype != {req} ; From CMD\n"); insert_index += 1

    # Add MoveType requirements found in the CMD (THE SPAM FIX!)
    #if cmd_statetype_reqs['movetype']['=']:
       # type_conditions = [f"movetype = {req}" for req in cmd_statetype_reqs['movetype']['=']]
      #  trigger_line = " || ".join(type_conditions)
     #   tempstate.insert(insert_index, f"triggerall = ({trigger_line}) ; From CMD\n"); insert_index += 1

    # Add negative MoveType requirements (THE MOST COMMON SPAM FIX!)
    #for req in cmd_statetype_reqs['movetype']['!=']:
    #    tempstate.insert(insert_index, f"triggerall = movetype != {req} ; From CMD (Spam Fix)\n"); insert_index += 1
        
    # --- ENHANCEMENT: DIRECT AI BRAIN INTEGRATION ---
    #tempstate.insert(insert_index, "; --- AI Brain Combo Triggers ---\n")
    # The Combo Window: Is the opponent currently in hitstun from our last attack?
    #tempstate.insert(insert_index + 1, f"triggerall = helper({aihelperID}),var(51) > 0\n")
    # The Permission Slip: Is the character currently in a state that is allowed to be cancelled?
    #tempstate.insert(insert_index + 2, f"triggerall = helper({aihelperID}),var(50) = 1\n")

    # --- Core Combo Logic (from writecombo) ---
    tempstate.insert(trigger + 5, f"triggerall = (enemynear,animtime <= -{reachtime} && !enemynear,canrecover && helper({aihelperID}),var(17) = 0 || helper({aihelperID}),var(17) >= {reachtime}) || (enemynear, movetype = H)\n")
    if hitdef is not None and '-D' in hitdef:
        tempstate.insert(trigger + 6, "triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H ;triggerall = !inguarddist && enemynear,alive && enemynear, movetype = H ;triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H\n")
    else:
        tempstate.insert(trigger + 6, "triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H && enemynear, statetype != L ;triggerall = !inguarddist && enemynear,alive && enemynear, movetype = H && enemynear, statetype != L ;triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H && enemynear, statetype != L\n")

    # 1. Get StateType (String: 'S', 'C', 'A') safely
    # We default to 'S' (Standing) if missing, as this is a standing catch function
    statetype = stateattr[1] if stateattr and len(stateattr) > 1 and isinstance(stateattr[1], str) else 'S'

    # DETERMINISTIC: Attack if within valid range (Ground: 60px, Air: 40px)
    safe_dist = 60 if statetype != 'A' else 40

    # --- High-Probability Execution ---
    # The "Warusaki3" style for combos is to be relentless and almost never drop them.
    tempstate.insert(trigger + 7, f"trigger1 = (random <= 950 * {get_ai_scale_string(stateno, ai_var)}) ; High-confidence cancel\n")

    return tempstate

