def generate_warusaki3_style_guard_triggers(ai_var, movement_states, helper_ids, grab_stateno=800):
    """
    (V2 - PRECISE REPLICATION) Generates the two-part universal guard logic
    exactly as specified by the user's provided MUGEN code example.
    """
    print("      L-> Warusaki3-Style AI: Generating V2 precise universal guard triggers...")

    # Extract all required helper IDs for clarity
    l_edge_id = helper_ids['l_edge']
    r_edge_id = helper_ids['r_edge']
    proj_check_id = helper_ids['proj_check']
    
    # --- DYNAMICALLY BUILD THE MOVEMENT STATE TRIGGER ---
    run_statenos = movement_states.get('run_fwd', [])
    walk_statenos = movement_states.get('walk_fwd', [])
    all_ground_move_statenos = sorted(list(set(run_statenos + walk_statenos)))
    
    ground_move_check_trigger = ""
    if all_ground_move_statenos:
        statenos_str = ','.join(map(str, all_ground_move_statenos))
        ground_move_check_trigger = f" || stateno = [{statenos_str}]"
        
    # Build the state block using a list of strings to precisely match the example
    final_code_block = [
        "\n;=============================================\n",
        ";ガード (Generated by Script)\n",
        ";=============================================\n",
        "[State -1, 汎用ガード]\n",
        "type = Null;ChangeState\n",
        "value = 120\n",
        
        # --- Universal Setup Triggers (Translated from example) ---
        f"triggerall = {ai_var} > 0 && roundstate = 2\n",
        f"triggerall = !helper({l_edge_id}),var(0) || (helper({l_edge_id}),var(0) = 3 && helper({l_edge_id}),var(2))\n",
        f"triggerall = numenemy > 0 || power >= 1000\n",
        f"triggerall = ctrl && stateno != [120,155]\n", #f"triggerall = (ctrl{ground_move_check_trigger}) && (stateno != [120,155])\n",
        "triggerall = !(enemynear,hitdefattr = SCA,AT)\n",
        f"triggerall = numhelper({l_edge_id})\n",
        f"triggerall = numhelper({proj_check_id})\n",
        f"triggerall = inguarddist || helper({l_edge_id}),var(10)&2**3 || (enemy,numproj && enemynear,p2dist x>=0 && p2bodydist x<=120 && p2bodydist y>=-120)\n",
        f"triggerall = inguarddist || (helper({proj_check_id}),inguarddist && random < (1.0-life*1.0/lifemax)*300)\n",
        f"triggerall = random < 500+(random%(100+(enemynear,time>=15)*100+(enemynear,time>=7)*100+(enemynear, statetype=A)*100+(life<700)*100+(life<500)*100+(life<333)*100)) || {ai_var} >= 7\n",
        f"triggerall = {ai_var} < 8 || random < 200\n",
        
        # --- High-Priority Guard Triggers (Directly from example) ---
        f"trigger1 = enemynear,hitdefattr = SCA,AA,AP\n",
        f"trigger1 = !(helper({l_edge_id}),var(35) || EnemyNear, Stateno=helper({l_edge_id}),var(18) || enemynear,p2dist x < 0)\n",
        f"trigger1 = !helper({r_edge_id}),fvar(0) || !enemynear,movecontact\n",
        f"trigger2 = enemy,numproj || helper({proj_check_id}),var(58)&2**10\n",
        f"trigger3 = enemynear,movetype = A && enemynear,stateno >= 1000 && !(enemynear,hitdefattr = SCA,AA,AP)\n",
        f"trigger4 = helper({l_edge_id}),var(10)&2**3\n",
        f"trigger5 = helper({proj_check_id}),var(2)=5\n",
        f"trigger6 = inguarddist\n",
        f"trigger6 = !(enemynear,hitdefattr = SCA,AA,AP)\n",
        f"trigger6 = !(enemy,numproj || helper({proj_check_id}),var(58)&2**10)\n",
        f"trigger6 = !(enemynear,movetype = A && enemynear,stateno >= 1000 && !(enemynear,hitdefattr = SCA,AA,AP))\n",
        f"trigger6 = !(helper({l_edge_id}),var(10)&2**3)\n",
        f"trigger6 = !(helper({proj_check_id}),var(2)=5)\n",
        f"trigger6 = !(enemynear,stateno = [200,999])\n\n",

        # --- Second State Block (AssertSpecial) ---
        "[State -1, Guard Flag Control]\n",
        "type = Null;AssertSpecial\n",
        f"trigger1 = {ai_var} >= 1\n",
        "flag = nostandguard\n",
        "flag2 = nocrouchguard\n",
        "flag3 = noairguard\n",
    ]
   
    # --- DYNAMICALLY GET HOP BACK STATENO ---
    hop_back_statenos = movement_states.get('hop_back', [])
    hop_back_stateno = hop_back_statenos[0] if hop_back_statenos else 105

    # --- ADD THE NEW EMERGENCY EVADE BLOCK ---
    final_code_block.extend([
        "\n\n;=============================================\n",
        ";緊急用回避 (Emergency Evade - Generated)\n",
        ";=============================================\n",
        "[State -1, 緊急用回避]\n",
        "type = Null;ChangeState\n",
        f"value = ifelse(backedgedist >= 90 && (frontedgebodydist < 90 || random < 666), {hop_back_stateno}, {grab_stateno}) ;replace 800 with a grab state\n", 
        f"triggerall = {ai_var} > 0 && roundstate = 2\n",
        "triggerall = statetype != A\n",
        "triggerall = power < 1000\n",
        f"triggerall = !helper({l_edge_id}),var(40)\n",
        f"triggerall = !helper({r_edge_id}),fvar(24)\n",
        f"triggerall = !helper({l_edge_id}),var(0) || (helper({l_edge_id}),var(0) = 3 && helper({l_edge_id}),var(2))\n",
        "triggerall = enemynear,ID != [0,1]\n",
        "triggerall = (facing != enemynear,facing && enemynear,p2dist x >= 0)\n",
        f"triggerall = ctrl && stateno != [120,155]\n", #f"triggerall = (ctrl{ground_move_check_trigger}) && (stateno != [120,155])\n",
        "triggerall = !(enemynear,hitdefattr = SCA,AT)\n",
        f"triggerall = numhelper({l_edge_id})\n",
        f"triggerall = numhelper({proj_check_id})\n",
        f"triggerall = inguarddist || helper({l_edge_id}),var(10)&2**3\n",
        f"triggerall = random < 500+(random%(100+(enemynear,time>=15)*100+(enemynear,time>=7)*100+(enemynear, statetype=A)*100+(life<700)*100+(life<500)*100+(life<333)*100)) || {ai_var} >= 7\n",
        "triggerall = enemynear, movetype != H\n",
        f"triggerall = {ai_var} < 8 || random < 200\n",
        f"trigger1 = enemynear,hitdefattr = SCA,AA,AP\n",
        f"trigger1 = !(helper({l_edge_id}),var(35) || EnemyNear, Stateno=helper({l_edge_id}),var(18) || enemynear,p2dist x < 0)\n",
        f"trigger1 = !helper({r_edge_id}),fvar(0) || !enemynear,movecontact\n",
        f"trigger2 = enemy,numproj || helper({proj_check_id}),var(58)&2**10\n",
        f"trigger3 = enemynear,movetype = A && enemynear,stateno >= 1000 && !(enemynear,hitdefattr = SCA,AA,AP)\n",
        f"trigger4 = helper({l_edge_id}),var(10)&2**3\n",
        f"trigger5 = helper({proj_check_id}),var(2)=5\n",
        f"trigger6 = inguarddist\n",
        f"trigger6 = !(enemynear,hitdefattr = SCA,AA,AP)\n",
        f"trigger6 = !(enemy,numproj || helper({proj_check_id}),var(58)&2**10)\n",
        f"trigger6 = !(enemynear,movetype = A && enemynear,stateno >= 1000 && !(enemynear,hitdefattr = SCA,AA,AP))\n",
        f"trigger6 = !(helper({l_edge_id}),var(10)&2**3)\n",
        f"trigger6 = !(helper({proj_check_id}),var(2)=5)\n",
        f"trigger6 = !(enemynear,stateno = [200,999])\n",
    ])
    
    return final_code_block


def generate_universal_ai_initializers(activation_id, proj_id, r_edge_id, l_edge_id, ai_var_string):
    """
    Generates the [State -3] controller blocks that create the universal AI helpers.
    """
    # Adapt the activation trigger based on MUGEN version
    activation_trigger = ""
    if "AILevel" in ai_var_string:
        activation_trigger = f"trigger1 = {ai_var_string} > 0"
    else:
        # For WinMUGEN, we check the var set by the activation helper itself.
        activation_trigger = f"trigger1 = !{ai_var_string}"

    initializers = [
        
        f"""
        
; If you want to use the Guard mode, Dummy mode, Distance, or Button jam dummy control
; options in Training mode without activating the dummy's AI while working on your
; character, then all you need to do is temporarily disable this controller.
; Or, if you want to permanently disable this controller in Training mode,
; then you could use the Training mode detection code available on my site
; ( http://www.shinmugen.net/winane/ ), and then just add a "(var(59)&63)>30"
; triggerall to this controller.
[State -3, AI Helper]
type = Helper
{activation_trigger}
triggerall = !IsHelper
triggerall = !numhelper({activation_id})
triggerall = alive && roundstate=2
trigger1 = !NumPartner
trigger2 = !(Partner,SelfAnimExist(9999))
HelperType = normal
name = "AI Helper Activator"
ID = {activation_id}
pos = 9999999,99999
StateNo = {activation_id}
KeyCtrl = 1
PauseMoveTime = 999999999
SuperMoveTime = 999999999 

; It is very important that this controller NOT be moved to State -2, as putting
; it there would defeat the entire purpose of the controller, allowing the
; helper method or the XOR method to erroneously set the AI variable.
; And within State -3, don't put any ChangeState controllers before this
; controller, lest you unnecessarily delay your character's AI activation.
[State -3, GameTimeVar]
type = Null;VarSet
trigger1 = 1
var(57) = GameTime
IgnoreHitPause = 1

"""
        "\n;===========================================================================\n",
        "; UNIVERSAL AI HELPER INITIALIZERS\n",
        ";===========================================================================\n",
        ";These controllers create the universal AI helpers used by the AI system but use with caution, they cause... bugs/glitches where the Character's AI will kind of... ignore the character's Transformation triggers\n",
        f"[State -3, AI Activation Helper Initializer]\n",
        # CORRECTED: The type should be 'Helper', not 'Null;helper'.
        "type = Helper\n",
        "Triggerall = !IsHelper\n",
        # COMBINED TRIGGERS: Ensures all conditions must be met.
        f"triggerall = !numhelper({activation_id})\n",
        "triggerall = alive && roundstate=2\n",
        f";{activation_trigger}\n",
        "trigger1 = 1\n",
        "helpertype=normal\n",
        "name=\"AI_Activator\"\n",
        f"ID={activation_id}\n",
        "pos=9999,9999\n",
        f"stateno={activation_id}\n",
        "keyctrl=1\n",
        "pausemovetime=65535\n",
        "supermovetime=65535\n",
        
        f"""
        [State -3]
        type = changestate
        Trigger1 = ishelper({activation_id})&&stateno != {activation_id}
        value = {activation_id}
        """

        f"\n[state -3, Right Edge Detector Initializer]\n",
        "type = Helper\n",
        "Triggerall = !IsHelper\n",
        "triggerall = roundstate = [1,2]\n",
        f";{activation_trigger}\n",
        "trigger1 = 1\n",
        f"triggerall = !numhelper({r_edge_id})\n",
        "helpertype = normal\n",
        "name = \"stageedge_right\"\n",
        "postype = left\n",
        f"stateno = {r_edge_id}\n",
        f"ID = {r_edge_id}\n",
        "pos = 160,9999\n",
        "facing = -1\n",
        "pausemovetime = 2147483647\n",
        "supermovetime = 2147483647\n",
        
        f"""
        [State -3]
        type = changestate
        Trigger1 = ishelper({r_edge_id})&&stateno != {r_edge_id}
        value = {r_edge_id}
        """

        f"\n[state -3, Left Edge Detector Initializer]\n",
        "type = Helper\n",
        "Triggerall = !IsHelper\n",
        "triggerall = roundstate = [1,2]\n",
        f";{activation_trigger}\n",
        "trigger1 = 1\n",
        f"triggerall = !numhelper({l_edge_id})\n",
        "helpertype = normal\n",
        "name = \"stageedge_left\"\n",
        "postype = left\n",
        f"stateno = {l_edge_id}\n",
        f"ID = {l_edge_id}\n",
        "pos = -160,9999\n",
        "facing = 1\n",
        "pausemovetime = 2147483647\n",
        "supermovetime = 2147483647\n",
        
        f"""
        [State -3]
        type = changestate
        Trigger1 = ishelper({l_edge_id})&&stateno != {l_edge_id}
        value = {l_edge_id}
        
        """

        f"\n[state -3, AI Projectile Scanner Initializer]\n",
        "type = Helper\n",
        "Triggerall = !IsHelper\n",
        "triggerall = roundstate = [1,2]\n",
        f"{activation_trigger}\n",
        "trigger1 = 1\n",
        f"triggerall = !numhelper({proj_id})\n",
        "helpertype = normal\n",
        "name = \"ai_projectile_scanner\"\n",
        "postype = p1\n",
        f"stateno = {proj_id}\n",
        f"ID = {proj_id}\n",
        "pos = 9999,9999\n",
        "facing = 1\n",
        "pausemovetime = 2147483647\n",
        "supermovetime = 2147483647\n",
        
        f"""
        [State -3]
        type = changestate
        Trigger1 = ishelper({proj_id})&&stateno != {proj_id}
        value = {proj_id}
        
        """
    ]
    return initializers

def writefight_doly_p29(state, trigger, py, reachtime, hitdef, statetype, totaltime, ai_var, aihelperID, cmd_statetype_reqs, power=0, damage=0, super_flag=0, stateno=0, analysis=None):
    """
    Generates general-purpose 'footsie' or aggressive attack triggers.
    AMALGAMATED: Includes 'Doly_P29 Style' Precision and Whiff Punish logic.
    """
    tempstate = state[:]
    reachtime = reachtime or 0
    totaltime = totaltime or 0
    power = power or 0
    damage = damage or 0
    hitdef = hitdef or ""
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    
    # --- END OF FIX ---

    tempstate.insert(trigger, py) #py + pyh)
    tempstate.insert(trigger, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    
    # --- Doly_P29 ENHANCEMENT: CONTROL CHECK ---
    # Standard AI often fails because it waits for 'Ctrl'. 
    # Doly_P29 logic allows attacks during dashes or specific states if defined.
    # We keep the helper check but ensure 'Ctrl' isn't the only gate.
    tempstate.insert(trigger + 1, f"triggerall = (ctrl) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")
    
    tempstate.insert(trigger + 2, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")

    # --- StateType Check (V2: Prioritizing CMD requirements) ---
    # We will insert triggers starting at this index
    insert_index = trigger + 3

    # Add StateType requirements found in the CMD
    #if cmd_statetype_reqs['statetype']['=']:
        #type_conditions = [f"statetype = {req}" for req in cmd_statetype_reqs['statetype']['=']]
       # trigger_line = " || ".join(type_conditions)
      #  tempstate.insert(insert_index, f"triggerall = ({trigger_line}) ; From CMD\n"); insert_index += 1
    
    # Add negative StateType requirements
    #for req in cmd_statetype_reqs['statetype']['!=']:
      #  tempstate.insert(insert_index, f"triggerall = statetype != {req} ; From CMD\n"); insert_index += 1

    # Add MoveType requirements found in the CMD (THE SPAM FIX!)
    #if cmd_statetype_reqs['movetype']['=']:
       # type_conditions = [f"movetype = {req}" for req in cmd_statetype_reqs['movetype']['=']]
      #  trigger_line = " || ".join(type_conditions)
     #   tempstate.insert(insert_index, f"triggerall = ({trigger_line}) ; From CMD\n"); insert_index += 1

    # Add negative MoveType requirements (THE MOST COMMON SPAM FIX!)
    #for req in cmd_statetype_reqs['movetype']['!=']:
    #    tempstate.insert(insert_index, f"triggerall = movetype != {req} ; From CMD (Spam Fix)\n"); insert_index += 1
        
    # --- START OF Y-AXIS DETECTOR ADDITION ---
    # --- METHOD 2: Helper-Based Situational Logic (Parallel) ---
    vertical_props = AI_VERTICAL_MAP.get(stateno, {})
    
    # We maintain your insert_index logic but shift it down to accommodate the new Doly_P29 logic below
    # ... (Your existing Y-Axis/Vertical Props logic goes here, unchanged) ...
    
    # --- START OF Doly_P29 PRECISION LOGIC INJECTION ---
    # This logic is inserted BEFORE the random triggers to ensure it takes priority.
    
    Doly_P29_idx = insert_index + 6 # Adjust based on your vertical props length
    
    # 1. WHIFF PUNISH (Doly_P29 Style)
    # If the enemy missed an attack and is recovering, and we are in range, ATTACK immediately.
    # No RNG involved. Pure reaction.
    if reachtime < 15: # Only fast moves are good whiff punishers
        tempstate.insert(Doly_P29_idx, f"; AI: Doly_P29-Style Whiff Punish (Deterministic)\n")
        tempstate.insert(Doly_P29_idx + 1, f"trigger1 = EnemyNear, MoveType = A && EnemyNear, MoveHit = 0\n")
        tempstate.insert(Doly_P29_idx + 2, f"trigger1 = P2BodyDist X < {100 if statetype != 'A' else 60}\n")
        Doly_P29_idx += 3

    # 2. PRESSURE / FRAME TRAPS (Doly_P29 Style)
    # If we are right in their face, keep pressing buttons.
    # This prevents the "staring contest" issue.
    tempstate.insert(Doly_P29_idx, f"; AI: Doly_P29-Style Close Pressure (Deterministic)\n")
    tempstate.insert(Doly_P29_idx + 1, f"trigger2 = P2BodyDist X < 30 && EnemyNear, Statetype != L\n")
    tempstate.insert(Doly_P29_idx + 2, f"trigger2 = EnemyNear, MoveType != A ; Don't mash into an active attack\n")
    Doly_P29_idx += 3
    
    # --- END OF Doly_P29 PRECISION LOGIC ---

    # --- STANDARD LOGIC (Renumbered to trigger3+) ---
    # We keep the randomness as a fallback for when the specific conditions above aren't met.
    
    # DETERMINISTIC: Attack if within valid range (Ground: 60px, Air: 40px)
    safe_dist = 60 if statetype != 'A' else 40
    
    attack_rate = max(min(int(3000 / (reachtime + 1 + totaltime + 10 * ('S' in hitdef or 'H' in hitdef)) + 15 * (statetype == 'A' or 'T' in hitdef)), 500), 20)
    if 0 < power < 1000:
        attack_rate = max(int(attack_rate * (1 - power / 1000)), 1)

    tempstate.insert(Doly_P29_idx, f"; AI: Standard Footsie (RNG Fallback)\n")
    tempstate.insert(Doly_P29_idx + 1, f"trigger3 = (random <= {attack_rate}* {get_ai_scale_string(stateno, ai_var)})\n")
    
    # Ensure triggers align with triggerall requirements
    tempstate.insert(trigger + 4, f"triggerall = (enemynear, statetype != L && movetype != H && ctrl) || (!inguarddist && !helper({aihelperID}),inguarddist && enemynear, statetype != L && movetype != H && ctrl) || (enemynear, statetype != L)\n")

    if 'T' in hitdef.upper():
        tempstate.insert(trigger + 9, f"triggerall = helper({aihelperID}),var(18) <= 0\n")

    return tempstate

def writecombo_doly_p29(state, trigger, pyh, reachtime, ai_var, aihelperID, cmd_statetype_reqs, statetype, power=0, nothitbyflag=0, hitdef=None, stateno=0):
    """
    Generates triggers for combo-ing into a move.
    AMALGAMATED: Includes 'Doly_P29 Style' Hit-Confirm Logic to prevent dropped combos.
    """
    tempstate = state[:]
    reachtime = reachtime or 0
    power = power or 0
    analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, {})
    
    # --- END OF FIX ---
    tempstate.insert(trigger, pyh) #pyh + py)
    tempstate.insert(trigger, f"triggerall = {ai_var} > 0 && roundstate = 2\n")
    
    # --- Doly_P29 ENHANCEMENT: COMBO FLUIDITY ---
    # The original script restricts combos if 'ctrl' is false, which is WRONG for cancelling moves.
    # We add "MoveContact" (did we touch them?) as a valid condition to cancel.
    tempstate.insert(trigger + 1, f"triggerall = (ctrl) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| MoveContact ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0) ;|| MoveContact\n")
    
    tempstate.insert(trigger + 2, f"triggerall = (stateno != {stateno}) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0 && random <= 850) || ((helper({aihelperID}),var(50) & 2048) && helper({aihelperID}),var(51) > 0) ;|| (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0 && random <= 850) || (helper({aihelperID}),var(50) = 1 && helper({aihelperID}),var(51) > 0)\n")

    # --- StateType Check (V2: Prioritizing CMD requirements) ---
    # (Insert your cmd_statetype_reqs logic here if you wish, or leave commented out as per your paste)
    insert_index = trigger + 2
        
    # --- ENHANCEMENT: DIRECT AI BRAIN INTEGRATION ---
    #tempstate.insert(insert_index, "; --- AI Brain Combo Triggers ---\n")
    #tempstate.insert(insert_index + 1, f"triggerall = helper({aihelperID}),var(51) > 0\n")
    #tempstate.insert(insert_index + 2, f"triggerall = helper({aihelperID}),var(50) = 1\n")
    
    # --- Doly_P29 STYLE: DETERMINISTIC HIT CONFIRM ---
    # This is the specific fix for "On and Off" combos.
    # If we hit the enemy (MoveHit), we DO NOT roll the dice. We execute the combo.
    # trigger1 is now the "Guaranteed" path.
    tempstate.insert(insert_index + 3, "; AI: Doly_P29-Style Hit Confirm (Guaranteed Combo)\n")
    tempstate.insert(insert_index + 4, f"trigger1 = MoveHit = 1\n")
    tempstate.insert(insert_index + 5, f"trigger1 = EnemyNear, StateType != L\n") # Don't combo if they dropped out/fell
    
    # --- STANDARD LOGIC (RNG) ---
    # This becomes trigger2, used if we are blocked (MoveGuarded) or just fishing.
    # Standard triggeralls for safety
    tempstate.insert(insert_index + 6, f"triggerall = (enemynear,animtime <= -{reachtime} && !enemynear,canrecover && helper({aihelperID}),var(17) = 0 || helper({aihelperID}),var(17) >= {reachtime}) || (enemynear, movetype = H)\n")
    
    if hitdef is not None and '-D' in hitdef:
        tempstate.insert(insert_index + 7, "triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H\n")
    else:
        tempstate.insert(insert_index + 7, "triggerall = (!inguarddist || !ctrl) && enemynear,alive && enemynear, movetype = H && enemynear, statetype != L\n")
    
    # This is the "Random" trigger. Note that it is now trigger2.
    # Because trigger1 (MoveHit) exists, if we hit, we ignore this randomness.
    # If we haven't confirmed a hit (e.g. blocked), we roll the dice to see if we continue pressure.
    tempstate.insert(insert_index + 8, f"trigger2 = (random <= (120+(helper({aihelperID}),var(17)={reachtime+1})*80)* {get_ai_scale_string(stateno, ai_var)}) ;|| (MoveContact) || (MoveHit)\n")
    
    if power >= 1000 or nothitbyflag == 1:
        tempstate.insert(insert_index + 9, "triggerall = EnemyNear, Stateno != [120,159]\n")
    
    # Special Super Logic
    if super_flag == 1 and power is not None and power > 0:
        # High probability to encourage using the super combo path
        # Note: Added as trigger3 to ensure it fires if power condition is met
        tempstate.insert(insert_index + 10, f"trigger3 = MoveHit && Power >= {power} && Random <= 900\n")
        
    return tempstate

