def procArray(a):
    """
    (OMNI-ROBUST V6 - INTEGRITY & VALIDATION GUARD)
    1. FLATTENS nested inputs.
    2. PARSES blocks based on [State] headers.
    3. MANDATORY CHECK: Disqualifies blocks missing 'type' or 'value'.
    4. PRIORITY PROTECTION: Keeps the first instance of singleton parameters.
    5. DEDUPLICATES & SORTS: Sorts by State Number and removes logical duplicates.
    """
    import re

    def flatten_input(data):
        flat_list = []
        if isinstance(data, (list, tuple, set)):
            for item in data:
                flat_list.extend(flatten_input(item))
        elif data is not None:
            lines = str(data).splitlines()
            for line in lines:
                if line.strip():
                    flat_list.append(line.strip())
        return flat_list

    raw_stream = flatten_input(a)

    # --- Phase 2: Reconstruction & Validation ---
    valid_blocks = []
    current_block = []
    current_stateno = 999999
    
    # Matches [State], [Statedef], [State 100], etc. 
    # Captures State Number in Group 1
    p_header = re.compile(r'^\s*\[State(?:def)?(?:\s*,\s*|\s+)?(-?\d+)?(?:(?:\s*,\s*|\s+)(.*))?\]', re.I)
    p_singleton = re.compile(r'^\s*(value|type|stateno|v|ID)\s*=', re.I)
    
    for line in raw_stream:
        match = p_header.match(line)
        if match:
            if current_block:
                valid_blocks.append((current_stateno, current_block))
            
            # Extract state number; default to 999999 if [State ] is empty
            state_num_raw = match.group(1)
            state_num = int(state_num_raw) if state_num_raw else 999999
            
            extra_content = match.group(2).strip() if match.group(2) else ""
            
            # Normalize header
            if extra_content:
                extra_content = re.sub(r'^,\s*', '', extra_content)
                line = f"[State {state_num if state_num_raw else ''}, {extra_content}]"
            else:
                line = f"[State {state_num if state_num_raw else ''}]"

            current_stateno = state_num
            current_block = [line]
        else:
            if current_block:
                current_block.append(line)

    if current_block:
        valid_blocks.append((current_stateno, current_block))

    # --- Phase 3: Processing (Validation, Integrity & Sort) ---
    # Amalgamated Sorting Logic
    valid_blocks.sort(key=lambda x: x[0])
    
    final_output = []
    seen_fingerprints = set()

    for stateno, block in valid_blocks:
        sanitized_block = []
        found_params = set() 

        for line in block:
            param_match = p_singleton.match(line)
            if param_match:
                p_name = param_match.group(1).lower()
                # Priority Integrity: Keep only the FIRST instance of a singleton
                if p_name in found_params:
                    continue 
                found_params.add(p_name)
            
            sanitized_block.append(line)

        # --- MANDATORY PARAMETER FILTER ---
        # Disqualify if 'type' or 'value' is missing
        # (Using 'type' as the primary indicator of a valid state controller)
        if 'type' not in found_params or 'value' not in found_params:
            continue

        # Context-Aware Deduplication
        logic_lines = [l.lower() for l in sanitized_block[1:] if not l.startswith(';')]
        fingerprint = "".join(logic_lines)

        if fingerprint in seen_fingerprints:
            continue
        
        seen_fingerprints.add(fingerprint)

        # --- Phase 4: Final Formatting ---
        for line in sanitized_block:
            final_output.append(line + '\n')
        final_output.append('\n')

    return final_output


#Remove if problematic
def fix_unconditional_or_triggers(state_block):
    """
    (DEFINITIVE FIX) Surgically removes the '|| 1' override from any trigger
    that uses an assignment-expression (:=). This prevents the AI from bypassing
    intended character logic.
    """
    # This regex finds any trigger line containing ':=', captures the valid part,
    # and specifically targets the '|| 1' at the end for removal.
    p_override = re.compile(r'(trigger\w*\s*=\s*.*?\s*:=\s*.*?)\s*\|\|\s*1', re.I)
    
    fixed_block = []
    for line in state_block:
        # Use re.sub to replace the pattern with only the captured group 1,
        # which is everything BEFORE the '|| 1'.
        modified_line = p_override.sub(r'\1', line)
        fixed_block.append(modified_line)
        
    return fixed_block

