#
# --- REPLACE your process_and_split_ai_code function with this DEFINITIVE version ---
#
def process_and_split_ai_code(list_of_all_logic_lists, ai_var, overflow_helper_id):
    """
    (V55 - STRICT 'AS IS' NULL METHOD)
    1. Uses 'type = Null'.
    2. Preserves original trigger numbering (trigger1, trigger2, etc.).
    3. Injects 'Root,' prefix only where necessary for Helper visibility.
    4. Appends specific 'floor' and 'var' assignment logic at the end.
    5. Sets Cooldown (var 2) to 1 for Turbo/Instant response.
    """
    print("\n--- [V55 STRICT 'AS IS'] Generating State Tree (Null) ---")
    
    STATE_CONTROLLER_LIMIT = 400
    
    p_val = re.compile(r'(?:value|stateno)\s*=\s*.*?(\d+)', re.I)
    p_trig_start = re.compile(r'^\s*trigger', re.I)

    # Redirection: Critical for Helper to see Player's stats
    # We apply this to prevent the helper from checking its own Ctrl/State
    redirect_pattern = re.compile(r'(?<![\.\,])\b(Ctrl|StateNo|StateType|MoveType|Power|Life|Time|Anim|CanRecover|MoveHit|MoveContact|MoveGuarded)\b', re.I)
    redirection_keywords = ['enemynear', 'enemy', 'target', 'parent', 'root', 'helper', 'partner', 'playerid']

    # 1. Flatten Inputs
    all_raw_blocks = []
    for item in list_of_all_logic_lists:
        if isinstance(item, (tuple, list)) and len(item) >= 2:
            logic_list = item[1]
            if not logic_list: continue
            
            def flatten(lst):
                flat = []
                for x in lst:
                    if isinstance(x, list): flat.extend(flatten(x))
                    elif isinstance(x, str): flat.append(x)
                return flat

            flat_data = flatten(logic_list)
            current_block = []
            p_header = re.compile(r'^\s*\[State', re.I)
            
            for line in flat_data:
                line_str = line.strip()
                if not line_str: continue
                if p_header.match(line_str):
                    if current_block: all_raw_blocks.append(current_block)
                    current_block = [line_str + "\n"]
                else:
                    current_block.append(line_str + "\n")
            if current_block: all_raw_blocks.append(current_block)

    print(f"  -> Total Blocks: {len(all_raw_blocks)}")

    # 2. Build Controllers
    final_processed_blocks = []
    ai_level_str = "root,AILevel" if "AILevel" in ai_var else "root," + ai_var
    
    for block in all_raw_blocks:
        block_str = "".join(block)
        
        stateno_val = None
        if m := p_val.search(block_str):
            stateno_val = m.group(1)
            
        if stateno_val and int(stateno_val) > 0:
            # Header
            new_block = [
                f"\n; [State Tree: {stateno_val}]\n",
                f"[State 20010, VS {stateno_val}]\n",
                "type = Null\n",
                # Mandatory Gatekeepers
                f"triggerall = {ai_level_str} > 0 && var(2) = 0\n",
                f"triggerall = root,stateno != {stateno_val}\n"
            ]
            
            # Inject Original Triggers "AS IS" (with Root Redirection Only)
            for line in block:
                line_strip = line.strip()
                if p_trig_start.match(line_strip):
                    
                    # 1. Redirection Logic
                    # If the line already looks at an external entity, leave it alone.
                    has_foreign_redirection = any(k in line_strip.lower() for k in redirection_keywords)
                    
                    if has_foreign_redirection:
                        new_block.append(line_strip + "\n")
                    #else:
                        # Otherwise, prefix keywords with 'Root,' so the Helper checks the Player
                    #    safe_line = redirect_pattern.sub(r'Root,\1', line_strip)
                    #    new_block.append(safe_line + "\n")
                    else:
                        # Fix: Keep "triggerX =" intact, only prefix the condition logic
                        safe_line = re.sub(r'(trigger\d*\s*=\s*)(.*)', 
                                        lambda m: m.group(1) + redirect_pattern.sub(r'Root,\1', m.group(2)), 
                                        line_strip, flags=re.I)
                        new_block.append(safe_line + "\n")

            # Execution Logic (Appended at the end, exactly as requested)
            # This relies on MUGEN's execution order. If the specific triggers above (AS IS)
            # evaluate to true, these trigger1 lines will also be evaluated.
            
            # Outcome Check
            new_block.append(f"triggerall = floor(1*var(0)/1000.0) = 0\n")
            
            # Set Target State
            new_block.append(f"triggerall = var(1) := {stateno_val}\n")
            
            # Set Cooldown (TURBO MODE: 1 Tick)
            new_block.append(f"triggerall = var(2):=11-{ai_level_str} ;var(2) := 1\n")
            
            new_block.append(f"trigger1 = 1\n")
            
            # Required Parameter (even for Null)
            new_block.append("ignorehitpause = 1\n")

            final_processed_blocks.append(new_block)

    # 3. Chunking & Generation
    chunks = [final_processed_blocks[i:i + STATE_CONTROLLER_LIMIT] for i in range(0, len(final_processed_blocks), STATE_CONTROLLER_LIMIT)]
    print(f"--- Splitting into {len(chunks)} Overflow Helper Statedefs ---")

    all_initializers = []
    all_helper_defs = []

    for i, chunk in enumerate(chunks):
        current_helper_id = overflow_helper_id + i
        
        # Spawner
        initializer = [
            f'\n; --- AI Helper #{i+1} Spawner ---\n',
            f'[State -2, Spawn AI Helper {current_helper_id}]\n', 
            'type = Helper\n',
            f'trigger1 = {ai_var} > 0\n',
            f'trigger1 = !NumHelper({current_helper_id})\n',
            f'stateno = {current_helper_id}\n', 
            f'ID = {current_helper_id}\n',
            f'name = "AI_Tree_{i+1}"\n', 
            'postype = p1\n', 'pos = 0,0\n',
            'ownpal = 1\n', 'facing = 1\n', 'ignorehitpause = 1\n'
        ]
        all_initializers.extend(initializer)

        # Helper Def
        helper_header = [
            f'\n;==================================================\n',
            f';--- AI STATE TREE HELPER #{i+1} (ID: {current_helper_id}) ---\n',
            f';==================================================\n',
            f'[Statedef {current_helper_id}]\n', 
            'anim = 20218;9999;20218;9999;20218 ; Blank Anim\n', 
            
            f'[State {current_helper_id}, TURN]\n',
            'type = Turn\n', 'trigger1 = facing != root,facing\n', 'ignorehitpause = 1\n',
            
            f'[State {current_helper_id}, BTR]\n',
            'type = BindToRoot\n', 'trigger1 = 1\n', 'pos = 0,0\n', 'ignorehitpause = 1\n',
            
            f'[State {current_helper_id}, RAND]\n',
            'type = VarSet\n', 'trigger1 = 1\n', 'var(0) = random\n', 'ignorehitpause = 1\n',
            
            f'\n; --- DECISION BLOCKS (NULL) ---\n'
        ]
        
        chunk_content = []
        for block in chunk:
            chunk_content.extend(block)
            chunk_content.append('\n')
            
        helper_footer = [
            
            f'\n; --- SIGNAL TRANSMISSION ---\n',
            
            # PVS (Send)
            f'[State {current_helper_id}, PVS]\n',
            'type = ParentVarSet\n',
            f'trigger1 = var(2) = 11 - {ai_level_str}\n',
            f'trigger2 = var(2) = 10 - {ai_level_str}\n',
            'var(58) = var(1) ; <--- MOVED TO VAR(58) TO AVOID CONFLICT WITH CHAR VAR(56)\n',
            'ignorehitpause = 1\n',
            
            # Cooldown
            f'[State {current_helper_id}, VA]\n',
            'type = VarAdd\n',
            'trigger1 = var(2) > 0\n',
            'var(2) = -1\n',
            'ignorehitpause = 1\n',
            
            # Reset
            f'[State {current_helper_id}, PVS Clear]\n',
            'type = ParentVarSet\n',
            'trigger1 = var(2) <= 0\n',
            'var(58) = 0 ; <--- MOVED TO VAR(58)\n',
            'ignorehitpause = 1\n',

            # Destruction
            f'[State {current_helper_id}, Zeeky]\n',
            'type = DestroySelf\n',
            f'trigger1 = root,{ai_var} <= 0\n'
            
            f'\n; --- SIGNAL TRANSMISSION 2 ---\n',
            
            # PVS (Send)
            f'[State {current_helper_id}, PVS]\n',
            'type = ParentVarSet\n',
            # Send immediately if a decision is made
            'trigger1 = var(1) > 0\n',
            'var(58) = var(1) ; <--- MOVED TO VAR(58)\n',
            'ignorehitpause = 1\n',
            
            # Reset Internal State
            f'[State {current_helper_id}, Reset]\n',
            'type = VarSet\n',
            'trigger1 = 1\n',
            'var(1) = 0\n', 
            'ignorehitpause = 1\n',
            
            # Reset Parent Buffer (Safety)
            f'[State {current_helper_id}, PVS Clear]\n',
            'type = ParentVarSet\n',
            'trigger1 = root,var(58) > 0 ; <--- MOVED TO VAR(58)\n', 
            'trigger1 = root,stateno = root,var(58)\n', 
            'var(58) = 0\n',
            'ignorehitpause = 1\n',
            
            # Cooldown Management
            f'[State {current_helper_id}, VA]\n',
            'type = VarAdd\n',
            'trigger1 = var(2) > 0\n',
            'var(2) = -1\n',
            'ignorehitpause = 1\n',

            # Destruction
            f'[State {current_helper_id}, Zeeky]\n',
            'type = DestroySelf\n',
            f'trigger1 = root,{ai_var} <= 0\n'
        ]

        all_helper_defs.extend(helper_header + chunk_content + helper_footer)

    # 4. Return Main File Logic
    main_file_logic = [
        f"\n;==================================================\n",
        f";--- AI COMMAND EXECUTOR ---\n",
        f";==================================================\n",
        f"[State -3, AI Execution]\n",
        f"type = ChangeState\n",
        f"triggerall = {ai_var} > 0 && RoundState = 2\n",
        f"triggerall = var(58) > 0\n",
        # Allow combos, cancels, and raw movement
        f"triggerall = Ctrl || (StateNo=[100,105]) || MoveContact || 1\n",
        f"trigger1 = 1\n",
        f"value = var(58)\n",
        f"ignorehitpause = 1\n",
        f"\n",
        f"[State -3, AI Reset]\n",
        f"type = VarSet\n",
        f"trigger1 = var(58) > 0\n",
        f"v = 58\n",
        f"value = 0\n",
        f"ignorehitpause = 1\n"
    ]

    return main_file_logic, all_initializers, all_helper_defs
# Add this new function
def analyze_common_states(all_cns_files, cmd_file_path, stcommon_path, ai_var):
    """
    (V5.1 - STRICT MODE & NEGATIVE STATE FIX)
    Analyzes state files to identify movement states using ONLY:
    1. EXPLICIT COMMANDS (from CMD file, mapped to Statedef -1)
    2. EXPLICIT CONSTANTS (const(velocity.x.x)) found in CNS files.
    
    * FIX: Explicitly ignores Statedef -1, -2, and -3 (System States).
    """
    print("\n--- [V5.1 STRICT ANALYSIS] Running Command & Const Only Engine ---")
    
    movement_states = { 
        "walk_fwd": [], "walk_back": [], "run_fwd": [], "hop_back": [], 
        "jump_start": [], "air_jump": [], "air_dash_fwd": [], "air_dash_back": [],
        "guard_cancel_roll_fwd": [], "guard_cancel_roll_back": [] 
    }

    # Use the complete list of files passed from main
    files_to_scan = all_cns_files
    print(f"  -> Scanning {len(files_to_scan)} files: {', '.join(map(os.path.basename, files_to_scan))}")

    # --- REGEX COMPILATION ---
    p_statedef = re.compile(r'^\s*\[Statedef\s+(-?\d+)', re.I) #re.compile(r'\[Statedef[^\]]*?(-?\d+)[^\]]*\]', re.I)
    p_state_block = re.compile(r'\[State\s', re.I)
    
    # Validation Regex
    p_hitdef = re.compile(r'type\s*=\s*(hitdef|projectile|proj)', re.I) 
    
    # Command Parsing
    p_cmd_block_start = re.compile(r'^\s*\[Command\]', re.I)
    p_cmd_name = re.compile(r'^\s*name\s*=\s*"([^"]+)"', re.I)
    p_cmd_definition = re.compile(r'^\s*command\s*=\s*([~/$a-zA-Z0-9, +]+)', re.I)
    p_cmd_trigger = re.compile(r'command\s*=\s*"([^"]+)"', re.I)
    p_cmd_trigger_type = re.compile(r'trigger\d*\s*=\s*statetype\s*=\s*([SA])', re.I)
    p_type_in_statedef = re.compile(r'^\s*type\s*=\s*([SCAI])', re.I)

    # STRICT CONSTANTS
    p_const_walk_fwd = re.compile(r'const\(velocity\.walk\.fwd\.x\)', re.I)
    p_const_walk_back = re.compile(r'const\(velocity\.walk\.back\.x\)', re.I)
    p_const_run_fwd = re.compile(r'const\(velocity\.run\.fwd\.x\)', re.I)
    p_const_run_back = re.compile(r'const\(velocity\.run\.back\.x\)', re.I)
    p_const_jump = re.compile(r'const\(velocity\.jump\.y\)', re.I)
    p_const_runjump = re.compile(r'const\(velocity\.runjump\.y\)', re.I)
    p_const_airjump = re.compile(r'const\(velocity\.airjump\.y\)', re.I)
    p_const_airjump_fwd = re.compile(r'const\(velocity\.airjump\.fwd\.x\)', re.I)
    p_const_airjump_back = re.compile(r'const\(velocity\.airjump\.back\.x\)', re.I)

    all_states = {}
    command_definitions = {} 
    command_to_statenos = {} 

    # 1. READ ALL STATES (CNS/ST)
    for cns_file in files_to_scan:
        if not os.path.isfile(cns_file): continue
        content = read_unknown_encoding(cns_file)
        current_stateno = None
        current_block_lines = []
        
        for line in content:
            match = p_statedef.search(line)
            if match:
                if current_stateno is not None:
                    all_states[current_stateno] = {
                        'header': current_block_lines[0],
                        'body': "\n".join(current_block_lines)
                    }
                current_stateno = int(match.group(1))
                current_block_lines = [line]
            elif current_stateno is not None:
                current_block_lines.append(line)
        if current_stateno is not None:
             all_states[current_stateno] = {
                'header': current_block_lines[0],
                'body': "\n".join(current_block_lines)
            }

    # 2. PARSE CMD FILE
    if os.path.isfile(cmd_file_path):
        cmd_content = read_unknown_encoding(cmd_file_path)
        
        # Map Command Names -> Inputs
        in_cmd_def_block, current_cmd_name = False, None
        for line in cmd_content:
            line_cut = cut(line).strip()
            if p_cmd_block_start.search(line_cut): in_cmd_def_block, current_cmd_name = True, None
            if in_cmd_def_block:
                if (m := p_cmd_name.search(line_cut)): current_cmd_name = m.group(1).lower()
                if (m := p_cmd_definition.search(line_cut)) and current_cmd_name:
                    command_definitions[current_cmd_name] = m.group(1).upper().strip().replace(" ", "")
                    in_cmd_def_block = False

        # Map Command Names -> Target Statenos
        in_sys_block, current_block = False, []
        for line in cmd_content:
            line_cut = cut(line).strip()
            if not line_cut: continue
            if (m := p_statedef.search(line_cut)): 
                # Only look for triggers in Statedef -1, -2, -3
                in_sys_block = m.group(1) in ['-1', '-2', '-3']
                current_block = [] 
            
            if in_sys_block:
                if p_state_block.search(line_cut):
                    if current_block:
                        _process_cmd_block(current_block, command_to_statenos, p_cmd_trigger, p_cmd_trigger_type)
                    current_block = [line_cut]
                else:
                    current_block.append(line_cut)
        if current_block and in_sys_block:
            _process_cmd_block(current_block, command_to_statenos, p_cmd_trigger, p_cmd_trigger_type)

    # 3. ANALYSIS: COMMAND MATCHING
    print("  -> Running Command Pattern Matching...")
    
    # Remove Guard/Intro/Win/Lose states
    # We only remove Guard (120-159) and standard Win/Lose/Intros (170-199).
    # We keep the high numbers because that's where Air Dashes often live.
    statenos_to_remove = [s for s in all_states if (120 <= s <= 159) or (170 <= s <= 199)] #statenos_to_remove = [s for s in all_states if (120 <= s <= 159) or (170 <= s <= 199) or (s >= 5900)]
    for s in statenos_to_remove: 
        if s in all_states: del all_states[s]

    for cmd_name, targets in command_to_statenos.items():
        cmd_input = command_definitions.get(cmd_name, "")
        if not cmd_input: continue

        move_type = None
        if re.fullmatch(r'F,F', cmd_input, re.I): move_type = 'run_fwd' 
        elif re.fullmatch(r'B,B', cmd_input, re.I): move_type = 'hop_back'
        elif re.fullmatch(r'/\$F', cmd_input, re.I) or cmd_name == "holdfwd": move_type = 'walk_fwd'
        elif re.fullmatch(r'/\$B', cmd_input, re.I) or cmd_name == "holdback": move_type = 'walk_back'
        elif re.fullmatch(r'~?/?U/?([FB])?', cmd_input, re.I) or cmd_name == "holdup": move_type = 'jump_start'

        if not move_type: continue

        for target in targets:
            stateno = target['stateno']
            
            # --- CRITICAL FIX: Ignore references to negative states ---
            if stateno < 0: continue
            
            if stateno not in all_states: continue
            
            state_body = all_states[stateno]['body']
            if p_hitdef.search(state_body): continue
            
            is_air = target['is_air']
            header_type = p_type_in_statedef.search(all_states[stateno]['header'])
            if header_type and header_type.group(1).upper() == 'A': is_air = True

            final_key = move_type
            if is_air:
                if move_type == 'run_fwd': final_key = 'air_dash_fwd'
                elif move_type == 'hop_back': final_key = 'air_dash_back'
                elif move_type == 'jump_start': final_key = 'air_jump'
            
            if stateno not in movement_states[final_key]:
                movement_states[final_key].append(stateno)
                print(f"     [Strict-CMD] Identified {final_key}: {stateno} (Input: '{cmd_input}')")

    # 4. ANALYSIS: CONST MATCHING
    print("  -> Running Constant (CONST) Scanning...")
    
    for stateno, data in all_states.items():
        # --- CRITICAL FIX: NEVER classify -1, -2, -3 as movement ---
        # Statedef -2 often contains 'const(velocity.jump.y)' for math/AI,
        # but it is NOT the jump state.
        if stateno < 0: continue

        if any(stateno in s_list for s_list in movement_states.values()): continue
        
        body = data['body']
        
        if p_const_walk_fwd.search(body):
            _add_strict(movement_states['walk_fwd'], stateno, "walk_fwd (CONST)")
        
        if p_const_walk_back.search(body):
            _add_strict(movement_states['walk_back'], stateno, "walk_back (CONST)")

        if p_const_run_fwd.search(body):
            _add_strict(movement_states['run_fwd'], stateno, "run_fwd (CONST)")

        if p_const_run_back.search(body):
            _add_strict(movement_states['hop_back'], stateno, "hop_back (CONST)")

        if p_const_jump.search(body) or p_const_runjump.search(body):
            _add_strict(movement_states['jump_start'], stateno, "jump_start (CONST)")

        if p_const_airjump.search(body):
             _add_strict(movement_states['air_jump'], stateno, "air_jump (CONST)")

        if p_const_airjump_fwd.search(body):
            _add_strict(movement_states['air_dash_fwd'], stateno, "air_dash_fwd (CONST)")
        
        if p_const_airjump_back.search(body):
            _add_strict(movement_states['air_dash_back'], stateno, "air_dash_back (CONST)")

    print("--- [V5.1 STRICT ANALYSIS] Complete. ---")
    return movement_states

def _process_cmd_block(block_lines, cmd_map, p_trigger, p_type):
    """ Helper to extract stateno and commands from a block in Statedef -1 """
    block_str = "\n".join(block_lines)
    stateno = _findstateno_universal_parser(block_str)
    
    # Ensure we don't map commands to negative states accidentally
    if stateno is not None and stateno >= 0:
        is_air = False
        for line in block_lines:
            if (m := p_type.search(line)) and 'A' in m.group(1):
                is_air = True
                
        for match in p_trigger.finditer(block_str):
            cmd_name = match.group(1).lower()
            if cmd_name not in cmd_map: cmd_map[cmd_name] = []
            cmd_map[cmd_name].append({'stateno': stateno, 'is_air': is_air})

def _add_strict(target_list, stateno, log_name):
    if stateno not in target_list:
        target_list.append(stateno)
        print(f"     [Strict-CONST] Identified {log_name}: {stateno}")
        
def analyze_common_states_V2(all_cns_files, cmd_file_path, stcommon_path, ai_var):
    """
    (V5.1 - STRICT MODE & NEGATIVE STATE FIX)
    Analyzes state files to identify movement states using ONLY:
    1. EXPLICIT COMMANDS (from CMD file, mapped to Statedef -1)
    2. EXPLICIT CONSTANTS (const(velocity.x.x)) found in CNS files.
    
    * FIX: Explicitly ignores Statedef -1, -2, and -3 (System States).
    """
    print("\n--- [V5.1 STRICT ANALYSIS] Running Command & Const Only Engine ---")
    
    movement_states = { 
        "walk_fwd": [], "walk_back": [], "run_fwd": [], "hop_back": [], 
        "jump_start": [], "air_jump": [], "air_dash_fwd": [], "air_dash_back": [],
        "guard_cancel_roll_fwd": [], "guard_cancel_roll_back": [] 
    }

    # Use the complete list of files passed from main
    files_to_scan = all_cns_files
    print(f"  -> Scanning {len(files_to_scan)} files: {', '.join(map(os.path.basename, files_to_scan))}")

    # --- REGEX COMPILATION ---
    p_statedef = re.compile(r'^\s*\[Statedef\s+(-?\d+)', re.I) #re.compile(r'\[Statedef[^\]]*?(-?\d+)[^\]]*\]', re.I)
    p_state_block = re.compile(r'\[State\s', re.I)
    
    # Validation Regex
    p_hitdef = re.compile(r'type\s*=\s*(hitdef|projectile|proj)', re.I) 
    
    # Command Parsing
    p_cmd_block_start = re.compile(r'^\s*\[Command\]', re.I)
    p_cmd_name = re.compile(r'^\s*name\s*=\s*"([^"]+)"', re.I)
    p_cmd_definition = re.compile(r'^\s*command\s*=\s*([~/$a-zA-Z0-9, +]+)', re.I)
    p_cmd_trigger = re.compile(r'command\s*=\s*"([^"]+)"', re.I)
    p_cmd_trigger_type = re.compile(r'trigger\d*\s*=\s*statetype\s*=\s*([SA])', re.I)
    p_type_in_statedef = re.compile(r'^\s*type\s*=\s*([SCAI])', re.I)

    # STRICT CONSTANTS
    p_const_walk_fwd = re.compile(r'const\(velocity\.walk\.fwd\.x\)', re.I)
    p_const_walk_back = re.compile(r'const\(velocity\.walk\.back\.x\)', re.I)
    p_const_run_fwd = re.compile(r'const\(velocity\.run\.fwd\.x\)', re.I)
    p_const_run_back = re.compile(r'const\(velocity\.run\.back\.x\)', re.I)
    p_const_jump = re.compile(r'const\(velocity\.jump\.y\)', re.I)
    p_const_runjump = re.compile(r'const\(velocity\.runjump\.y\)', re.I)
    p_const_airjump = re.compile(r'const\(velocity\.airjump\.y\)', re.I)
    p_const_airjump_fwd = re.compile(r'const\(velocity\.airjump\.fwd\.x\)', re.I)
    p_const_airjump_back = re.compile(r'const\(velocity\.airjump\.back\.x\)', re.I)

    all_states = {}
    command_definitions = {} 
    command_to_statenos = {} 

    # 1. READ ALL STATES (CNS/ST)
    for cns_file in files_to_scan:
        if not os.path.isfile(cns_file): continue
        content = read_unknown_encoding(cns_file)
        current_stateno = None
        current_block_lines = []
        
        for line in content:
            match = p_statedef.search(line)
            if match:
                if current_stateno is not None:
                    all_states[current_stateno] = {
                        'header': current_block_lines[0],
                        'body': "\n".join(current_block_lines)
                    }
                current_stateno = int(match.group(1))
                current_block_lines = [line]
            elif current_stateno is not None:
                current_block_lines.append(line)
        if current_stateno is not None:
             all_states[current_stateno] = {
                'header': current_block_lines[0],
                'body': "\n".join(current_block_lines)
            }

    # 2. PARSE CMD FILE
    if os.path.isfile(cmd_file_path):
        cmd_content = read_unknown_encoding(cmd_file_path)
        
        # Map Command Names -> Inputs
        in_cmd_def_block, current_cmd_name = False, None
        for line in cmd_content:
            line_cut = cut(line).strip()
            if p_cmd_block_start.search(line_cut): in_cmd_def_block, current_cmd_name = True, None
            if in_cmd_def_block:
                if (m := p_cmd_name.search(line_cut)): current_cmd_name = m.group(1).lower()
                if (m := p_cmd_definition.search(line_cut)) and current_cmd_name:
                    command_definitions[current_cmd_name] = m.group(1).upper().strip().replace(" ", "")
                    in_cmd_def_block = False

        # Map Command Names -> Target Statenos
        in_sys_block, current_block = False, []
        for line in cmd_content:
            line_cut = cut(line).strip()
            if not line_cut: continue
            if (m := p_statedef.search(line_cut)): 
                # Only look for triggers in Statedef -1, -2, -3
                in_sys_block = m.group(1) in ['-1', '-2', '-3']
                current_block = [] 
            
            if in_sys_block:
                if p_state_block.search(line_cut):
                    if current_block:
                        _process_cmd_block(current_block, command_to_statenos, p_cmd_trigger, p_cmd_trigger_type)
                    current_block = [line_cut]
                else:
                    current_block.append(line_cut)
        if current_block and in_sys_block:
            _process_cmd_block(current_block, command_to_statenos, p_cmd_trigger, p_cmd_trigger_type)

    # 3. ANALYSIS: COMMAND MATCHING
    print("  -> Running Command Pattern Matching...")
    
    # Remove Guard/Intro/Win/Lose states
    # We only remove Guard (120-159) and standard Win/Lose/Intros (170-199).
    # We keep the high numbers because that's where Air Dashes often live.
    statenos_to_remove = [s for s in all_states if (120 <= s <= 159) or (170 <= s <= 199)] #statenos_to_remove = [s for s in all_states if (120 <= s <= 159) or (170 <= s <= 199) or (s >= 5900)]
    for s in statenos_to_remove: 
        if s in all_states: del all_states[s]

    for cmd_name, targets in command_to_statenos.items():
        cmd_input = command_definitions.get(cmd_name, "")
        if not cmd_input: continue

        move_type = None
        if re.fullmatch(r'F,F', cmd_input, re.I): move_type = 'run_fwd' 
        elif re.fullmatch(r'B,B', cmd_input, re.I): move_type = 'hop_back'
        elif re.fullmatch(r'/\$F', cmd_input, re.I) or cmd_name == "holdfwd": move_type = 'walk_fwd'
        elif re.fullmatch(r'/\$B', cmd_input, re.I) or cmd_name == "holdback": move_type = 'walk_back'
        elif re.fullmatch(r'~?/?U/?([FB])?', cmd_input, re.I) or cmd_name == "holdup": move_type = 'jump_start'

        if not move_type: continue

        for target in targets:
            stateno = target['stateno']
            
            # --- CRITICAL FIX: Ignore references to negative states ---
            if stateno < 0: continue
            
            if stateno not in all_states: continue
            
            state_body = all_states[stateno]['body']
            if p_hitdef.search(state_body): continue
            
            is_air = target['is_air']
            header_type = p_type_in_statedef.search(all_states[stateno]['header'])
            if header_type and header_type.group(1).upper() == 'A': is_air = True

            final_key = move_type
            if is_air:
                if move_type == 'run_fwd': final_key = 'air_dash_fwd'
                elif move_type == 'hop_back': final_key = 'air_dash_back'
                elif move_type == 'jump_start': final_key = 'air_jump'
            
            if stateno not in movement_states[final_key]:
                movement_states[final_key].append(stateno)
                print(f"     [Strict-CMD] Identified {final_key}: {stateno} (Input: '{cmd_input}')")

    # 4. ANALYSIS: CONST MATCHING
    print("  -> Running Constant (CONST) Scanning...")
    
    for stateno, data in all_states.items():
        # --- CRITICAL FIX: NEVER classify -1, -2, -3 as movement ---
        # Statedef -2 often contains 'const(velocity.jump.y)' for math/AI,
        # but it is NOT the jump state.
        if stateno < 0: continue

        if any(stateno in s_list for s_list in movement_states.values()): continue
        
        body = data['body']
        
        if p_const_walk_fwd.search(body):
            _add_strict(movement_states['walk_fwd'], stateno, "walk_fwd (CONST)")
        
        if p_const_walk_back.search(body):
            _add_strict(movement_states['walk_back'], stateno, "walk_back (CONST)")

        if p_const_run_fwd.search(body):
            _add_strict(movement_states['run_fwd'], stateno, "run_fwd (CONST)")

        if p_const_run_back.search(body):
            _add_strict(movement_states['hop_back'], stateno, "hop_back (CONST)")

        if p_const_jump.search(body) or p_const_runjump.search(body):
            _add_strict(movement_states['jump_start'], stateno, "jump_start (CONST)")

        if p_const_airjump.search(body):
             _add_strict(movement_states['air_jump'], stateno, "air_jump (CONST)")

        if p_const_airjump_fwd.search(body):
            _add_strict(movement_states['air_dash_fwd'], stateno, "air_dash_fwd (CONST)")
        
        if p_const_airjump_back.search(body):
            _add_strict(movement_states['air_dash_back'], stateno, "air_dash_back (CONST)")

    print("--- [V5.1 STRICT ANALYSIS] Complete. ---")
    return movement_states

