def inject_blank_actions_to_air(air_filepath):
    """
    Reads an AIR file, checks for the existence of specific blank actions,
    and appends them only if they are not found. This modifies the original file.
    """
    print("\n--- Checking and Injecting Actions into AIR File ---")
    if not os.path.isfile(air_filepath):
        print(f"ERROR: AIR file not found at '{air_filepath}'. Cannot inject actions.")
        return

    # Actions to check for and inject
    # We check for the header, which is a more reliable way to see if it's there
    action_9999_header = "[Begin Action 9999]"
    action_20218_header = "[Begin Action 20218]"

    action_9999_content = [
        "\n; --- Appended by AI Generator for Helper States ---\n",
        "; Blank Animation for Invisible Helpers\n",
        "[Begin Action 9999]\n",
        "-1,0, 0,0, 0 ;-1 ;10\n"
    ]
    action_20218_content = [
        "\n; Blank Animation for Specific Effects\n",
        "[Begin Action 20218]\n",
        "-1,0, 0,0, 0\n"
    ]

    try:
        # Read the entire file content first to perform checks
        with open(air_filepath, 'r', encoding='utf-8', errors='surrogateescape') as f:
            content = f.read()

        action_9999_exists = action_9999_header in content
        action_20218_exists = action_20218_header in content
        
        actions_to_append = []

        if not action_9999_exists:
            actions_to_append.extend(action_9999_content)
            print("Action 9999 not found. Queued for injection.")
        else:
            print("Action 9999 already exists. Skipping.")

        if not action_20218_exists:
            actions_to_append.extend(action_20218_content)
            print("Action 20218 not found. Queued for injection.")
        else:
            print("Action 20218 already exists. Skipping.")

        # If we have anything to add, open the file in append mode and write it
        if actions_to_append:
            with open(air_filepath, 'a', encoding='utf-8', errors='surrogateescape') as f:
                f.writelines(actions_to_append)
            print(f"Successfully injected missing actions into: {os.path.basename(air_filepath)}")
        else:
            print("All required actions are already present. No changes made to AIR file.")

    except Exception as e:
        print(f"ERROR: Could not read or write to {air_filepath}. Error: {e}")
# <<<--- END OF ADDITION --- >>>

def write_ai_file(filename, statenolist):
    """
    Generates a .ai file listing all states the AI can use.
    MUGEN's default AI can use this file to make basic decisions.
    """
    try:
        with open(filename, 'w', encoding='utf-8', errors='surrogateescape') as f:
            f.write("; AI file generated by AI Combined v1.2 (Improved)\n")
            f.write("[State -1]\n")
            # Create a sorted, unique list of states
            unique_states = sorted(list(set(statenolist)))
            for i, stateno in enumerate(unique_states, 1):
                f.write(f"trigger{i} = 1\n")
                f.write(f"stateno = {stateno}\n")
            f.write("\n")
        print(f"Generated AI file: {filename}")
    except Exception as e:
        print(f"Warning: Could not write AI file {filename}. Error: {e}")
                      
