def _generate_x_triggers_omniscient(analysis, reach, stateattr, spawner_data, velx, velstart, p2x1, p2x2, xscale, groundfront, groundback, airfront, airback, reach_time, midposy, aihelperID):
    """
    (V34 OMNI-FUSION EXACT) Ultimate X-axis trigger engine.
    Omits legacy groundfront/airfront modification (Code 2) to maintain absolute hitbox precision 
    for varied spawn points and up-close combat. Seamlessly merges Code 1's impeccable 
    velocity matrix with Omni-Adaptive dynamic weighting.
    """
    px = ""
    spawner_type = spawner_data.get('type', 'p1') if spawner_data else 'p1'

    reach_time = int(reach_time or (reach[0] if reach else 0))
    velstart = int(velstart) if velstart is not None else 0
    try:
        effective_velx = float(velx) if velx is not None else 0.0
    except (TypeError, ValueError):
        effective_velx = 0.0

    # Standard AI Level variable for MUGEN
    #ai_var = "var(59)" 

    # --- OMNI-ADAPTIVE DYNAMIC WEIGHTING ---
    pred_weight = "((0.4 + (0.05 * %s)) * (1.0 - (ifelse(%d.0 < 20.0, %d.0, 20.0) / 50.0)))" % (ai_var, reach_time, reach_time)

    if spawner_type == 'p2':
        px += "triggerall = (NumEnemy > 0) && (Enemynear, Alive)\n"
        px += "triggerall = ((p2dist x) < 400)\n"
        px += "triggerall = (p2bodydist x) = [(%d * const(size.xscale)), (%d * const(size.xscale))]\n" % (p2x1, p2x2)
        return px

    elif spawner_type in ['front', 'back', 'left', 'right']:
        if spawner_type == 'front': px += "triggerall = (EnemyNear, (ScreenPos X) >= 0) && ((P2Dist X) > 0)\n"
        elif spawner_type == 'back': px += "triggerall = (EnemyNear, (ScreenPos X) <= (IfElse(GameWidth, GameWidth, (BackEdgeDist + FrontEdgeDist)))) && ((P2Dist X) < 0)\n"
        elif spawner_type == 'left': px += "triggerall = (EnemyNear, (ScreenPos X) < (IfElse(GameWidth, GameWidth, (BackEdgeDist + FrontEdgeDist)) / 2))\n"
        elif spawner_type == 'right': px += "triggerall = (EnemyNear, (ScreenPos X) > (IfElse(GameWidth, GameWidth, (BackEdgeDist + FrontEdgeDist)) / 2))\n"
        return px

    if reach_time > 0:
        # Constantly updating predictive X-offset string
        pred_x = "((p2statetype=A || statetype=A) * %d * (enemynear,vel x) * %s)" % (reach_time, pred_weight)

        if p2x1 <= 0:
            if effective_velx == 0.0 and velstart < reach_time:
                if velstart == 0:
                    px += "triggerall = p2dist x >= %s * (enemynear,frontedgedist>10 && enemynear,backedgedist>10) && p2bodydist x <= (%d * const(size.xscale)) + %s\n" % (pred_x, p2x2, pred_x)
                else:
                    px += "triggerall = p2dist x >= (%d * (vel x) + %s) * (enemynear,frontedgedist>10 && enemynear,backedgedist>10) && p2bodydist x <= (%d * const(size.xscale)) + %d * (vel x) + %s\n" % (velstart, pred_x, p2x2, velstart, pred_x)
            
            # --- RESTORED: Custom Velocity Displacement Matrix (Code 1 Timing) ---
            elif effective_velx != 0.0 and velstart < reach_time:
                own_dist = int(reach_time * effective_velx) # Full velocity calculation from Code 1
                if velstart == 0:
                    px += "triggerall = p2dist x >= (%d + %s) * (enemynear,frontedgedist>10 && enemynear,backedgedist>10) && p2bodydist x <= (%d * const(size.xscale)) + %d + %s\n" % (own_dist, pred_x, p2x2, own_dist, pred_x)
                else:
                    velchangetime = reach_time - velstart
                    own_vel_dist = int(velchangetime * effective_velx)
                    px += "triggerall = p2dist x >= (%d + %d * (vel x) + %s) * (enemynear,frontedgedist>10 && enemynear,backedgedist>10) && p2bodydist x <= (%d * const(size.xscale)) + %d * (vel x) + %d + %s\n" % (own_vel_dist, velstart, pred_x, p2x2, velstart, own_vel_dist, pred_x)
            
            else:
                px += "triggerall = p2dist x >= (%d * (vel x) + %s) * (enemynear,frontedgedist>10 && enemynear,backedgedist>10) && p2bodydist x <= (%d * const(size.xscale)) + %d * (vel x) + %s\n" % (reach_time, pred_x, p2x2, reach_time, pred_x)
        else:
            if effective_velx == 0.0 and velstart < reach_time:
                if velstart == 0:
                    px += "triggerall = p2bodydist x - %s = [(%d * const(size.xscale)), (%d * const(size.xscale))]\n" % (pred_x, p2x1, p2x2)
                else:
                    px += "triggerall = p2bodydist x - %d * (vel x) - %s = [(%d * const(size.xscale)), (%d * const(size.xscale))]\n" % (velstart, pred_x, p2x1, p2x2)
            else:
                px += "triggerall = (p2bodydist x - %s) = [(%d * const(size.xscale)), (%d * const(size.xscale))]\n" % (pred_x, p2x1, p2x2)
    else:
        if p2x1 != 0:
            px += "triggerall = p2bodydist x = [(%d * const(size.xscale)), (%d * const(size.xscale))]\n" % (p2x1, p2x2)
        else:
            px += "triggerall = p2dist x >= 0\n"
            px += "triggerall = p2bodydist x <= (%d * const(size.xscale))\n" % (p2x2)

    return px


def _generate_y_triggers_omniscient(analysis, reach, stateattr, spawner_data, vely, velstart, p2y1, p2y2, yscale, reach_time, reach_time1, midposy, aihelperID, localcoord_scale=1.0):
    """
    (V34 OMNI-FUSION EXACT) Ultimate Y-axis trigger engine.
    Retains Code 1's precision altitude/gravity matrices and eliminates Code 2's bounds corruption.
    Uses precise physics prediction via Helper vars (37, 39).
    """
    py = ""
    pyh = ""

    reach_time = int(reach_time or (reach[0] if reach else 0))
    reach_time1 = int(reach_time1 or (reach_time + 1))
    velstart = int(velstart) if velstart is not None else 0
    try:
        effective_vely = float(vely) if vely is not None else 0.0
    except (TypeError, ValueError):
        effective_vely = 0.0

    #ai_var = "var(59)"

    # --- OMNI-ADAPTIVE DYNAMIC WEIGHTING (Y-AXIS) ---
    pred_weight_y = "((0.35 + (0.05 * %s)) * (1.0 - (ifelse(%d.0 < 15.0, %d.0, 15.0) / 45.0)))" % (ai_var, reach_time, reach_time)
    pred_y = "(%d * (enemynear,vel y) * %s)" % (reach_time, pred_weight_y)

    #yaccel_val = "(IfElse(NumHelper({id}), (helper({id}),fvar(39) - helper({id}),fvar(37)), IfElse((Enemynear, MoveType = H), (Enemynear, GetHitVar(yaccel)), (Enemynear, Const(movement.yaccel)))))".format(id=aihelperID) 
    #ydiff_val = "(IfElse(NumHelper({id}), ((helper({id}),fvar(39) - helper({id}),fvar(37)) - IfElse((Enemynear, MoveType = H), (Enemynear, GetHitVar(yaccel)), (Enemynear, Const(movement.yaccel)))), 0))".format(id=aihelperID) 

    # This represents the actual, CURRENT vertical acceleration of the enemy
    yaccel_val = "(IfElse(NumHelper({id}), helper({id}),fvar(39), IfElse(Enemynear,MoveType=H, Enemynear,GetHitVar(yaccel), Enemynear,Const(movement.yaccel))))".format(id=aihelperID)

    # This represents the DIFFERENCE between your acceleration and the enemy's
    # This is the "secret sauce" for aerial combo precision
    ydiff_val = "(IfElse(NumHelper({id}), (helper({id}),fvar(39) - helper({id}),fvar(37)), 0))".format(id=aihelperID)

    if reach_time > 6 and stateattr[1] == 'A' and effective_vely != 0:
        py += "triggerall = (pos Y + %d * (vel y) + const(movement.yaccel) * %d * %d * 0.5) < 0\n" % (reach_time, reach_time, reach_time + 1)

    p2height = p2y2
    if p2height is not None and p2height < 0:
        p2height = int(p2height * localcoord_scale)
        
    if p2height is not None and p2height < -20 and stateattr[1] != 'A':
        safety = "triggerall = (!numhelper({id})) || (helper({id}),var(16) <= {h})\n".format(id=aihelperID, h=p2height)
        py += safety
        pyh += safety

    if stateattr[1] != 'A':
        if reach_time > 1:
            py += "triggerall = p2bodydist y + %s + %s * %d * %d * 0.5 >= (%d * const(size.yscale))\n" % (pred_y, yaccel_val, reach_time, reach_time1, p2y1)
            pyh += "triggerall = (p2statetype != A) || (p2bodydist y + %s + %s * %d * %d * 0.5 = [(%d * const(size.yscale)), -1])\n" % (pred_y, yaccel_val, reach_time, reach_time1, p2y1)
        else:
            py = pyh = "triggerall = (p2statetype != A) || (p2bodydist y = [(%d * const(size.yscale)), (%d * const(size.yscale))])\n" % (p2y1, p2y2)

        if stateattr[3] is not None and '-A' in stateattr[3]:
            py = pyh = "triggerall = p2statetype != A\n"
            
    else:
        if reach_time > 0:
            if effective_vely == 0.0 and velstart < reach_time:
                py = pyh = "triggerall = p2bodydist y + %s + {ydiff} * {rt} * {rt1} * 0.5 = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(rt=reach_time, rt1=reach_time1, ydiff=ydiff_val, y1=p2y1, y2=p2y2) % (pred_y)
            
            # --- RESTORED: Aerial Trajectory w/ Custom Velocity matrix (Code 1 Timing) ---
            elif effective_vely != 0.0 and velstart < reach_time:
                own_dist_y = int(effective_vely * reach_time)
                py = pyh = "triggerall = p2bodydist y - %d + %s + {ydiff} * {rt} * {rt1} * 0.5 = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(rt=reach_time, rt1=reach_time1, ydiff=ydiff_val, y1=p2y1, y2=p2y2) % (own_dist_y, pred_y)
            
            else:
                py = pyh = "triggerall = p2bodydist y - {rt} * (vel y) + %s + {ydiff} * {rt} * {rt1} * 0.5 = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(rt=reach_time, rt1=reach_time1, ydiff=ydiff_val, y1=p2y1, y2=p2y2) % (pred_y)
        
        elif reach_time == 1:
            if effective_vely == 0.0 and velstart < reach_time:
                py = pyh = "triggerall = p2bodydist y + (enemynear,vel y) + {ydiff} = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(ydiff=ydiff_val, y1=p2y1, y2=p2y2)
            
            elif effective_vely != 0.0 and velstart < reach_time:
                py = pyh = "triggerall = p2bodydist y - %d + (enemynear,vel y) + {ydiff} = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(ydiff=ydiff_val, y1=p2y1, y2=p2y2) % (int(effective_vely))
            
            else:
                py = pyh = "triggerall = p2bodydist y - (vel y) + (enemynear,vel y) + {ydiff} = [({y1} * const(size.yscale)), ({y2} * const(size.yscale))]\n".format(ydiff=ydiff_val, y1=p2y1, y2=p2y2)
        else:
            py = pyh = "triggerall = p2bodydist y = [(%d * const(size.yscale)), (%d * const(size.yscale))]\n" % (p2y1, p2y2)

    return py, pyh
   
def calculate_py_triggers(state, trigger, velx, velstart, vely, attacktype, analysis, reach, stateattr, localcoord_scale, xscale, yscale, groundfront, groundback, airfront, airback, midposy, aihelperID, ai_var):
    """
    (OMNI-COMPETENT V9 - CONTEXT-AWARE TRIGGER AUTHORITY)
    Intelligently calculates and bundles X (px) and Y (py) triggers based on
    the specific needs of the move. It is self-aware of range, tracking type,
    and screen coverage to avoid redundant or restrictive triggers.
    
    RETURNS:
        tuple: (trigger_string_1, trigger_string_2)
        - trigger_string_1: Used for general execution (e.g., standard attacks).
        - trigger_string_2: Used for high-precision scenarios (e.g., combos).
    """
    
    # --- INITIALIZATION & SAFEGUARDS ---
    px_generated, py_generated, pyh_generated = "", "", ""
    _px_patch = "" 

    try:
        # --- 0. GLOBAL ANALYSIS CACHE & SAFETY CHECK ---
        if not analysis: pass
        stateno = analysis.get('stateno', 0) if isinstance(analysis, dict) else 0
        
        current_analysis = {}
        try:
            current_analysis = GLOBAL_ANALYSIS_CACHE.get(stateno, analysis)
        except NameError:
            current_analysis = analysis
        
        if not current_analysis: current_analysis = {}

        # =========================================================================
        # --- 1. HIGH-PRECISION PHYSICS SUBSTITUTION (OMNISCIENT V4) ---
        # =========================================================================
        # This version perfectly translates simulated physics back into 
        # trigger-compatible "Effective Velocity."
        # If physics engine calculated specific displacement, use it.
        # =========================================================================

        if analysis and reach[0] is not None and reach[0] > 0:
            # --- X-AXIS PRECISION ---
            if 'dynamic_reach_x' in analysis:
                # The 'dynamic_reach_x' is the total simulated pixels traveled.
                # We derive the 'Effective Velocity' by seeing how many pixels 
                # were moved per tick on average.
                true_displacement_x = float(analysis['dynamic_reach_x'])
                
                # OMNI-FIX: Calculate velocity from the RESULT of simulation, not the raw input
                effective_vel_x = true_displacement_x / float(reach[0])
                
                # Only substitute if the movement is significant
                if abs(effective_vel_x - velx) > 0.01:
                    # print(f"      L-> Precision Fix: Substituting raw Vel X ({velx}) with True Simulated Vel X ({effective_vel_x:.4f})")
                    velx = effective_vel_x
                    # Force velstart to 0 because the effective velocity accounts for the whole duration
                    velstart = 0 

            # --- Y-AXIS PRECISION ---
            if 'dynamic_reach_y' in analysis:
                # Gravity makes Y-axis displacement non-linear.
                # We calculate the effective linear velocity required to reach that point.
                true_displacement_y = float(analysis['dynamic_reach_y'])
                effective_vel_y = true_displacement_y / float(reach[0])
                
                if abs(effective_vel_y - vely) > 0.01:
                    # print(f"      L-> Precision Fix: Substituting raw Vel Y ({vely}) with True Simulated Vel Y ({effective_vel_y:.4f})")
                    vely = effective_vel_y
                    # Note: We keep the gravity logic in the trigger generator, 
                    # this just ensures the 'starting point' is correct.

        # --- PRELIMINARY DATA VALIDATION ---
        if not current_analysis or not reach or reach[2] is None or not stateattr:
            return "", ""
        
        # --- OMNI-AWARENESS: UTILITY BYPASS ---
        # If the move is a non-offensive Utility (Heal/Install/Transform), we return 
        # empty strings immediately. Spatial triggers (px/py) only hinder these moves.
        #if analysis.get('is_transformation') or analysis.get('is_healing_move') or attacktype in ['install', 'heal', 'buff', 'power_charge']:
        #    return "; Omni-Awareness: Spatial Triggers disabled for Utility Move\n", "; Omni-Awareness: Spatial Triggers disabled for Utility Move\n"

        # Prepare timing variables
        reach_time = reach[0] or 0
        reach_time1 = reach_time + 1


            
        # =========================================================================
        # --- [V25 OMNISCIENT] SPAWNER, SCALE & CONTEXT ANALYSIS ---
        # =========================================================================
        # This engine calculates the "Physical Presence" of the attack by fusing
        # local coordinate resolution (localcoord), internal scaling (xscale/yscale),
        # and projected velocity/travel distance (reach). It uses this data to
        # intelligently decide if distance triggers are even necessary.
        # =========================================================================
        
        # --- 1. Determine Spawner Context ---
        # =========================================================================
        # --- [V26.6 OMNISCIENT] DYNAMIC SCALE & RESOLUTION CONTEXT ENGINE ---
        # =========================================================================
        # This engine calculates the "Physical Presence" of the attack by factoring
        # local coordinate resolution (localcoord), internal scaling (xscale),
        # and projected velocity/travel distance (reach). 
        #
        # OMNI-FIX: This version explicitly handles the "MJ Paradox" where a 
        # high-resolution coordinate character might have a small visual presence 
        # due to low xscale/yscale, preventing premature trigger removal.
        # =========================================================================

        ignore_x = False
        ignore_y = False
        
        # --- 1. Determine Spawner Context ---
        spawner = current_analysis.get('spawner')
        spawner_type = 'p1' # Default to self-relative
        if spawner and isinstance(spawner, dict):
            spawner_type = str(spawner.get('type', 'p1')).lower()

        # --- 2. Tracking & Targeting Context ---
        # spawner_type 'p2' (spawns on enemy) means distance is always 0 effectively.
        is_tracking = (spawner_type == 'p2')

        if is_tracking:
            ignore_x = True # Usually tracks X
            ignore_y = True # Usually tracks Y
            # Y might still need checking if it's an air-only tracker

        # --- 8. Master Trigger Logic Sync ---
        # Preserves the legacy 'ignore' flags for the subsequent trigger generators.
        # (This ensures parallel hitdef/helper/proj logic uses the same context)
        analysis['ignore_x_dist'] = ignore_x
        analysis['ignore_y_dist'] = ignore_y

        """# --- 2. Calculate Effective Screen Dimensions in Local Units ---
        # We extract the true resolution from localcoord_scale.
        # localcoord_scale = (320 / localcoord_width). 
        # If the divisor is 0.25 (720p), the screen width is 1280 local units.
        res_divisor_x = localcoord_scale if (localcoord_scale and localcoord_scale > 0) else 1.0
        # For Y, standard MUGEN is 240. We derive height similarly.
        eff_screen_w = (320.0 / res_divisor_x)
        eff_screen_h = (240.0 / res_divisor_x) # Using X-scale for height is MUGEN standard for aspect ratio

        # --- 3. Factor in Character's Internal Multipliers ---
        # These are the multipliers from the [Size] section of the CNS.
        adj_xscale = xscale if (xscale not in [None, 0]) else 1.0
        adj_yscale = yscale if (yscale not in [None, 0]) else 1.0

        # --- 4. Calculate the "Physical Footprint" of the Attack ---
        # This is the real-world pixel size of the hitbox as it appears on screen.
        # reach[3]-reach[2] = raw coordinate width. 
        # physical_presence = (Raw Units * Character Scale).
        raw_range_x = abs((reach[3] or 0) - (reach[2] or 0))
        raw_range_y = abs((reach[5] or 0) - (reach[4] or 0))
        
        physical_presence_x = raw_range_x * adj_xscale
        physical_presence_y = raw_range_y * adj_yscale

        # --- 5. DYNAMIC COVERAGE HEURISTICS (SCALE-AWARE) ---
        # Instead of a hardcoded 320/240, we compare the scaled attack 
        # against the resolution-adjusted screen width/height.
        #
        # Logic: If (BoxWidth * MJ_Scale) / ScreenWidth >= 80%, ignore triggers.
        coverage_ratio_x = physical_presence_x / eff_screen_w
        coverage_ratio_y = physical_presence_y / eff_screen_h

        # A move is "Omnipresent" (ignore distance) only if it fills the screen visually.
        ignore_x = (coverage_ratio_x >= 0.8) 
        ignore_y = (coverage_ratio_y >= 0.8)

        # --- 6. Tracking & Targeting Context ---
        # spawner_type 'p2' (spawns on enemy) means distance is always 0 effectively.
        is_tracking = (spawner_type == 'p2')
        
        # Projectile context-awareness
        if attacktype in ['proj', 'projectile', 'striker_helper']:
             # Check for infinite projectiles (Traps)
             if 'projremovetime = -1' in str(statedef).lower():
                 # Traps cover space over time, but still need X-dist unless they fill the screen
                 is_tracking = (coverage_ratio_x >= 0.5) 
             # Check for "Sniper" velocity (Speed vs Screen Resolution)
             # A projectile is a sniper if it crosses 50% of the screen in < 10 ticks.
             elif velx is not None:
                 screen_pixels_per_tick = abs(velx) * adj_xscale
                 if (screen_pixels_per_tick * 10) > (eff_screen_w * 0.5):
                     is_tracking = True 

        if is_tracking:
            ignore_x = True
            # Y is only ignored if the vertical presence covers the jumping arc (~50% screen)
            if coverage_ratio_y > 0.5:
                ignore_y = True
        
        # --- 7. Final Precision Sanity Check (The MJ Small-Scale Protector) ---
        # Even if the math says ignore, if the visual footprint is smaller than a 
        # standard character width (approx 50-60 pixels), we FORCE triggers back on.
        # This prevents MJ from firing tiny webs from across the stage.
        if physical_presence_x < (60.0): ignore_x = False
        if physical_presence_y < (60.0): ignore_y = False

        # --- 8. Master Trigger Logic Sync ---
        # Preserves the legacy 'ignore' flags for the subsequent trigger generators.
        # (This ensures parallel hitdef/helper/proj logic uses the same context)
        analysis['ignore_x_dist'] = ignore_x
        analysis['ignore_y_dist'] = ignore_y"""
        
        # print(f"  [Omni-Context] Stateno {stateno}: VisualWidth: {physical_presence_x:.1f}px | ScreenWidth: {eff_screen_w:.0f}px | Coverage: {coverage_ratio_x*100:.1f}% | IgnoreX: {ignore_x}")

        #if is_tracking:
        #    ignore_x = True # Usually tracks X
        #    ignore_y = True # Usually tracks Y
            # Y might still need checking if it's an air-only tracker

        # --- [ONE-AND-DONE FIX] GUARANTEED PX INJECTION PREP ---
        if reach[2] is not None and not ignore_x:
            _fix_x1 = current_analysis.get('corrected_p2x1', 0)
            _fix_x2 = current_analysis.get('corrected_p2x2', 60)

            if xscale not in [None, 0, 1]:
                _fix_x1, _fix_x2 = int(_fix_x1 * xscale), int(_fix_x2 * xscale)
            
            if _fix_x2 < _fix_x1: _fix_x1, _fix_x2 = _fix_x2, _fix_x1

            if _fix_x1 != 0:
                _px_patch = f"triggerall = p2bodydist x = [{_fix_x1}*const(size.xscale), {_fix_x2}*const(size.xscale)]\n"
            else:
                _px_patch = f"triggerall = p2dist x >= 0 && p2bodydist x <= {_fix_x2}*const(size.xscale)\n"

        # =========================================================================
        # --- OMNI-LINK CHAIN HUNTER (THE DEFINITIVE CHAIN RESOLVER V4) ---
        # =========================================================================
        # Bridges empty "Trigger" states to their "Meat" (Action) states while
        # preserving timing, velocity, and loop-prevention.
        # =========================================================================

        if reach[2] is None and stateno >= 200 and stateno != nextstate and nextstate is not None and changestatetime is not None:
            # 1. Initialize Loop Prevention & Context
            nextstate_list = [stateno, nextstate]
            current_hunt_state = nextstate
            
            # Preserve the initial totaltime of the starting state for offset math
            initial_totaltime = totaltime 

            while current_hunt_state is not None and stateno != current_hunt_state and current_hunt_state >= 200 and reach[2] is None:
                # 2. Deep Scan the Linked State
                # FIXED: Pass all required arguments to match the amalgamated state_read signature
                _read_res = state_read(current_hunt_state, newstfiles, actionlist, cached_cns_data)
                if not _read_res: break
                
                # Unpack: (attacktype, stateattr, reach, attr, [spawner_info])
                c_type, c_stateattr, c_reach, c_attr_str = _read_res[:4]
                c_reach = list(c_reach) # Convert to list for mutable timing adjustments
                
                # 3. Apply Timing Shifts (Legacy Offset Math)
                # This converts the child's local timing into the parent's global timing
                if changestatetime >= 0:
                    if c_reach[0] is not None: c_reach[0] = c_reach[0] + changestatetime
                    if c_reach[1] is not None: c_reach[1] = c_reach[1] + changestatetime
                elif changestatetime < 0 and initial_totaltime is not None:
                    # Handles triggers like [State ..., ChangeState] trigger1 = AnimTime = 0
                    offset_delay = initial_totaltime + changestatetime + 1
                    if c_reach[0] is not None: c_reach[0] = c_reach[0] + offset_delay
                    if c_reach[1] is not None: c_reach[1] = c_reach[1] + offset_delay

                # 4. SUCCESS: Meat Found
                if c_reach[2] is not None:
                    reach = c_reach
                    attacktype = c_type
                    attr = c_attr_str
                    
                    # --- CRITICAL PHYSICS INHERITANCE ---
                    # Parent must inherit the child's velocity attributes to calculate accurate reach
                    stateattr = list(stateattr) # Ensure list type
                    stateattr[11] = c_stateattr[11] # Copy Vel X
                    stateattr[12] = c_stateattr[12] # Copy Vel X Attr
                    stateattr[13] = c_stateattr[13] # Copy Vel Y
                    stateattr[14] = c_stateattr[14] # Copy Vel Y Attr
                    
                    # Update local velocity variables for the main generator scope
                    velx = float(stateattr[11]) if stateattr[11] is not None else 0.0
                    vely = float(stateattr[13]) if stateattr[13] is not None else 0.0
                    break
                    
                # 5. Iterative Chain Progression (If no hitbox yet)
                # Check if the child state itself has a NextState transition
                if c_stateattr[17] is not None and c_stateattr[17] >= 200:
                    next_link = c_stateattr[17]
                    
                    # Loop check (Stop if we've seen this state in this specific chain before)
                    if next_link in nextstate_list:
                        break
                    
                    nextstate_list.append(next_link)
                    
                    # Update the chain timing for the next hop
                    # c_stateattr[18] is the changestatetime of the CHILD
                    child_jump_time = c_stateattr[18]
                    child_total_time = c_reach[1]
                    
                    if child_jump_time is not None:
                        if child_jump_time >= 0:
                            changestatetime += child_jump_time
                        elif child_total_time is not None:
                            changestatetime += child_total_time + child_jump_time + 1
                    
                    # Move to next state in chain
                    current_hunt_state = next_link
                    initial_totaltime = child_total_time # Set context for next negative offset math
                else:
                    # End of chain branch
                    break

        # =========================================================================
        # --- END: OMNI-LINK CHAIN HUNTER ---
        # =========================================================================
        # =========================================================================
        # --- 2. UNIFIED RANGE CALCULATION (SYNTHESIS V4 - OMNI-SCALED) ---
        # =========================================================================
        # This engine fuses static scale-aware math with dynamic displacement logic.
        # It handles custom character widths, xscale multipliers, and recursive
        # velocity-based reach adjustments in a single parallel pass.
        # =========================================================================
        if reach[2] is not None:
            # 1. Prepare Environment & Scaling Factors
            is_air = (stateattr[1] == 'A')
            base_p2x1, base_p2x2 = 0, 0
            
            # Determine effective front/back widths based on state type
            curr_front = airfront if is_air else groundfront
            curr_back = airback if is_air else groundback
            
            # Apply X-Scale Multiplier if present (Handles non-standard character sizes)
            scale_val = xscale if (xscale not in [None, 0, 1]) else 1
            scaled_start = reach[2] * scale_val
            scaled_end = reach[3] * scale_val

            # 2. Static Bound Calculation (Front-Edge & Cross-up Logic)
            # Calculate P2X2 (The leading edge of the attack)
            base_p2x2 = scaled_end - curr_front
            
            # Calculate P2X1 (The trailing/origin edge with Cross-up detection)
            if scaled_start < 0 and abs(scaled_start) > curr_back:
                # Move is a cross-up (origin is behind character)
                base_p2x1 = scaled_start + curr_back
            elif scaled_start >= curr_back + 10:
                # Origin is significantly in front of the character axis
                base_p2x1 = scaled_start - curr_back
            else:
                # Move effectively starts at the character's axis
                base_p2x1 = 0

            # 3. Static Y-Bound Logic (Melee vs. Aerial Geometry)
            if not is_air:
                # Ground states use standard HitBox Y-heights
                base_p2y1, base_p2y2 = reach[4], reach[5]
            else:
                # Air states calculate reach relative to the character's Hurtbox position
                # This ensures the AI understands "Reach" as the gap between boxes.
                p2y1_base = reach[4] if reach[7] is None else (reach[4] - reach[7])
                p2y2_base = reach[5] if reach[6] is None else (reach[5] - reach[6])
                base_p2y1 = p2y1_base
                base_p2y2 = p2y2_base

            # 4. DYNAMIC DISPLACEMENT INTEGRATION (ADVANCED VELOCITY SYNC)
            # If the state-reader found valid velocity/acceleration data, we 
            # override the static bounds with "True Pathing" reach.
            dynamic_displacement = {'x': 0, 'y': 0}
            
            if current_analysis and current_analysis.get('corrected_p2x2') is not None:
                try:
                    # External calls to the dynamic math engine
                    dynamic_displacement = calculate_dynamic_reach(current_analysis)
                    final_range = calculate_full_dynamic_range(current_analysis, dynamic_displacement)
                    
                    # Inherit dynamic values
                    p2x1, p2x2 = final_range['x1'], final_range['x2']
                    p2y1, p2y2 = final_range['y1'], final_range['y2']
                except (NameError, KeyError, Exception):
                    # Fallback to scaled static bounds on engine error
                    p2x1, p2x2 = base_p2x1, base_p2x2
                    p2y1, p2y2 = base_p2y1, base_p2y2
            else:
                # No dynamic data available; use optimized static bounds
                p2x1 = base_p2x1
                p2x2 = base_p2x2
                p2y1 = base_p2y1
                p2y2 = base_p2y2

            # --- 4. SCALING AND REVERSAL ADJUSTMENTS ---
            if attacktype == "reversal":
                p2x1, p2x2, p2y1, p2y2 = p2x1 - 20, p2x2 + 20, p2y1 - 20, p2y2 + 20

            if xscale not in [None, 0, 1]:
                if p2x1 is not None: p2x1 = int(p2x1 * xscale)
                if p2x2 is not None: p2x2 = int(p2x2 * xscale)
            if yscale not in [None, 0, 1]:
                if p2y1 is not None: p2y1 = int(p2y1 * yscale)
                if p2y2 is not None: p2y2 = int(p2y2 * yscale)

            # Sanity check to prevent inverted ranges
            if p2x2 < p2x1: p2x1, p2x2 = p2x2, p2x1
            if p2y2 < p2y1: p2y1, p2y2 = p2y2, p2y1

            # --- [V35 OMNI-ADAPTIVE] RANGE PADDING ENGINE ---
            # Automatically expands ranges that are too narrow to be reliable.
            # Base windows are calculated for standard 320x240 MUGEN logic.
            min_x_window = int(35 * localcoord_scale)
            min_y_window = int(30 * localcoord_scale)
            
            # Dynamic Buffer: Slower moves need wider windows due to tracking latency.
            #startup_buffer = (reach_time // 3) 
            #target_x_window = min_x_window + startup_buffer
            #target_y_window = min_y_window + startup_buffer

            # Dynamic Buffer REMOVED: Temporal tracking latency is handled natively 
            # by the Omniscient Trigger Engine. Expanding spatial reach based on time 
            # causes double-dipped prediction and early whiffing/dropped combos.
            target_x_window = min_x_window
            target_y_window = min_y_window

            # Pad X Axis (Horizontal Reach)
            if (p2x2 - p2x1) < target_x_window:
                x_diff = target_x_window - (p2x2 - p2x1)
                if p2x1 == 0: 
                    p2x2 += x_diff # Point-blank: expand outwards
                else:
                    p2x1 -= (x_diff // 2)
                    p2x2 += (x_diff // 2) + (x_diff % 2)

            # Pad Y Axis (Vertical Reach)
            if (p2y2 - p2y1) < target_y_window:
                y_diff = target_y_window - (p2y2 - p2y1)
                # Logic: If move targets the ground level, expand upwards. 
                if abs(p2y2) < 5: p2y1 -= y_diff
                elif abs(p2y1) < 5: p2y2 += y_diff
                else:
                    p2y1 -= (y_diff // 2)
                    p2y2 += (y_diff // 2) + (y_diff % 2)
            
            if p2x1 is None or p2x2 is None or p2y1 is None or p2y2 is None:
                return "", ""

            # Prepare timing variables
            reach_time = reach[0] or 0
            reach_time1 = reach_time + 1

            # --- 5. OMNISCIENT X-AXIS TRIGGER GENERATION (PX) ---
            # Only generate if NOT ignoring X
            if not ignore_x:
                px_generated = _generate_x_triggers_omniscient(
                    current_analysis, reach, stateattr, spawner, velx, velstart, p2x1, p2x2, xscale,
                    groundfront, groundback, airfront, airback, reach_time, midposy, aihelperID
                )
            else:
                px_generated = "; Omni-Awareness: X-Axis Trigger Suppressed (Full Screen/Tracking)\n"

            # --- 6. OMNISCIENT Y-AXIS TRIGGER GENERATION (PY/PYH) ---
            # Only generate if NOT ignoring Y
            if not ignore_y:
                py_generated, pyh_generated = _generate_y_triggers_omniscient(
                    current_analysis, reach, stateattr, spawner, vely, velstart, p2y1, p2y2, yscale,
                    reach_time, reach_time1, midposy, aihelperID
                )
            else:
                 py_generated = "; Omni-Awareness: Y-Axis Trigger Suppressed (Vertical Coverage)\n"
                 pyh_generated = py_generated
            
            # --- OMNI-AUTHORITY: FINAL VALIDATION & PATCHING ---
            # If X wasn't ignored but generated nothing useful, patch it.
            if not ignore_x and not any(x in px_generated.lower() for x in ["p2bodydist x", "p2dist x", "EnemyNear, ScreenPos"]):
                 if _px_patch:
                     px_generated += _px_patch
                 else:
                     safe_x = max(_fix_x2 if '_fix_x2' in locals() else 60, 80) 
                     px_generated += f"triggerall = p2bodydist x = [0, {safe_x}*const(size.xscale)] ; Forced Omni-Awareness\n"
            
    
        # --- 7. FINAL BUNDLING & RETURN ---
        # We must return TWO strings to satisfy the caller (py, pyh).
        # We intelligently bundle PX into both.
        
        final_py = ""
        final_pyh = ""

        # Logic: If a trigger string exists (is not empty/comment-only), include it.
        has_px = "trigger" in px_generated.lower()
        has_py = "trigger" in py_generated.lower()
        
        if has_px and has_py:
            # Both axes matter: Combine them
            final_py = px_generated + py_generated
            final_pyh = px_generated + pyh_generated
        elif has_px and not has_py:
            # X matters, Y is irrelevant: Return X only
            final_py = px_generated
            final_pyh = px_generated
        elif has_py and not has_px:
            # Y matters, X is irrelevant: Return Y only
            final_py = py_generated
            final_pyh = pyh_generated
        else:
            # Neither matters (Full Screen / Infinite Tracking): Return empty valid strings
            # We return a comment so it's not None
            final_py = "; Omni-Competent: No Spatial Triggers Required (Full Coverage)\n"
            final_pyh = final_py

        return final_py, final_pyh

    except Exception as e:
        # --- EMERGENCY FALLBACK (OMNI-ADAPTIVE) ---
        print(f"CRITICAL ERROR in calculate_py_triggers (OMNI-FUSED): {e}")
        return "triggerall = p2bodydist x <= 100\n", "triggerall = p2bodydist x <= 100\n"

    finally:
        pass    
 
