def apply_prone_safety_filter(data_input):
    """
    (OMNI-ADAPTIVE V3)
    Automatically adapts to any list structure (.append vs .extend vs mixed).
    1. Normalizes: Converts mixed inputs (strings/lists) into a clean List of Blocks.
    2. Scans: Checks if the move is ALREADY an OTG (Off-The-Ground) move.
    3. Injects: Adds safety triggers to prevent attacking lying opponents.
    """
    if not data_input: return []

    # --- PHASE 1: UNIVERSAL NORMALIZATION ---
    # This loop absorbs whatever format you passed (flat strings or nested lists)
    # and reorganizes them into a standard [ [Line, Line], [Line, Line] ] format.
    normalized_blocks = []
    current_flat_buffer = []
    
    # Regex to detect the start of a new block (headers like [State -3, ...])
    p_header = re.compile(r'^\s*\[State', re.I)

    # We assume data_input is a list. Iterate through whatever is inside.
    for item in data_input:
        if isinstance(item, list):
            # HIT: It's a Block (from .append).
            # If we were collecting loose lines in the buffer, wrap them up first.
            if current_flat_buffer:
                normalized_blocks.append(current_flat_buffer)
                current_flat_buffer = []
            
            # Add this valid block to our clean list
            if item: normalized_blocks.append(item)

        elif isinstance(item, str):
            # HIT: It's a Loose Line (from .extend).
            # Check if this line looks like the start of a NEW block.
            if p_header.search(item):
                # If we have a previous buffer accumulating, close it off now.
                if current_flat_buffer:
                    normalized_blocks.append(current_flat_buffer)
                # Start a new buffer with this header.
                current_flat_buffer = [item]
            else:
                # It's just a regular line of code. Add it to the current buffer.
                # Only add if it's not just empty whitespace, or if we have a buffer started.
                if item.strip() or current_flat_buffer:
                    current_flat_buffer.append(item)

    # If there are leftovers in the buffer after the loop, add them.
    if current_flat_buffer:
        normalized_blocks.append(current_flat_buffer)

    # --- PHASE 2: SAFETY LOGIC INJECTION ---
    final_output = []
    
    # Regex to detect if OTG logic is ALREADY present (don't break combos)
    p_otg_check = re.compile(r'(?:p2|enemy|enemynear).*statetype\s*=\s*L', re.I)
    # Regex to find the first trigger line
    p_insertion_point = re.compile(r'^\s*trigger', re.I)

    for block in normalized_blocks:
        if not block: continue
        
        # Create a safe copy to modify
        new_block = block[:]
        block_str = "".join(new_block)
        
        # --- Context Checks ---
        # 1. Is this already an OTG move?
        is_otg = p_otg_check.search(block_str)
        # 2. Is this a Helper/Projectile/Variable controller? (Don't limit those)
        is_utility = "type = VelSet" in block_str or "type = Helper" in block_str or "type = Projectile" in block_str or "type = VarSet" in block_str

        if not is_otg and not is_utility:
            # Find the best place to insert the safety trigger
            inserted = False
            for i, line in enumerate(new_block):
                if p_insertion_point.search(line):
                    # INJECT: Don't attack if P2 is Lying Down (L)
                    new_block.insert(i, "triggerall = p2statetype != L\n")
                    # Double check for Simul mode safety
                    new_block.insert(i, "triggerall = !(EnemyNear, StateType = L)\n")
                    inserted = True
                    break
            
            # Fallback: If no triggers exist yet, append to the end
            if not inserted:
                 new_block.append("triggerall = enemynear, statetype != L\n")

        final_output.append(new_block)

    return final_output

def apply_resource_gate_filter(data_input):
    """
    (OMNI-RESOURCE AUTOMATION)
    Scans generated AI blocks. If a block belongs to a move classified as
    Heal, Buff, or Power Charge, it automatically injects the resource cap triggers.
    """
    if not data_input: return []

    # --- PHASE 1: NORMALIZATION (Same as Prone Filter) ---
    normalized_blocks = []
    current_flat_buffer = []
    p_header = re.compile(r'^\s*\[State', re.I)

    for item in data_input:
        if isinstance(item, list):
            if current_flat_buffer:
                normalized_blocks.append(current_flat_buffer)
                current_flat_buffer = []
            if item: normalized_blocks.append(item)
        elif isinstance(item, str):
            if p_header.search(item):
                if current_flat_buffer:
                    normalized_blocks.append(current_flat_buffer)
                current_flat_buffer = [item]
            else:
                if item.strip() or current_flat_buffer:
                    current_flat_buffer.append(item)
    if current_flat_buffer:
        normalized_blocks.append(current_flat_buffer)

    # --- PHASE 2: INTELLIGENT INJECTION ---
    final_output = []
    # Regex to find the target StateNo in a ChangeState controller
    p_value = re.compile(r'value\s*=\s*(\d+)', re.I)
    # Regex to find where to insert triggers
    p_insertion = re.compile(r'^\s*trigger', re.I)

    for block in normalized_blocks:
        new_block = block[:]
        block_str = "".join(new_block).lower()
        
        # 1. Identify which State this block is triggering
        match = p_value.search(block_str)
        if match:
            stateno = int(match.group(1))
            
            # 2. Look up the Analysis
            analysis = GLOBAL_ANALYSIS_CACHE.get(stateno)
            
            if analysis:
                atype = analysis.get('attacktype', 'unknown')
                
                # 3. Define the Trigger to Inject
                trigger_to_add = None
                
                if atype in ["power_charge", "buff", "stat_modifier_buff"]:
                    if "power < powermax" not in block_str:
                        trigger_to_add = "triggerall = power < powermax\n"
                
                elif atype in ["heal", "major_recovery"]:
                    if "life < lifemax" not in block_str:
                        trigger_to_add = "triggerall = life < lifemax\n"

                # 4. Inject it
                if trigger_to_add:
                    inserted = False
                    for i, line in enumerate(new_block):
                        if p_insertion.search(line):
                            new_block.insert(i, trigger_to_add)
                            inserted = True
                            break
                    if not inserted: new_block.append(trigger_to_add)

        final_output.append(new_block)

    return final_output

